import type { FlashcardData } from "./flashcards-rpn";

export const rnGiCancerPedsIntegFlashcards: FlashcardData[] = [
  // === LIVER CIRRHOSIS (25 cards) ===
  { id: "rn-cirrhosis-q1", type: "question", question: "A client with cirrhosis has a serum ammonia of 98 mcg/dL and is disoriented with asterixis. Which medication is the priority?", options: ["Spironolactone", "Lactulose", "Propranolol", "Furosemide"], correctIndex: 1, answer: "Lactulose is first-line for hepatic encephalopathy. It converts ammonia (NH3) to ammonium (NH4+) in the colon for fecal excretion. It also acts as an osmotic laxative, increasing stool frequency. Titrate to 2-3 soft stools/day. Spironolactone treats ascites but not encephalopathy.", category: "Gastrointestinal", difficulty: 2, clinicalPearl: "Asterixis (liver flap) is tested by asking the patient to dorsiflex wrists with arms extended — involuntary flapping indicates grade 2+ hepatic encephalopathy." },
  { id: "rn-cirrhosis-q2", type: "question", question: "During a large-volume paracentesis removing 6 liters, which intervention prevents post-paracentesis circulatory dysfunction?", options: ["IV normal saline bolus", "25% albumin IV infusion", "Packed red blood cell transfusion", "Oral potassium supplementation"], correctIndex: 1, answer: "Large-volume paracentesis (>5 L) requires IV albumin replacement at 6-8 g/L removed to prevent post-paracentesis circulatory dysfunction. This complication causes rapid reaccumulation of ascites and hepatorenal syndrome. Normal saline is less effective than albumin for this purpose.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-cirrhosis-q3", type: "question", question: "What is the target resting heart rate for a cirrhotic patient on propranolol for variceal prophylaxis?", options: ["60-70 bpm", "70-80 bpm", "55-60 bpm", "80-90 bpm"], correctIndex: 2, answer: "Non-selective beta-blockers (propranolol, nadolol) for variceal prophylaxis are titrated to a target resting HR of 55-60 bpm. This reduces portal pressure by decreasing cardiac output (beta-1) and causing splanchnic vasoconstriction (beta-2). Hold if SBP <90 mmHg.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q4", type: "question", question: "A nurse suspects spontaneous bacterial peritonitis (SBP) in a cirrhotic patient with ascites. Which finding on paracentesis confirms the diagnosis?", options: ["Ascitic fluid WBC >500/mm3", "Ascitic fluid PMN count >250/mm3", "SAAG >1.1 g/dL", "Positive gram stain"], correctIndex: 1, answer: "SBP is diagnosed when ascitic fluid PMN count exceeds 250/mm3. The gram stain is positive in only 60% of cases, so a negative gram stain does not rule out SBP. SAAG >1.1 indicates portal hypertension but doesn't diagnose SBP specifically. Treatment is IV cefotaxime.", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "Suspect SBP in any cirrhotic patient with fever, abdominal pain, or unexplained worsening of hepatic encephalopathy." },
  { id: "rn-cirrhosis-q5", type: "question", question: "Why should NSAIDs be avoided in patients with cirrhosis?", options: ["They cause hepatotoxicity", "They reduce renal blood flow and precipitate hepatorenal syndrome", "They increase portal pressure", "They worsen hepatic encephalopathy"], correctIndex: 1, answer: "NSAIDs inhibit prostaglandin synthesis, which is critical for maintaining renal perfusion in cirrhotic patients. The compensatory prostaglandin-mediated renal vasodilation keeps kidneys functioning despite reduced effective circulating volume. NSAIDs remove this compensation, precipitating hepatorenal syndrome.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q6", type: "question", question: "A MELD score of 22 is calculated for a cirrhotic patient. What does this score primarily predict?", options: ["Degree of ascites", "90-day mortality and transplant listing priority", "Risk of variceal bleeding", "Severity of hepatic encephalopathy"], correctIndex: 1, answer: "The MELD (Model for End-Stage Liver Disease) score uses bilirubin, INR, and creatinine to predict 90-day mortality. It is used to prioritize patients on the liver transplant waiting list. A score >=15 generally indicates the need for transplant evaluation. Higher scores = greater urgency.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q7", type: "question", question: "A client with cirrhosis has a musty, sweet breath odor. What does this finding indicate?", options: ["Diabetic ketoacidosis", "Fetor hepaticus from hepatic failure", "Uremia from renal failure", "Respiratory infection"], correctIndex: 1, answer: "Fetor hepaticus is a distinctive musty, sweet breath odor caused by the liver's inability to metabolize mercaptans (sulfur compounds) from the GI tract. It is a sign of severe hepatic dysfunction. This differs from the fruity odor of DKA or the urine-like smell of uremia.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-cirrhosis-q8", type: "question", question: "What ratio of spironolactone to furosemide is used for ascites management in cirrhosis?", options: ["40:100 (furosemide:spironolactone)", "100:40 (spironolactone:furosemide)", "1:1 equal doses", "200:80 (spironolactone:furosemide)"], correctIndex: 1, answer: "The standard ratio is spironolactone 100 mg : furosemide 40 mg. Spironolactone counteracts the secondary hyperaldosteronism in cirrhosis, while furosemide provides additional natriuresis. This ratio maintains potassium balance. Titrate both simultaneously while monitoring electrolytes and renal function.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q9", type: "question", question: "Which assessment finding is most specific to portal hypertension?", options: ["Peripheral edema", "Caput medusae (dilated periumbilical veins)", "Generalized jaundice", "Palmar erythema"], correctIndex: 1, answer: "Caput medusae — dilated periumbilical veins radiating from the umbilicus — is pathognomonic for portal hypertension. These are portosystemic collaterals where blood bypasses the obstructed portal system. Peripheral edema and jaundice occur in many liver conditions. Palmar erythema is common in cirrhosis but not specific to portal hypertension.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-cirrhosis-q10", type: "question", question: "A client with known esophageal varices begins vomiting large amounts of bright red blood. What is the priority medication?", options: ["Pantoprazole IV push", "Octreotide IV bolus and infusion", "Propranolol oral", "Vitamin K IV"], correctIndex: 1, answer: "Octreotide (somatostatin analog) is the priority pharmacotherapy for acute variceal bleeding. It reduces splanchnic blood flow and portal pressure. Give 50 mcg IV bolus then 50 mcg/hr continuous infusion for 3-5 days. Propranolol is for prophylaxis, not acute bleeding. PPI is added but octreotide takes priority.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-cirrhosis-q11", type: "question", question: "A cirrhotic patient on lactulose has had 6 watery stools today. What should the nurse assess?", options: ["Increase the lactulose dose for better effect", "Monitor for dehydration and electrolyte imbalances", "Discontinue lactulose immediately", "Add a bulk-forming laxative"], correctIndex: 1, answer: "Lactulose is titrated to 2-3 soft stools/day. Six watery stools indicates overmedication, risking dehydration, hypokalemia, and hyponatremia. Assess hydration status, electrolytes, and I&O. The dose may need reduction but should not be abruptly discontinued.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q12", type: "question", question: "Which daily dietary sodium restriction is recommended for a cirrhotic patient with ascites?", options: ["4 g/day", "2 g/day", "500 mg/day", "No restriction needed"], correctIndex: 1, answer: "A 2 g/day sodium restriction is the standard recommendation for ascites management in cirrhosis. This is combined with diuretic therapy. Stricter restriction (<500 mg) is poorly tolerated and impractical. Higher sodium intake (4 g) is insufficient to control ascites.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-cirrhosis-q13", type: "question", question: "Rifaximin is added to lactulose for a cirrhotic patient. What is the purpose of this combination?", options: ["Treat urinary tract infection", "Secondary prevention of hepatic encephalopathy episodes", "Reduce portal hypertension", "Treat spontaneous bacterial peritonitis"], correctIndex: 1, answer: "Rifaximin is a non-absorbable antibiotic that reduces ammonia-producing intestinal bacteria. When combined with lactulose, it significantly reduces recurrence of hepatic encephalopathy episodes. It is used for secondary prevention after the first episode. Its minimal systemic absorption makes it well-tolerated.", category: "Gastrointestinal", difficulty: 2, clinicalPearl: "Rifaximin 550 mg BID plus lactulose is the current standard of care for preventing recurrent hepatic encephalopathy." },
  { id: "rn-cirrhosis-q14", type: "question", question: "A nurse notes spider angiomata on a cirrhotic patient's upper chest and face. What causes these lesions?", options: ["Thrombocytopenia", "Hyperestrogenemia from impaired hepatic estrogen metabolism", "Portal hypertension directly", "Vitamin K deficiency"], correctIndex: 1, answer: "Spider angiomata result from hyperestrogenemia due to the cirrhotic liver's inability to metabolize estrogen. Elevated estrogen causes arteriolar vasodilation and the characteristic spider-like lesions with a central arteriole. They are predominantly found on the upper body in the distribution of the superior vena cava.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q15", type: "question", question: "A cirrhotic patient's INR is 2.8. What is the underlying cause?", options: ["Vitamin C deficiency", "Decreased synthesis of clotting factors by damaged hepatocytes", "Excessive platelet consumption", "Medication interaction with warfarin"], correctIndex: 1, answer: "The liver synthesizes clotting factors II, VII, IX, and X. In cirrhosis, damaged hepatocytes cannot produce adequate quantities, leading to prolonged PT/INR. Factor VII has the shortest half-life (6 hours) and decreases first. This is intrinsic liver dysfunction, not warfarin-related.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q16", type: "question", question: "What nursing position best relieves dyspnea in a patient with tense ascites?", options: ["Supine with legs elevated", "Semi-Fowler's position", "Left lateral decubitus", "Prone position"], correctIndex: 1, answer: "Semi-Fowler's position (30-45 degrees HOB elevation) reduces pressure on the diaphragm from the distended abdomen, improving respiratory excursion and relieving dyspnea. Supine position worsens dyspnea by allowing the ascitic fluid to push the diaphragm upward.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-cirrhosis-q17", type: "question", question: "Which type of hepatorenal syndrome progresses most rapidly and has the highest mortality?", options: ["Type 2 (chronic, gradual)", "Type 1 (rapid, <2 weeks)", "Type 3 (medication-induced)", "Type 4 (post-transplant)"], correctIndex: 1, answer: "Type 1 hepatorenal syndrome is characterized by rapid deterioration of renal function (doubling of creatinine to >2.5 mg/dL in <2 weeks). It carries extremely high mortality without treatment. Type 2 is more gradual and associated with refractory ascites. Types 3 and 4 do not exist in standard classification.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-cirrhosis-q18", type: "question", question: "What lab finding confirms that ascites is caused by portal hypertension?", options: ["Ascitic fluid WBC >1000", "SAAG (serum-ascites albumin gradient) >1.1 g/dL", "Ascitic fluid protein >3 g/dL", "Ascitic fluid glucose <50 mg/dL"], correctIndex: 1, answer: "SAAG >1.1 g/dL confirms that ascites is due to portal hypertension (cirrhosis, heart failure, Budd-Chiari). SAAG <1.1 suggests non-portal hypertension causes (malignancy, tuberculosis, pancreatitis). SAAG = serum albumin minus ascitic fluid albumin.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-cirrhosis-q19", type: "question", question: "A patient with cirrhosis is being evaluated using the Child-Pugh classification. Which factors are included in this scoring system?", options: ["BUN, creatinine, potassium", "Bilirubin, albumin, INR, ascites, encephalopathy grade", "AST, ALT, alkaline phosphatase", "Hemoglobin, WBC, platelet count"], correctIndex: 1, answer: "Child-Pugh classification uses five variables: total bilirubin, serum albumin, PT/INR, ascites presence/severity, and hepatic encephalopathy grade. Each is scored 1-3, yielding a total score of 5-15 and class A (5-6), B (7-9), or C (10-15). Class C has poorest prognosis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q20", type: "question", question: "A nurse is monitoring daily weight for a cirrhotic patient on diuretics. What is the maximum recommended weight loss per day for patients with peripheral edema?", options: ["0.5 kg/day", "1.0 kg/day", "2.0 kg/day", "No limit as long as symptoms improve"], correctIndex: 1, answer: "Maximum recommended weight loss is 1.0 kg/day for patients with both ascites and peripheral edema, and 0.5 kg/day for those with ascites alone. More rapid diuresis risks hepatorenal syndrome and electrolyte derangements. Peripheral edema serves as a buffer allowing faster safe diuresis.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-cirrhosis-q21", type: "question", question: "What procedure is indicated for a cirrhotic patient with refractory ascites that does not respond to maximum diuretic therapy?", options: ["Liver biopsy", "TIPS (transjugular intrahepatic portosystemic shunt)", "Splenectomy", "Cholecystectomy"], correctIndex: 1, answer: "TIPS creates a shunt between the hepatic vein and portal vein, reducing portal hypertension and decompressing ascites. It is indicated for refractory ascites (not responding to sodium restriction and maximum diuretic doses) or recurrent variceal bleeding. Risk includes worsening hepatic encephalopathy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q22", type: "question", question: "A cirrhotic patient has thrombocytopenia (platelets 68,000/mm3). What is the primary cause?", options: ["DIC", "Hypersplenism from splenomegaly", "Vitamin B12 deficiency", "Medication side effect"], correctIndex: 1, answer: "In cirrhosis, portal hypertension causes splenomegaly. The enlarged spleen sequesters and destroys blood cells (hypersplenism), causing thrombocytopenia, leukopenia, and anemia. Up to 90% of platelet mass can be trapped in an enlarged spleen. This is the most common cause of thrombocytopenia in cirrhosis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q23", type: "question", question: "Which nursing assessment best evaluates for hepatic encephalopathy progression?", options: ["Blood pressure monitoring every 4 hours", "Serial neurological assessments including number connection test and asterixis check", "Daily abdominal girth measurement", "Hourly urine output monitoring"], correctIndex: 1, answer: "Hepatic encephalopathy is assessed through neurological evaluation: orientation, behavior changes, asterixis (flapping tremor), sleep-wake reversal, and standardized tests like the number connection test. The West Haven criteria grade severity from 0 (subtle) to 4 (coma). Serum ammonia correlates but is not definitive.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q24", type: "question", question: "A cirrhotic patient has an AST:ALT ratio of 2.5:1. What does this ratio suggest about the etiology?", options: ["Viral hepatitis", "Alcoholic liver disease", "Autoimmune hepatitis", "Drug-induced liver injury"], correctIndex: 1, answer: "An AST:ALT ratio >2:1 is highly suggestive of alcoholic liver disease. In alcoholic hepatitis, AST is typically elevated more than ALT because alcohol depletes pyridoxal phosphate (B6), a cofactor needed for ALT production. In viral hepatitis, ALT is usually higher than AST.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-cirrhosis-q25", type: "question", question: "What FibroScan (transient elastography) value indicates advanced fibrosis/cirrhosis?", options: ["<6 kPa", "6-8 kPa", ">12.5 kPa", "Any value above 0 kPa"], correctIndex: 2, answer: "FibroScan values >12.5 kPa generally indicate advanced fibrosis or cirrhosis. Values <6 kPa suggest minimal fibrosis. This non-invasive test measures liver stiffness using ultrasound-based shear wave technology, reducing the need for liver biopsy in many patients.", category: "Gastrointestinal", difficulty: 3 },

  // === HEPATITIS (25 cards) ===
  { id: "rn-hep-q1", type: "question", question: "A healthcare worker's anti-HBs titer is 12 mIU/mL after hepatitis B vaccination. What does this indicate?", options: ["Active hepatitis B infection", "Inadequate immunity requiring revaccination", "Adequate immunity to hepatitis B", "Chronic hepatitis B carrier status"], correctIndex: 2, answer: "Anti-HBs titer >10 mIU/mL indicates adequate immunity from vaccination. Titers are checked in healthcare workers to confirm protection. If <10 mIU/mL, a booster dose or complete revaccination series is recommended. HBsAg would be positive for active infection.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q2", type: "question", question: "Which hepatitis B serology pattern indicates the 'window period'?", options: ["HBsAg+, anti-HBs−, anti-HBc IgM+", "HBsAg−, anti-HBs−, anti-HBc IgM+", "HBsAg−, anti-HBs+, anti-HBc−", "HBsAg+, anti-HBs+, anti-HBc IgG+"], correctIndex: 1, answer: "The window period occurs when HBsAg has cleared but anti-HBs has not yet appeared. Only anti-HBc IgM is detectable. This is a diagnostic trap — testing only HBsAg and anti-HBs would miss the infection. Anti-HBc IgM confirms recent acute infection during this period.", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "The window period typically lasts a few weeks to months. Anti-HBc IgM is the only detectable marker during this time." },
  { id: "rn-hep-q3", type: "question", question: "What is the cure rate for hepatitis C with current direct-acting antivirals (DAAs)?", options: ["30-40%", "50-60%", "75-80%", ">95%"], correctIndex: 3, answer: "Current DAA regimens (sofosbuvir/velpatasvir, glecaprevir/pibrentasvir) achieve sustained virologic response (cure) rates >95% in 8-12 weeks. This represents a paradigm shift from the interferon era when cure rates were 40-50%. HCV is now a curable disease.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q4", type: "question", question: "Which hepatitis virus is a DNA virus while all others are RNA viruses?", options: ["Hepatitis A", "Hepatitis B", "Hepatitis C", "Hepatitis E"], correctIndex: 1, answer: "Hepatitis B is the only DNA hepatitis virus. HAV, HCV, HDV, and HEV are all RNA viruses. This distinction is clinically relevant because HBV can integrate into the host genome, contributing to its ability to cause chronic infection and hepatocellular carcinoma.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q5", type: "question", question: "An infant is born to an HBsAg-positive mother. What should be administered within 12 hours of birth?", options: ["Hepatitis B vaccine only", "HBIG only", "Both HBIG and hepatitis B vaccine", "No intervention until 2 months of age"], correctIndex: 2, answer: "Both HBIG (passive immunity with immediate anti-HBs antibodies) and the first dose of hepatitis B vaccine (active immunity) must be given within 12 hours of birth to prevent vertical transmission. HBIG provides immediate protection while the vaccine series builds long-term immunity.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q6", type: "question", question: "What type of isolation precautions is required for a patient with hepatitis A?", options: ["Droplet precautions", "Airborne precautions", "Contact precautions (enteric/fecal-oral)", "No special precautions needed"], correctIndex: 2, answer: "Hepatitis A is transmitted via the fecal-oral route, requiring contact precautions with emphasis on enteric precautions. Meticulous hand hygiene, especially after toileting, is essential. Stool is the primary source of virus. Hepatitis B and C require standard/blood precautions.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q7", type: "question", question: "Why is hepatitis E particularly dangerous during pregnancy?", options: ["It always causes chronic infection", "Mortality rate up to 25% in the third trimester", "It causes fetal hepatitis B coinfection", "It is resistant to all antiviral therapy"], correctIndex: 1, answer: "HEV infection during pregnancy, especially in the third trimester, carries a mortality rate of up to 25% due to fulminant hepatic failure. The immunological changes of pregnancy combined with hormonal effects on the liver increase susceptibility. HEV is otherwise self-limiting in non-pregnant individuals.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q8", type: "question", question: "Which hepatitis virus requires coinfection with hepatitis B to replicate?", options: ["Hepatitis A", "Hepatitis C", "Hepatitis D (delta)", "Hepatitis E"], correctIndex: 2, answer: "Hepatitis D is a defective RNA virus that requires the HBsAg coat protein from hepatitis B for replication. It cannot exist without HBV. HDV superinfection (acquired by an HBV carrier) has a worse prognosis than coinfection (simultaneous acquisition of both).", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q9", type: "question", question: "A patient with chronic hepatitis C asks about screening for liver cancer. What is the recommended surveillance?", options: ["Annual CT scan of the abdomen", "AFP level and liver ultrasound every 6 months", "Monthly liver function tests", "Liver biopsy every 2 years"], correctIndex: 1, answer: "Patients with chronic HBV or HCV (especially with cirrhosis) should undergo hepatocellular carcinoma surveillance with AFP and liver ultrasound every 6 months. Early detection of HCC significantly improves treatment options and survival.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q10", type: "question", question: "What percentage of acute hepatitis C infections become chronic?", options: ["10-15%", "30-40%", "50-60%", "75-85%"], correctIndex: 3, answer: "HCV becomes chronic in 75-85% of infected individuals because the virus evades immune clearance through rapid mutation. This high chronicity rate is why HCV screening is recommended for all adults born between 1945-1965 and all adults at least once in their lifetime.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q11", type: "question", question: "Which finding is characteristic of the icteric phase of acute hepatitis?", options: ["Low-grade fever and malaise only", "Dark (tea-colored) urine and clay-colored (acholic) stools", "Productive cough and rhinorrhea", "Joint swelling in multiple joints"], correctIndex: 1, answer: "The icteric phase features jaundice, dark urine (elevated conjugated bilirubin excreted by kidneys), and clay-colored stools (lack of bilirubin reaching the intestine due to hepatocellular dysfunction or cholestasis). Hepatomegaly with tenderness is also common.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q12", type: "question", question: "What is the recommended hepatitis B vaccine schedule for adults?", options: ["Single dose", "Two doses at 0 and 6 months", "Three doses at 0, 1, and 6 months", "Four doses at 0, 1, 2, and 12 months"], correctIndex: 2, answer: "The standard adult HBV vaccine schedule is a 3-dose series at 0, 1, and 6 months. A newer 2-dose vaccine (Heplisav-B) given at 0 and 1 month is also available. Anti-HBs titer should be checked 1-2 months after the final dose in healthcare workers.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q13", type: "question", question: "A patient with hepatitis has ALT 850 and AST 620. What does the ALT > AST pattern suggest?", options: ["Alcoholic liver disease", "Viral hepatitis", "Acetaminophen toxicity", "Cirrhosis"], correctIndex: 1, answer: "In viral hepatitis, ALT is typically higher than AST because ALT is more liver-specific and is released in greater quantities during viral hepatocyte damage. In alcoholic liver disease, AST > ALT (ratio >2:1) because alcohol depletes the B6 cofactor needed for ALT synthesis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q14", type: "question", question: "Which side effect is most concerning with pegylated interferon therapy for hepatitis?", options: ["Headache", "Depression and suicidal ideation", "Mild nausea", "Injection site redness"], correctIndex: 1, answer: "Pegylated interferon can cause severe depression and suicidal ideation, requiring baseline and ongoing psychiatric assessment. Other serious effects include myelosuppression (monitor CBC), thyroid dysfunction, and autoimmune reactions. Screen for psychiatric history before initiating therapy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q15", type: "question", question: "A patient has: HBsAg negative, anti-HBs positive, anti-HBc IgG positive. What does this indicate?", options: ["Active acute hepatitis B", "Chronic hepatitis B", "Immunity from vaccination", "Immunity from natural infection (resolved)"], correctIndex: 3, answer: "HBsAg negative (no active virus), anti-HBs positive (immunity), and anti-HBc IgG positive (past exposure) = immunity from resolved natural infection. Vaccination immunity would show anti-HBs positive but anti-HBc NEGATIVE (never exposed to whole virus).", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "Anti-HBc differentiates vaccine immunity (anti-HBc negative) from natural immunity (anti-HBc positive)." },
  { id: "rn-hep-q16", type: "question", question: "What is the maximum safe daily dose of acetaminophen for a patient with chronic hepatitis?", options: ["4 g/day (standard dose)", "2 g/day or less", "1 g/day", "Acetaminophen is completely contraindicated"], correctIndex: 1, answer: "Patients with chronic liver disease should limit acetaminophen to 2 g/day or less. While not completely contraindicated, the diseased liver has reduced capacity to metabolize acetaminophen safely. The toxic metabolite NAPQI accumulates more readily when hepatic glutathione is depleted.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q17", type: "question", question: "What HBV serology marker indicates high viral replication and infectivity?", options: ["Anti-HBs", "HBeAg", "Anti-HBc IgG", "Anti-HBe"], correctIndex: 1, answer: "HBeAg (hepatitis B e antigen) indicates active viral replication and HIGH infectivity. When HBeAg is positive, the patient has high viral loads and is very infectious. Seroconversion to anti-HBe indicates decreased replication and lower infectivity.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-hep-q18", type: "question", question: "Why should entecavir not be abruptly discontinued in a chronic HBV patient?", options: ["It causes withdrawal seizures", "Risk of severe hepatic flare from viral rebound", "It causes renal failure if stopped suddenly", "No specific reason — it can be stopped anytime"], correctIndex: 1, answer: "Abrupt discontinuation of entecavir (or any HBV nucleoside analog) can cause severe hepatic flare due to rapid viral rebound. The immune system's response to the suddenly increased viral load can cause fulminant hepatitis. Tapering and close monitoring are essential when discontinuing.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q19", type: "question", question: "Which arthralgias pattern is characteristic of acute hepatitis B prodrome?", options: ["Large joint inflammatory arthritis", "Serum sickness-like syndrome with symmetric small joint arthralgias and skin rash", "Gout-like monoarthritis", "Septic arthritis"], correctIndex: 1, answer: "Acute HBV can present with a serum sickness-like syndrome during the prodromal phase: symmetric polyarthralgias (often small joints), urticarial skin rash, and low-grade fever. This is caused by circulating immune complexes (HBsAg-anti-HBs) depositing in joints and skin.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q20", type: "question", question: "Which hepatitis types can cause chronic hepatitis?", options: ["Hepatitis A and E only", "Hepatitis B, C, and D", "All hepatitis types (A through E)", "Only hepatitis C"], correctIndex: 1, answer: "Hepatitis B, C, and D can progress to chronic hepatitis. HAV and HEV cause acute, self-limiting infections only and do NOT cause chronic hepatitis. HCV has the highest chronicity rate (75-85%), followed by HBV (5% in adults, up to 90% in neonates), and HDV (requires HBV coinfection).", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q21", type: "question", question: "What drug interaction is critical to avoid when prescribing sofosbuvir/velpatasvir for HCV?", options: ["Metformin", "Amiodarone — risk of symptomatic bradycardia", "Acetaminophen", "Omeprazole"], correctIndex: 1, answer: "Sofosbuvir-containing regimens combined with amiodarone can cause life-threatening symptomatic bradycardia, including cardiac arrest. This interaction can occur up to 2 weeks after starting DAA therapy. Amiodarone should be discontinued or an alternative HCV regimen used.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q22", type: "question", question: "What is the significance of HBV DNA viral load in guiding treatment decisions?", options: ["It is not clinically useful", "High HBV DNA (>2000 IU/mL with liver damage) indicates need for antiviral therapy", "Only the presence/absence of HBsAg matters", "HBV DNA is only used for research purposes"], correctIndex: 1, answer: "HBV DNA viral load quantifies active viral replication. Treatment is indicated when HBV DNA >2000 IU/mL with evidence of liver inflammation (elevated ALT) or fibrosis. Very high levels (>200,000 IU/mL) in pregnant women in the third trimester indicate need for tenofovir to reduce vertical transmission.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q23", type: "question", question: "A nurse is providing education to a patient with hepatitis A. Which statement by the patient indicates correct understanding?", options: ["I will need lifelong antiviral therapy", "I should use condoms because it is sexually transmitted", "I should wash my hands thoroughly after using the bathroom because it spreads through stool", "I need to have my blood tested monthly for the rest of my life"], correctIndex: 2, answer: "HAV is transmitted via the fecal-oral route. Meticulous hand hygiene, especially after toileting and before food preparation, is the primary prevention measure. HAV is self-limiting, does not require antiviral therapy, and does not become chronic.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-hep-q24", type: "question", question: "What is the most common cause of fulminant hepatic failure from viral hepatitis?", options: ["Hepatitis A in adults", "Hepatitis B (especially with HDV superinfection)", "Hepatitis C", "Hepatitis E in non-pregnant adults"], correctIndex: 1, answer: "HBV is the most common viral cause of fulminant hepatic failure, especially when HDV superinfection occurs. The combined immune response to both viruses causes massive hepatocyte destruction. Fulminant hepatitis presents with rapidly worsening jaundice, coagulopathy, and encephalopathy within weeks.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-hep-q25", type: "question", question: "What is the recommended post-exposure prophylaxis time frame for hepatitis A exposure?", options: ["Within 24 hours", "Within 2 weeks", "Within 30 days", "Within 6 months"], correctIndex: 1, answer: "HAV post-exposure prophylaxis (vaccine and/or immune globulin depending on age and health status) should be given within 2 weeks of exposure. After 2 weeks, the benefit diminishes significantly. Healthy individuals aged 1-40 receive vaccine alone; those >40 or immunocompromised receive both vaccine and IG.", category: "Gastrointestinal", difficulty: 2 },

  // === ACUTE PANCREATITIS (25 cards) ===
  { id: "rn-panc-q1", type: "question", question: "A patient with acute pancreatitis has a serum calcium of 7.0 mg/dL. What mechanism causes this hypocalcemia?", options: ["Excessive urinary calcium excretion", "Fat saponification — calcium binds to fatty acids released from fat necrosis", "Vitamin D deficiency", "PTH suppression"], correctIndex: 1, answer: "Lipase-mediated fat necrosis releases free fatty acids that bind ionized calcium (saponification), sequestering it and causing hypocalcemia. This is a hallmark finding of necrotizing pancreatitis. Monitor for Chvostek and Trousseau signs indicating symptomatic hypocalcemia.", category: "Gastrointestinal", difficulty: 2, clinicalPearl: "Calcium <7 mg/dL at 48 hours is one of the Ranson criteria and indicates severe pancreatitis." },
  { id: "rn-panc-q2", type: "question", question: "What are the two most common causes of acute pancreatitis?", options: ["Trauma and medication", "Gallstones (40%) and alcohol (40%)", "Infection and autoimmune disease", "Hypertriglyceridemia and ERCP"], correctIndex: 1, answer: "Gallstones and alcohol each account for approximately 40% of acute pancreatitis cases. Gallstones cause obstruction at the ampulla of Vater, leading to bile reflux. Alcohol causes direct acinar cell toxicity and increased zymogen production. Together they account for 80% of cases.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q3", type: "question", question: "A nurse observes bluish discoloration on the patient's flanks. This is documented as:", options: ["Cullen sign", "Grey Turner sign", "Murphy sign", "Rovsing sign"], correctIndex: 1, answer: "Grey Turner sign is ecchymosis of the flanks indicating retroperitoneal hemorrhage in severe necrotizing pancreatitis. Cullen sign is periumbilical ecchymosis. Both are late findings (48-72 hours) present in only ~3% of cases but indicate severe hemorrhagic disease with high mortality.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q4", type: "question", question: "Which lab test is most specific for diagnosing acute pancreatitis?", options: ["Serum amylase", "Serum lipase", "WBC count", "C-reactive protein"], correctIndex: 1, answer: "Serum lipase is the most sensitive and specific marker for acute pancreatitis. A level >3x the upper limit of normal is diagnostic. Lipase remains elevated longer than amylase (up to 14 days vs 3-5 days). Amylase can be elevated in non-pancreatic conditions (parotitis, renal failure, bowel obstruction).", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q5", type: "question", question: "Which IV fluid is preferred for initial resuscitation in acute pancreatitis?", options: ["D5W", "Normal saline (0.9%)", "Lactated Ringer's solution", "Dextran"], correctIndex: 2, answer: "Lactated Ringer's is preferred over normal saline in acute pancreatitis based on evidence suggesting it may reduce SIRS compared to NS. Aggressive resuscitation at 5-10 mL/kg/hr is critical because massive third-spacing into the retroperitoneum causes significant intravascular depletion. Target UOP >0.5 mL/kg/hr.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q6", type: "question", question: "What position best relieves abdominal pain in a patient with acute pancreatitis?", options: ["Supine with legs elevated", "Side-lying or fetal position with knees flexed", "Prone position", "Standing upright"], correctIndex: 1, answer: "The fetal position (side-lying with knees drawn to chest) reduces tension on the inflamed retroperitoneal pancreas. Supine position worsens pain because the retroperitoneal pancreas is compressed against the spine. Patients often instinctively adopt this position.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q7", type: "question", question: "When should antibiotics be initiated in acute pancreatitis?", options: ["Immediately on admission for all patients", "Only for confirmed infected pancreatic necrosis", "When WBC exceeds 15,000", "After 48 hours of NPO status"], correctIndex: 1, answer: "Antibiotics are NOT routinely indicated in acute pancreatitis. They should only be used for confirmed infected pancreatic necrosis (diagnosed by CT-guided FNA showing bacteria on culture). Prophylactic antibiotics do not prevent infection and may promote resistant organisms.", category: "Gastrointestinal", difficulty: 2, clinicalPearl: "Sterile necrosis is managed conservatively. Infected necrosis has gas bubbles on CT and requires antibiotics with pancreatic tissue penetration (carbapenems)." },
  { id: "rn-panc-q8", type: "question", question: "A patient's Ranson score at 48 hours is 5. What does this indicate about prognosis?", options: ["Mild pancreatitis with excellent prognosis", "Moderate pancreatitis requiring ICU monitoring", "Severe pancreatitis with 15-40% mortality", "Ranson score is not prognostically relevant"], correctIndex: 2, answer: "Ranson score >=3 indicates severe pancreatitis. Score of 5 predicts 15-40% mortality. Admission criteria include age >55, WBC >16K, glucose >200, AST >250, LDH >350. 48-hour criteria include Hct drop >10%, BUN rise >5, Ca <8, PaO2 <60, base deficit >4, fluid sequestration >6L.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q9", type: "question", question: "Why does acute pancreatitis increase the risk of ARDS?", options: ["Direct aspiration of vomitus", "Systemic inflammatory cytokines damage pulmonary endothelium", "Bacterial pneumonia from immunosuppression", "Pulmonary embolism from immobility"], correctIndex: 1, answer: "Acute pancreatitis triggers a massive systemic inflammatory response releasing TNF-alpha, IL-1, IL-6, and phospholipase A into the circulation. These cytokines damage pulmonary capillary endothelium, causing increased permeability, non-cardiogenic pulmonary edema, and ARDS. Monitor respiratory status closely.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-panc-q10", type: "question", question: "What is the preferred nutritional approach for a patient with acute pancreatitis who cannot eat within 72 hours?", options: ["Total parenteral nutrition (TPN)", "Enteral nutrition via nasojejunal tube", "Continue NPO until pain resolves completely", "IV dextrose solutions only"], correctIndex: 1, answer: "Enteral nutrition (EN) via NJ tube is strongly preferred over TPN. EN maintains gut mucosal integrity, reduces bacterial translocation, and decreases infectious complications. TPN is associated with higher infection rates and gut atrophy. EN should begin within 72 hours if oral intake is not possible.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q11", type: "question", question: "A patient with biliary pancreatitis also has cholangitis. When should ERCP be performed?", options: ["After complete resolution of pancreatitis", "Within 24 hours", "Only if the patient develops jaundice", "ERCP is contraindicated in pancreatitis"], correctIndex: 1, answer: "Urgent ERCP within 24 hours is indicated when biliary pancreatitis is complicated by cholangitis or persistent biliary obstruction. ERCP removes the obstructing gallstone from the common bile duct. For uncomplicated biliary pancreatitis without cholangitis, ERCP is not routinely needed.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-panc-q12", type: "question", question: "What blood glucose monitoring is important in acute pancreatitis and why?", options: ["Monitor for hypoglycemia from malnutrition", "Monitor for hyperglycemia from islet cell damage", "Blood glucose is not affected by pancreatitis", "Monitor only if patient has pre-existing diabetes"], correctIndex: 1, answer: "Acute pancreatitis can damage islets of Langerhans, causing hyperglycemia. The inflammatory process destroys beta cells, reducing insulin production. Monitor blood glucose regularly and manage with insulin if needed. Some patients develop permanent diabetes after severe necrotizing pancreatitis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q13", type: "question", question: "What is the hallmark pain pattern of acute pancreatitis?", options: ["Right upper quadrant pain radiating to the right shoulder", "Severe epigastric pain radiating straight through to the back", "Periumbilical pain migrating to the right lower quadrant", "Diffuse abdominal pain without specific pattern"], correctIndex: 1, answer: "Acute pancreatitis classically presents with severe, constant epigastric pain that radiates straight through to the back (because the pancreas sits retroperitoneally). Pain worsens with eating and lying supine. It is often described as 'boring' or 'knife-like' and is unrelenting.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q14", type: "question", question: "Which analgesic is preferred for pain management in acute pancreatitis?", options: ["Morphine", "Hydromorphone", "Meperidine", "Aspirin"], correctIndex: 1, answer: "Hydromorphone is currently preferred for acute pancreatitis pain. While meperidine was historically used (theoretically less sphincter of Oddi spasm than morphine), it is falling out of favor due to seizure risk from its metabolite normeperidine. Morphine's effect on the sphincter of Oddi is clinically insignificant.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q15", type: "question", question: "When should a cholecystectomy be performed for gallstone pancreatitis?", options: ["Never — it is contraindicated", "During the same hospital admission for mild pancreatitis", "At least 6 months after the episode", "Only if pancreatitis recurs"], correctIndex: 1, answer: "Cholecystectomy during the index admission is recommended for mild gallstone pancreatitis to prevent recurrence (risk up to 30-40% without surgery). For severe pancreatitis, cholecystectomy is delayed until inflammation resolves (typically 4-6 weeks) to reduce surgical complications.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q16", type: "question", question: "A patient with pancreatitis has diminished bowel sounds and abdominal distension. What complication should the nurse suspect?", options: ["Pancreatic pseudocyst", "Paralytic ileus", "Bowel perforation", "Pancreatic abscess"], correctIndex: 1, answer: "Paralytic ileus is common in acute pancreatitis due to local inflammation spreading to adjacent bowel. Absent or diminished bowel sounds with distension, nausea, and vomiting are characteristic. NG tube decompression may be needed. Bowel sounds should return before advancing diet.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q17", type: "question", question: "What CRP level at 48 hours suggests severe acute pancreatitis?", options: [">50 mg/L", ">100 mg/L", ">150 mg/L", ">200 mg/L"], correctIndex: 2, answer: "CRP >150 mg/L at 48 hours is a predictor of severe pancreatitis and necrosis. CRP is an acute phase reactant produced by the liver in response to IL-6. It peaks at 48-72 hours and correlates with pancreatic necrosis development.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-panc-q18", type: "question", question: "What is the mechanism of autodigestion in acute pancreatitis?", options: ["Gastric acid refluxes into the pancreatic duct", "Premature activation of trypsinogen to trypsin within the pancreas activates other zymogens", "Bacterial infection directly digests pancreatic tissue", "Bile salts erode the pancreatic capsule"], correctIndex: 1, answer: "Trypsinogen is prematurely activated to trypsin within the pancreatic parenchyma instead of the duodenum. Active trypsin then activates other zymogens (elastase, phospholipase, lipase) in a cascade. Elastase digests blood vessel walls (hemorrhage), lipase digests fat (necrosis, saponification), and phospholipase damages cell membranes.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q19", type: "question", question: "What is the significance of pleural effusion in a pancreatitis patient?", options: ["It is unrelated to pancreatitis", "Left-sided pleural effusion is common due to diaphragmatic inflammation from the retroperitoneal process", "It always indicates a pulmonary embolism", "It requires immediate chest tube insertion"], correctIndex: 1, answer: "Left-sided pleural effusion (or bilateral) is common in acute pancreatitis because the inflamed retroperitoneal pancreas is adjacent to the left hemidiaphragm. Inflammatory fluid can track through the diaphragm. It indicates severe disease but usually resolves with treatment of the pancreatitis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q20", type: "question", question: "What diet should be advanced when a pancreatitis patient is ready to eat?", options: ["Regular diet with high-fat foods", "Low-fat, soft diet with small frequent meals", "Clear liquid diet for 2 weeks", "Protein-restricted diet"], correctIndex: 1, answer: "Advance to a low-fat diet because fat is the strongest stimulant of pancreatic enzyme secretion (via CCK release). Small, frequent meals are better tolerated. Early oral feeding (within 24 hours if tolerated) actually improves outcomes compared to prolonged NPO status.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-panc-q21", type: "question", question: "Which medication can trigger acute pancreatitis?", options: ["Acetaminophen", "Valproic acid", "Metformin", "Lisinopril"], correctIndex: 1, answer: "Valproic acid is a well-established cause of drug-induced acute pancreatitis. Other medications include azathioprine, thiazide diuretics, estrogens, tetracycline, didanosine, and GLP-1 receptor agonists. The mechanism varies but often involves direct acinar cell toxicity or hypertriglyceridemia.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q22", type: "question", question: "A hypertriglyceridemia level above what threshold can cause acute pancreatitis?", options: [">200 mg/dL", ">500 mg/dL", ">1000 mg/dL", ">2000 mg/dL"], correctIndex: 2, answer: "Triglyceride levels >1000 mg/dL significantly increase the risk of acute pancreatitis. Excess triglycerides are hydrolyzed by pancreatic lipase, releasing toxic free fatty acids that damage acinar cells. Treatment includes insulin infusion (stimulates lipoprotein lipase) and fibrate therapy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q23", type: "question", question: "What is a pancreatic pseudocyst and when does it typically develop?", options: ["A malignant tumor developing immediately", "An encapsulated collection of pancreatic fluid without an epithelial lining, developing 4-6 weeks after acute pancreatitis", "An abscess requiring immediate drainage", "A congenital pancreatic malformation"], correctIndex: 1, answer: "A pseudocyst is a fluid collection enclosed by a non-epithelial wall of granulation tissue and fibrosis. It develops 4-6 weeks after acute pancreatitis from ductal disruption. Most resolve spontaneously. Intervention (endoscopic or surgical drainage) is needed if >6 cm, symptomatic, or infected.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-panc-q24", type: "question", question: "When should CT imaging with contrast be performed in acute pancreatitis?", options: ["Immediately on admission for all patients", "Within the first 12 hours", "At 72+ hours if concern for necrotizing pancreatitis", "CT is not useful in pancreatitis"], correctIndex: 2, answer: "CT with IV contrast should be performed at 72+ hours after symptom onset if there is concern for necrotizing pancreatitis or the patient is not improving. Early CT (<72 hours) may underestimate the degree of necrosis because it has not yet fully declared. CT is the gold standard for detecting necrosis.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-panc-q25", type: "question", question: "What urine output target indicates adequate fluid resuscitation in acute pancreatitis?", options: [">0.25 mL/kg/hr", ">0.5 mL/kg/hr", ">1.0 mL/kg/hr", ">2.0 mL/kg/hr"], correctIndex: 1, answer: "Target UOP >0.5 mL/kg/hr indicates adequate renal perfusion and volume resuscitation. Report UOP below this threshold as it may indicate inadequate resuscitation or developing acute kidney injury. Aggressive IV fluid replacement at 5-10 mL/kg/hr is the cornerstone of early pancreatitis management.", category: "Gastrointestinal", difficulty: 1 },

  // === GI BLEEDING (25 cards) ===
  { id: "rn-gib-q1", type: "question", question: "A patient presents with melena and a BUN of 45 with creatinine 1.0. Where is the likely bleeding source?", options: ["Hemorrhoids", "Upper GI tract", "Sigmoid colon", "Rectum"], correctIndex: 1, answer: "Melena (black tarry stool) indicates blood has been digested by gastric acid and bacteria, suggesting upper GI source. An elevated BUN:creatinine ratio (45:1 here, >20:1) occurs because digested blood proteins are absorbed as urea nitrogen, disproportionately raising BUN.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q2", type: "question", question: "A patient with active hematemesis has a hemoglobin of 14.2 g/dL. Why might the Hgb appear normal?", options: ["The patient is not actually bleeding", "Hemoconcentration — early hemorrhage loses RBCs and plasma proportionally before hemodilution occurs", "Lab error", "The patient has polycythemia"], correctIndex: 1, answer: "In acute hemorrhage, both red cells and plasma are lost proportionally, so the initial Hgb/Hct may appear normal. Hemodilution occurs over 24-72 hours as interstitial fluid shifts into the vascular space and IV fluids are administered. Serial monitoring every 4-6 hours is essential.", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "Rely on clinical signs (tachycardia, orthostatic changes) rather than initial Hgb to assess severity of acute GI hemorrhage." },
  { id: "rn-gib-q3", type: "question", question: "What IV size and number should be established for a patient with massive GI bleeding?", options: ["One 20-gauge IV", "One 22-gauge IV", "Two 16-18 gauge peripheral IVs", "One central venous catheter only"], correctIndex: 2, answer: "Two large-bore (16-18 gauge) peripheral IVs are required for rapid volume resuscitation in GI hemorrhage. Peripheral IVs have faster flow rates than central lines due to shorter length and wider bore (per Poiseuille's law). Central access may be added but should not delay fluid resuscitation.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q4", type: "question", question: "What hemoglobin threshold triggers transfusion in a hemodynamically stable GI bleeding patient without cardiac disease?", options: ["<10 g/dL", ">7 g/dL", "<7 g/dL", "<9 g/dL"], correctIndex: 2, answer: "Restrictive transfusion strategy targets Hgb >7 g/dL in hemodynamically stable patients without active coronary disease. Liberal transfusion (Hgb >9 g/dL) is reserved for patients with active cardiac ischemia. Overtransfusion in variceal bleeding can increase portal pressure and worsen hemorrhage.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q5", type: "question", question: "What is the PPI protocol for upper GI bleeding from a peptic ulcer?", options: ["Omeprazole 20 mg PO daily", "Pantoprazole 80 mg IV bolus then 8 mg/hr continuous infusion for 72 hours", "Ranitidine 50 mg IV every 8 hours", "Sucralfate 1 g PO four times daily"], correctIndex: 1, answer: "High-dose IV PPI therapy (pantoprazole 80 mg bolus then 8 mg/hr infusion for 72 hours) raises gastric pH above 6, which stabilizes clot formation over the ulcer and reduces rebleeding after endoscopic hemostasis. This protocol has been shown to significantly reduce rebleeding rates.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q6", type: "question", question: "Bright red blood per rectum in a hemodynamically UNSTABLE patient should prompt evaluation of what source?", options: ["Hemorrhoids", "Anal fissure", "Upper GI tract — rapid UGIB can present as hematochezia", "Diverticular disease only"], correctIndex: 2, answer: "Hematochezia (bright red rectal blood) typically indicates lower GI bleeding, but in a hemodynamically unstable patient, it may represent massive upper GI hemorrhage (>1L rapid bleeding). Blood acts as a cathartic, accelerating transit without time for digestion. EGD should be performed first.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-gib-q7", type: "question", question: "What is the most common cause of upper GI bleeding?", options: ["Esophageal varices", "Mallory-Weiss tear", "Peptic ulcer disease (35-50%)", "Gastric cancer"], correctIndex: 2, answer: "Peptic ulcer disease accounts for 35-50% of UGIB cases. H. pylori infection and NSAID use are the primary etiologies. Esophageal varices account for 10-20% but carry higher mortality (30-50%). Mallory-Weiss tears from forceful vomiting cause 5-10%.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q8", type: "question", question: "A patient with suspected variceal bleeding has octreotide ordered. When should it be administered?", options: ["Only after endoscopy confirms variceal source", "Before endoscopy — it should be started immediately upon suspicion", "After the bleeding has stopped", "Only if endoscopy fails"], correctIndex: 1, answer: "Octreotide should be started immediately when variceal bleeding is suspected, BEFORE endoscopy. The 50 mcg IV bolus followed by 50 mcg/hr infusion reduces splanchnic blood flow and portal pressure. Starting before EGD improves endoscopic visualization and hemostasis success.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q9", type: "question", question: "What does a positive orthostatic test indicate in a GI bleeding patient?", options: ["Normal hydration status", "Greater than 15% blood volume loss", "Need for immediate surgery", "Upper GI source confirmed"], correctIndex: 1, answer: "Positive orthostatic changes (HR increase >20 bpm or SBP drop >20 mmHg on standing) indicate approximately 15% or greater blood volume loss. This is an important early indicator of significant hemorrhage when initial Hgb may still be normal due to hemoconcentration.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q10", type: "question", question: "How much blood is needed in the GI tract to produce melena?", options: ["10-25 mL", "50-100 mL", "500 mL", "1000 mL"], correctIndex: 1, answer: "As little as 50-100 mL of blood in the upper GI tract can produce melena. The blood is degraded by gastric acid, intestinal bacteria, and digestive enzymes, turning it black and tarry with a characteristic foul smell. Melena can persist for 3-5 days after the bleeding source has stopped.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q11", type: "question", question: "What is the most common modifiable risk factor for peptic ulcer bleeding?", options: ["H. pylori infection", "NSAID use", "Alcohol consumption", "Smoking"], correctIndex: 1, answer: "NSAID use is the most common modifiable risk factor for peptic ulcer bleeding. NSAIDs inhibit cyclooxygenase (COX), reducing protective prostaglandins in the gastric mucosa. This allows acid-pepsin to erode the mucosal barrier. Discontinuing NSAIDs and using PPIs significantly reduces risk.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q12", type: "question", question: "When should endoscopy (EGD) be performed for a patient with UGIB and suspected variceal source?", options: ["Within 72 hours", "Within 24 hours", "Within 12 hours", "Only if medical therapy fails"], correctIndex: 2, answer: "For suspected variceal bleeding, EGD should be performed within 12 hours (some guidelines say as soon as possible after hemodynamic stabilization). For non-variceal UGIB, within 24 hours is standard. Early endoscopy allows diagnostic and therapeutic intervention (banding, cauterization, clipping).", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q13", type: "question", question: "A patient with GI bleeding is positioned. What is the best position to prevent aspiration from hematemesis?", options: ["Supine flat", "Right lateral with HOB elevated", "Left lateral with HOB elevated", "Prone"], correctIndex: 2, answer: "Left lateral position with HOB elevated helps prevent aspiration during active hematemesis. The left lateral position keeps the gastroesophageal junction above the gastric pool, and HOB elevation uses gravity to reduce aspiration risk. Have suction at bedside and consider intubation for massive hematemesis.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q14", type: "question", question: "What does a Glasgow-Blatchford score of 0 indicate in UGIB?", options: ["Massive hemorrhage requiring ICU", "Moderate risk requiring hospitalization", "Low risk — patient may be safely managed as outpatient", "Score is not clinically useful"], correctIndex: 2, answer: "A Glasgow-Blatchford score of 0 (normal vitals, normal Hgb, normal BUN, no melena/syncope, no liver or heart disease) identifies very low-risk patients who may be safely managed as outpatients without endoscopy. This score has excellent sensitivity for identifying patients who will NOT need intervention.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-gib-q15", type: "question", question: "What is the significance of coffee-ground emesis?", options: ["It is normal after eating dark foods", "Blood degraded by gastric acid indicates upper GI bleeding", "It confirms lower GI bleeding", "It indicates bile reflux"], correctIndex: 1, answer: "Coffee-ground emesis represents blood that has been partially digested by gastric acid, appearing dark brown and granular. It confirms UGIB, though the bleeding may have slowed or stopped (as opposed to bright red hematemesis which indicates active arterial bleeding).", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q16", type: "question", question: "What is the most common cause of painless massive lower GI bleeding in elderly patients?", options: ["Hemorrhoids", "Colorectal cancer", "Diverticular bleeding", "Anal fissure"], correctIndex: 2, answer: "Diverticular bleeding is the most common cause of acute, painless, massive lower GI bleeding in elderly patients. A blood vessel in the diverticulum wall erodes, causing sudden profuse rectal bleeding. 80% stop spontaneously but may require endoscopic or angiographic intervention.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q17", type: "question", question: "A Mallory-Weiss tear is most commonly caused by:", options: ["Chronic alcohol use", "Forceful retching or vomiting", "Ingestion of caustic substances", "Chronic gastritis"], correctIndex: 1, answer: "Mallory-Weiss tears are mucosal lacerations at the gastroesophageal junction caused by forceful retching, vomiting, or straining. They account for 5-10% of UGIB. Risk factors include alcohol binge drinking, bulimia, and severe retching. 90% heal spontaneously without intervention.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q18", type: "question", question: "Which medication corrects warfarin-related coagulopathy in a GI bleeding patient?", options: ["Protamine sulfate", "Vitamin K IV", "Aminocaproic acid", "Desmopressin"], correctIndex: 1, answer: "Vitamin K IV reverses warfarin by restoring hepatic synthesis of vitamin K-dependent clotting factors (II, VII, IX, X). For severe INR elevation with active bleeding, prothrombin complex concentrate (PCC) provides immediate factor replacement. Protamine reverses heparin, not warfarin.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q19", type: "question", question: "A clear NG aspirate in a patient with suspected GI bleeding rules out UGIB. True or false?", options: ["True — clear aspirate excludes UGIB", "False — clear aspirate does not exclude a duodenal source", "True — the test is 100% sensitive", "False — the test is always positive in UGIB"], correctIndex: 1, answer: "A clear NG aspirate does NOT rule out UGIB because a post-pyloric (duodenal) bleeding source may not reflux back through the pylorus into the stomach. A positive aspirate (bloody or coffee-ground) confirms UGIB, but a negative result is inconclusive.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-gib-q20", type: "question", question: "What monitoring interval for hemoglobin is appropriate during active GI bleeding?", options: ["Once daily", "Every 12 hours", "Every 4-6 hours", "Only on admission"], correctIndex: 2, answer: "Serial hemoglobin monitoring every 4-6 hours is indicated during active GI bleeding to assess ongoing blood loss and guide transfusion decisions. The initial value may be normal (hemoconcentration), with the true drop becoming apparent over 24-72 hours as hemodilution occurs.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q21", type: "question", question: "What is the mortality rate of esophageal variceal bleeding?", options: ["<5%", "10-15%", "30-50%", "75-90%"], correctIndex: 2, answer: "Esophageal variceal bleeding carries a mortality rate of 30-50% per episode, making it one of the most lethal causes of GI hemorrhage. Each subsequent episode increases mortality. This is why primary prophylaxis with non-selective beta-blockers or endoscopic variceal ligation is critical.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q22", type: "question", question: "Which GI bleeding assessment finding indicates the patient is in hypovolemic shock?", options: ["Normal vital signs with dark stool", "Tachycardia, hypotension, cool clammy skin, altered mental status", "Bright red rectal bleeding with normal vitals", "Melena with normal hemoglobin"], correctIndex: 1, answer: "Hypovolemic shock presents with tachycardia, hypotension, cool/clammy/pale skin (peripheral vasoconstriction), decreased urine output, restlessness/anxiety progressing to lethargy, and narrowed pulse pressure. These indicate >30% blood volume loss and require immediate aggressive resuscitation.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-gib-q23", type: "question", question: "Why are hyperactive bowel sounds common in GI bleeding?", options: ["Infection is present", "Blood in the GI tract acts as an irritant and cathartic", "The patient has diarrhea from a separate cause", "Bowel obstruction is developing"], correctIndex: 1, answer: "Blood is a potent GI irritant and osmotic cathartic. When blood enters the intestinal lumen, it stimulates increased peristalsis (hyperactive bowel sounds), often causing diarrhea and cramping. This can accelerate transit of blood through the GI tract, sometimes causing hematochezia from an upper source.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q24", type: "question", question: "What intervention does the nurse anticipate for a patient with GI bleeding who fails endoscopic therapy?", options: ["Repeat endoscopy only", "Interventional radiology angiographic embolization", "Oral PPI therapy", "Observation and serial monitoring"], correctIndex: 1, answer: "When endoscopic hemostasis fails, interventional radiology can perform angiographic embolization to occlude the bleeding vessel. This is less invasive than surgery and is effective for both upper and lower GI bleeding. Surgery is reserved for patients who fail both endoscopic and radiologic interventions.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-gib-q25", type: "question", question: "A patient who was previously on aspirin and clopidogrel presents with peptic ulcer bleeding. Should antiplatelet therapy be permanently discontinued?", options: ["Yes — permanently stop all antiplatelet agents", "No — restart after hemostasis is achieved, balancing bleeding vs cardiovascular risk", "Switch to warfarin instead", "Add a second PPI for protection"], correctIndex: 1, answer: "Antiplatelet therapy decisions require balancing bleeding risk against cardiovascular risk (stent thrombosis, MI, stroke). After achieving hemostasis and starting PPI therapy, antiplatelet agents should typically be restarted within 3-7 days in consultation with cardiology. Permanent discontinuation may cause worse cardiovascular outcomes.", category: "Gastrointestinal", difficulty: 3 },

  // === BOWEL OBSTRUCTION (25 cards) ===
  { id: "rn-bo-q1", type: "question", question: "What is the most common cause of small bowel obstruction?", options: ["Colorectal cancer", "Adhesions from prior surgery (60%)", "Hernia", "Volvulus"], correctIndex: 1, answer: "Post-surgical adhesions cause 60% of small bowel obstructions, making it the most common cause and the most common surgical emergency. Adhesions form as part of the normal healing process after abdominal surgery and can create bands that trap or kink bowel loops.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q2", type: "question", question: "What is the '3-6-9 rule' in bowel obstruction imaging?", options: ["Maximum time in hours between imaging studies", "Normal bowel diameter: small bowel >3 cm, large bowel >6 cm, cecum >9 cm = abnormal dilation", "Fluid replacement formula", "Antibiotic dosing intervals"], correctIndex: 1, answer: "The 3-6-9 rule defines abnormal bowel dilation on abdominal X-ray: small bowel >3 cm, large bowel >6 cm, and cecum >9 cm are dilated. Cecal diameter >9-12 cm carries high risk for perforation and is a surgical emergency.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q3", type: "question", question: "A patient with bowel obstruction reports sudden cessation of pain and feeling better. Vital signs show HR 125, BP 85/52, T 39.2C. What does the nurse suspect?", options: ["Spontaneous resolution", "Bowel perforation", "Effective pain medication", "Dehydration improvement"], correctIndex: 1, answer: "Sudden pain relief in a previously obstructed patient with fever, tachycardia, and hypotension strongly suggests bowel perforation. Intraluminal pressure is released (hence pain relief), but peritonitis and sepsis develop rapidly. This is a surgical emergency requiring immediate intervention.", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "Sudden improvement in pain with deteriorating vital signs is an ominous sign — never assume the obstruction has resolved without imaging confirmation." },
  { id: "rn-bo-q4", type: "question", question: "Which bowel sounds are characteristic of mechanical bowel obstruction?", options: ["Absent bowel sounds", "Normal bowel sounds", "High-pitched, tinkling bowel sounds", "Hypoactive bowel sounds"], correctIndex: 2, answer: "Mechanical bowel obstruction produces high-pitched, tinkling or rushing bowel sounds proximal to the obstruction as peristalsis attempts to overcome the blockage. This differentiates mechanical obstruction from paralytic ileus, which presents with absent or hypoactive bowel sounds.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q5", type: "question", question: "What is feculent vomiting and what does it indicate?", options: ["Vomiting blood", "Vomiting with feces-like odor indicating prolonged distal obstruction with bacterial overgrowth", "Vomiting bile", "Normal vomiting pattern"], correctIndex: 1, answer: "Feculent vomiting has a feces-like odor and brown appearance, caused by bacterial overgrowth and degradation of bowel contents proximal to a prolonged obstruction. It is more common in distal SBO and LBO. It indicates a severe, established obstruction requiring urgent intervention.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q6", type: "question", question: "What percentage of adhesive small bowel obstructions resolve with conservative management?", options: ["20-30%", "40-50%", "65-80%", "95-100%"], correctIndex: 2, answer: "Conservative management (NPO, NG decompression, IV fluids) resolves 65-80% of partial adhesive SBOs. The bowel often decompresses as edema subsides. However, complete obstruction or signs of strangulation (increasing pain, fever, leukocytosis, elevated lactate) require urgent surgical exploration.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q7", type: "question", question: "What is the most common cause of large bowel obstruction?", options: ["Adhesions", "Colorectal cancer (60%)", "Volvulus", "Diverticular disease"], correctIndex: 1, answer: "Colorectal cancer accounts for approximately 60% of large bowel obstructions. Unlike SBO where adhesions predominate, LBO is most often caused by malignancy. Diverticular disease (20%) and volvulus (5%) are the next most common causes.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q8", type: "question", question: "Why should barium NEVER be used in a patient with suspected bowel perforation?", options: ["It obscures X-ray findings", "Free barium in the peritoneum causes severe chemical peritonitis", "It causes allergic reactions", "It worsens the obstruction"], correctIndex: 1, answer: "Barium that leaks through a perforation into the peritoneal cavity causes severe, potentially fatal chemical peritonitis. Water-soluble contrast (Gastrografin) should be used instead when perforation is a possibility, as it is safely absorbed from the peritoneum.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q9", type: "question", question: "What medication is FDA-approved specifically for postoperative ileus?", options: ["Metoclopramide", "Alvimopan", "Ondansetron", "Bisacodyl"], correctIndex: 1, answer: "Alvimopan is a peripheral mu-opioid receptor antagonist that blocks opioid effects on the GI tract without affecting central analgesia. It accelerates return of bowel function after surgery. Given 30 min-5 hrs before surgery then BID up to 7 days. Only approved for hospitalized patients.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-bo-q10", type: "question", question: "Why is metoclopramide CONTRAINDICATED in mechanical bowel obstruction?", options: ["It causes cardiac arrhythmias", "It increases intraluminal pressure by enhancing motility against a fixed obstruction", "It masks symptoms of infection", "It interacts with pain medications"], correctIndex: 1, answer: "Metoclopramide is a prokinetic agent that increases GI motility. In mechanical obstruction, increased peristalsis against a fixed blockage raises intraluminal pressure, increasing the risk of bowel perforation and strangulation. It is only appropriate for functional ileus or gastroparesis.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-bo-q11", type: "question", question: "A child presents with sudden-onset colicky abdominal pain, vomiting, and a 'currant jelly' stool. What is the most likely diagnosis?", options: ["Appendicitis", "Intussusception", "Pyloric stenosis", "Meckel diverticulum"], correctIndex: 1, answer: "Intussusception presents with sudden-onset colicky abdominal pain, vomiting, and 'currant jelly' stools (blood and mucus from ischemic bowel mucosa). It is the most common cause of intestinal obstruction in children 6 months to 3 years. A sausage-shaped mass may be palpable in the RUQ.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q12", type: "question", question: "What NG tube setting is appropriate for bowel obstruction decompression?", options: ["Continuous high suction", "Low intermittent suction", "Gravity drainage only", "Continuous low suction"], correctIndex: 1, answer: "Low intermittent suction is the standard NG tube setting for bowel obstruction decompression. Continuous suction can cause gastric mucosal damage and electrolyte imbalances. Record output color, amount, and character each shift. The tube relieves distension and reduces aspiration risk.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q13", type: "question", question: "What electrolyte imbalance is most common with persistent vomiting from proximal SBO?", options: ["Hyperkalemia", "Metabolic acidosis", "Hypochloremic metabolic alkalosis", "Respiratory alkalosis"], correctIndex: 2, answer: "Persistent vomiting from proximal SBO causes loss of HCl (hydrogen and chloride ions), leading to hypochloremic metabolic alkalosis. The kidneys compensate by retaining H+ and excreting K+ and HCO3-, causing hypokalemia. This is the classic metabolic derangement of proximal intestinal obstruction.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q14", type: "question", question: "What is a closed-loop obstruction and why is it a surgical emergency?", options: ["Any bowel obstruction that doesn't resolve in 24 hours", "Both ends of a bowel segment are occluded, causing rapid progression to strangulation and perforation", "Obstruction at the ileocecal valve only", "Obstruction caused by foreign body"], correctIndex: 1, answer: "A closed-loop obstruction occurs when both the proximal and distal ends of a bowel segment are occluded (as in volvulus or incarcerated hernia). The trapped segment cannot decompress, leading to rapid increase in intraluminal pressure, ischemia, necrosis, and perforation. This is always a surgical emergency.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-bo-q15", type: "question", question: "What lab value, if elevated, strongly suggests bowel ischemia/strangulation in an obstructed patient?", options: ["Amylase", "Serum lactate", "BUN", "Alkaline phosphatase"], correctIndex: 1, answer: "Elevated serum lactate indicates tissue ischemia from anaerobic metabolism in strangulated bowel. It is the most sensitive laboratory marker for bowel compromise. A rising lactate in an obstructed patient is an indication for urgent surgical exploration.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q16", type: "question", question: "How does Gastrografin (water-soluble contrast) help in partial SBO management?", options: ["It is only diagnostic", "It has osmotic properties that draw fluid into the lumen and stimulate peristalsis, potentially resolving the obstruction", "It dissolves the adhesion", "It has antibacterial properties"], correctIndex: 1, answer: "Gastrografin is both diagnostic (identifies transition point) and therapeutic. Its hyperosmolarity draws fluid into the bowel lumen, reducing mucosal edema at the obstruction point and stimulating peristalsis. Studies show it reduces time to resolution and need for surgery in partial adhesive SBO.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-bo-q17", type: "question", question: "What initial treatment for sigmoid volvulus is often attempted before surgery?", options: ["Barium enema", "Sigmoidoscopic decompression", "Oral laxatives", "IV antibiotics alone"], correctIndex: 1, answer: "Sigmoid volvulus is initially treated with sigmoidoscopic decompression (inserting a flexible or rigid scope to detorse the bowel). This is successful in 70-80% of cases. However, recurrence rate is high (40-60%), so elective sigmoid resection is often recommended after successful decompression.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q18", type: "question", question: "A postoperative patient has not passed flatus or stool for 4 days and has absent bowel sounds. What type of obstruction is most likely?", options: ["Mechanical obstruction from adhesions", "Paralytic ileus", "Volvulus", "Intussusception"], correctIndex: 1, answer: "Absent bowel sounds, no flatus or stool, and abdominal distension after surgery without colicky pain is characteristic of paralytic ileus. Postoperative ileus results from temporary inhibition of peristalsis due to surgical manipulation, anesthesia, and opioid use. It typically resolves in 3-5 days.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q19", type: "question", question: "What nursing assessment differentiates SBO from LBO?", options: ["SBO has early vomiting and mild distension; LBO has late vomiting and prominent distension", "Both present identically", "LBO always has bloody stool", "SBO is painless"], correctIndex: 0, answer: "In SBO, vomiting occurs early and prominently because the obstruction is proximal, while distension is relatively mild. In LBO, the colon can accommodate more volume, so distension is marked but vomiting occurs late (after significant retrograde backup). LBO also presents with obstipation (no passage of gas or stool).", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q20", type: "question", question: "After surgery for bowel obstruction, what finding indicates return of bowel function?", options: ["Absence of NG drainage", "Passage of flatus", "Patient reports hunger", "Clear liquid tolerance"], correctIndex: 1, answer: "Passage of flatus is the most reliable indicator of return of bowel function after surgery. It indicates that peristalsis has resumed and gas is moving through the entire GI tract. This is typically followed by the return of bowel sounds and ability to tolerate oral intake.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q21", type: "question", question: "How often should the nurse measure abdominal girth in a patient with bowel obstruction?", options: ["Once daily", "Every 8 hours at the umbilicus level", "Only on admission", "Every 2 hours"], correctIndex: 1, answer: "Abdominal girth should be measured at the umbilicus level every 8 hours using the same anatomical landmark each time. Mark the measurement point to ensure consistency. Increasing girth indicates worsening distension. Decreasing girth after NG decompression suggests improvement.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q22", type: "question", question: "What oral care frequency is recommended for an NPO patient with an NG tube?", options: ["Once daily", "Every 2 hours", "Every 8 hours", "Only when requested"], correctIndex: 1, answer: "Oral care every 2 hours is essential for patients who are NPO with NG tubes. The NG tube causes mouth breathing, drying of mucous membranes, and is uncomfortable. Moisten lips with water-based lubricant, perform mouth care with sponge swabs, and keep the nares clean around the tube.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-bo-q23", type: "question", question: "Which sign indicates strangulation in a patient with bowel obstruction?", options: ["Intermittent colicky pain relieved by vomiting", "Constant severe pain, fever, tachycardia, and peritoneal signs (rebound, rigidity)", "Mild nausea without pain", "Normal vital signs with distension"], correctIndex: 1, answer: "Strangulation is indicated by a shift from intermittent colicky pain to constant severe pain, accompanied by fever, tachycardia, leukocytosis, elevated lactate, and peritoneal signs (rebound tenderness, guarding, rigidity). These indicate bowel ischemia/necrosis requiring emergent surgery.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-bo-q24", type: "question", question: "What is the treatment for cecal volvulus?", options: ["Sigmoidoscopic decompression", "Surgical intervention (cecal volvulus cannot be managed endoscopically)", "Barium enema reduction", "Conservative management with IV fluids"], correctIndex: 1, answer: "Unlike sigmoid volvulus, cecal volvulus requires surgical intervention (right hemicolectomy or cecopexy). Endoscopic decompression is not effective for cecal volvulus. Cecal volvulus is more common in younger patients and carries higher strangulation risk than sigmoid volvulus.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-bo-q25", type: "question", question: "What position should the nurse use for a patient with bowel obstruction and significant abdominal distension?", options: ["Supine flat", "Trendelenburg", "Semi-Fowler's position", "Prone"], correctIndex: 2, answer: "Semi-Fowler's position (30-45 degrees) reduces diaphragmatic pressure from the distended abdomen, improving respiratory function. Abdominal distension can compromise breathing by limiting diaphragmatic excursion. This position also promotes comfort and reduces nausea.", category: "Gastrointestinal", difficulty: 1 },

  // === IBD: CROHN VS UC (25 cards) ===
  { id: "rn-ibd-q1", type: "question", question: "Which type of IBD can be CURED by surgery?", options: ["Crohn disease", "Ulcerative colitis (total proctocolectomy)", "Both can be cured", "Neither can be cured"], correctIndex: 1, answer: "Ulcerative colitis can be cured by total proctocolectomy with ileal pouch-anal anastomosis (J-pouch) because UC is limited to the colon and rectum. Crohn disease has NO surgical cure — it can affect any part of the GI tract and recurs after resection (70% recurrence rate).", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q2", type: "question", question: "Smoking has opposite effects on Crohn disease and UC. Which statement is correct?", options: ["Smoking improves both conditions", "Smoking worsens Crohn but is paradoxically protective in UC", "Smoking worsens UC but improves Crohn", "Smoking has no effect on either"], correctIndex: 1, answer: "Smoking worsens Crohn disease (doubles post-surgical recurrence, increases flare frequency) but is paradoxically protective in UC. Former smokers have higher UC risk than current smokers. However, smoking is never recommended as treatment — the overall health risks far outweigh any UC benefit.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q3", type: "question", question: "What lab test should be performed BEFORE starting azathioprine for IBD?", options: ["Serum creatinine", "TPMT (thiopurine methyltransferase) enzyme level", "Hepatitis panel", "ESR"], correctIndex: 1, answer: "TPMT testing is essential before initiating azathioprine or 6-mercaptopurine. TPMT deficiency (1 in 300 patients) causes inability to metabolize thiopurines, leading to life-threatening myelosuppression (severe pancytopenia). Patients with deficiency should NOT receive thiopurines.", category: "Gastrointestinal", difficulty: 3, clinicalPearl: "TPMT testing can save lives — complete deficiency causes fatal bone marrow failure if thiopurines are given at standard doses." },
  { id: "rn-ibd-q4", type: "question", question: "What complication should be avoided by NOT giving opioids or anticholinergics during an acute UC flare?", options: ["Hepatotoxicity", "Toxic megacolon", "Pancreatitis", "Seizures"], correctIndex: 1, answer: "Opioids, anticholinergics, and other drugs that decrease colonic motility can precipitate toxic megacolon during acute UC flares. They cause colonic dilation and fecal stasis, worsening mucosal inflammation and risking perforation. Toxic megacolon is defined as colonic dilation >6 cm with systemic toxicity.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q5", type: "question", question: "What is the characteristic stool pattern in ulcerative colitis?", options: ["Non-bloody diarrhea with fat malabsorption", "Bloody diarrhea with mucus and tenesmus", "Constipation alternating with diarrhea", "Large-volume watery diarrhea"], correctIndex: 1, answer: "UC classically presents with bloody diarrhea containing mucus, accompanied by tenesmus (urgency with incomplete evacuation) and rectal bleeding. The continuous mucosal inflammation produces blood and mucus. Crohn typically produces non-bloody diarrhea unless there is concurrent colonic involvement.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q6", type: "question", question: "What screening must be done BEFORE starting a biologic agent like infliximab?", options: ["Coagulation studies", "Latent TB screen (PPD/IGRA), hepatitis B, and immunization status", "Renal function panel", "Cardiac stress test"], correctIndex: 1, answer: "Before starting anti-TNF biologics, patients must be screened for latent TB (TNF-alpha inhibition can reactivate latent TB), hepatitis B (risk of reactivation), and immunization status (live vaccines are contraindicated during biologic therapy). A negative TB test is required before initiating therapy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q7", type: "question", question: "A patient with Crohn disease develops a perianal fistula. What is the first-line treatment?", options: ["Mesalamine suppositories", "Metronidazole (with or without ciprofloxacin)", "High-dose prednisone", "Immediate surgical resection"], correctIndex: 1, answer: "Perianal fistulae in Crohn are initially treated with antibiotics (metronidazole +/- ciprofloxacin). Complex or refractory fistulae may require anti-TNF biologics (infliximab has the best evidence for fistula healing). Surgical intervention (seton placement, fistulotomy) is considered for recurrent cases.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q8", type: "question", question: "At what point after IBD diagnosis should colorectal cancer surveillance colonoscopy begin?", options: ["At diagnosis", "5 years after diagnosis", "8-10 years after diagnosis, then every 1-2 years", "Only if symptoms change"], correctIndex: 2, answer: "Colorectal cancer risk increases significantly after 8-10 years of IBD (especially UC with extensive colitis). Surveillance colonoscopy with random biopsies should be performed every 1-2 years starting at this timepoint. UC carries higher cancer risk than Crohn due to continuous mucosal inflammation.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q9", type: "question", question: "What is a key colonoscopy finding that differentiates Crohn from UC?", options: ["Continuous inflammation from the rectum = UC; skip lesions with cobblestone mucosa = Crohn", "Both show identical findings", "UC has skip lesions; Crohn is continuous", "Neither can be differentiated by colonoscopy"], correctIndex: 0, answer: "UC shows continuous inflammation always starting at the rectum and extending proximally, with crypt abscesses and pseudopolyps. Crohn shows skip lesions (diseased segments separated by normal bowel), cobblestone mucosa, deep linear ulcers, and non-caseating granulomas on biopsy.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q10", type: "question", question: "Which extraintestinal manifestation of IBD produces tender red nodules on the shins?", options: ["Pyoderma gangrenosum", "Erythema nodosum", "Uveitis", "Primary sclerosing cholangitis"], correctIndex: 1, answer: "Erythema nodosum presents as tender, raised, red/violet nodules on the anterior shins. It is one of the most common extraintestinal manifestations of IBD, correlating with disease activity. Pyoderma gangrenosum produces deep, painful ulcers (different from erythema nodosum's nodular pattern).", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q11", type: "question", question: "Which IBD type is more commonly associated with primary sclerosing cholangitis (PSC)?", options: ["Crohn disease", "Ulcerative colitis", "Both equally", "Neither"], correctIndex: 1, answer: "Primary sclerosing cholangitis (inflammation and fibrosis of bile ducts) is more commonly associated with UC than Crohn. About 70-80% of PSC patients have UC. PSC increases the risk of cholangiocarcinoma and is an independent risk factor for colorectal cancer in UC patients.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-ibd-q12", type: "question", question: "Why should corticosteroids NOT be used for maintenance therapy in IBD?", options: ["They are not effective against inflammation", "Long-term use causes serious side effects (osteoporosis, diabetes, infection, adrenal suppression) without maintaining remission", "They worsen IBD symptoms", "They interact with all IBD medications"], correctIndex: 1, answer: "Corticosteroids are effective for inducing remission during acute flares but should NOT be used for maintenance. Long-term use causes osteoporosis, diabetes, cataracts, immunosuppression, adrenal suppression, and weight gain. Steroid-sparing agents (immunomodulators, biologics) are used for maintenance.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q13", type: "question", question: "What complication of Crohn disease is caused by transmural inflammation?", options: ["Crypt abscesses", "Pseudopolyps", "Fistulae (abnormal connections between bowel and other organs/skin)", "Toxic megacolon"], correctIndex: 2, answer: "Crohn disease's transmural inflammation (affecting all bowel wall layers from mucosa to serosa) leads to fistula formation — abnormal connections between bowel segments, or between bowel and skin, bladder, or vagina. UC only affects the mucosa and submucosa and does not form fistulae.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q14", type: "question", question: "What is the first-line medication for mild-to-moderate ulcerative colitis?", options: ["Prednisone", "Infliximab", "Mesalamine (5-ASA)", "Azathioprine"], correctIndex: 2, answer: "Mesalamine (5-ASA) is first-line for mild-to-moderate UC. It works topically on the colonic mucosa to reduce inflammation by inhibiting prostaglandin and leukotriene synthesis. Available as oral, rectal suppository, and enema formulations. It is less effective in Crohn disease.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q15", type: "question", question: "What abdominal X-ray finding constitutes an emergency in an UC patient?", options: ["Small bowel dilation >3 cm", "Colonic dilation >6 cm (toxic megacolon)", "Calcified gallstones", "Free air under the diaphragm"], correctIndex: 1, answer: "Colonic dilation >6 cm on X-ray defines toxic megacolon — a life-threatening complication of UC. It is accompanied by systemic toxicity (fever >38.6C, tachycardia, leukocytosis, anemia). Free air under the diaphragm would indicate perforation, which is an even more dire emergency.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q16", type: "question", question: "What stool biomarker is used to assess intestinal inflammation in IBD?", options: ["Fecal occult blood", "Fecal calprotectin", "Stool pH", "Stool electrolytes"], correctIndex: 1, answer: "Fecal calprotectin is a protein released by activated neutrophils in the inflamed intestinal lumen. It is a reliable non-invasive biomarker for intestinal inflammation and correlates with endoscopic disease activity. It is used to monitor disease activity and response to treatment without repeated colonoscopy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q17", type: "question", question: "Why is growth failure a significant concern in pediatric Crohn disease?", options: ["Crohn disease causes kidney failure in children", "Chronic inflammation, malabsorption, and anorexia impair normal growth and pubertal development", "Crohn disease only affects children", "Growth failure is not related to IBD"], correctIndex: 1, answer: "Pediatric Crohn disease causes growth failure through chronic inflammation (elevated cytokines suppress growth hormone axis), malnutrition (anorexia, malabsorption from inflamed small bowel), and corticosteroid use (inhibits bone growth). Growth velocity monitoring is essential in pediatric IBD.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q18", type: "question", question: "What is the J-pouch surgical procedure for UC?", options: ["Partial colectomy", "Total proctocolectomy with ileal pouch-anal anastomosis — the ileum is formed into a reservoir connected to the anus", "Ileostomy only", "Colostomy placement"], correctIndex: 1, answer: "The J-pouch (ileal pouch-anal anastomosis or IPAA) involves removing the entire colon and rectum, then folding the terminal ileum into a J-shaped reservoir that is connected to the anus. This preserves fecal continence while removing all diseased tissue. It is curative for UC.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q19", type: "question", question: "What serologic markers help differentiate UC from Crohn (though neither is diagnostic alone)?", options: ["ANA and anti-dsDNA", "pANCA (more common in UC) and ASCA (more common in Crohn)", "RF and anti-CCP", "C3 and C4 complement levels"], correctIndex: 1, answer: "pANCA (perinuclear antineutrophil cytoplasmic antibodies) is found in 60-70% of UC patients. ASCA (anti-Saccharomyces cerevisiae antibodies) is found in 60-70% of Crohn patients. Neither is diagnostic alone but the pattern can help differentiate indeterminate cases.", category: "Gastrointestinal", difficulty: 3 },
  { id: "rn-ibd-q20", type: "question", question: "Which location in the GI tract is most commonly affected by Crohn disease?", options: ["Esophagus", "Stomach", "Terminal ileum", "Rectum"], correctIndex: 2, answer: "The terminal ileum is the most commonly affected site in Crohn disease, which is why RLQ pain is the typical presentation. However, Crohn can affect any part of the GI tract from mouth to anus, unlike UC which is limited to the colon and rectum.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q21", type: "question", question: "What is the primary concern with long-term infliximab therapy?", options: ["Hepatotoxicity", "Increased risk of infections (including TB reactivation) and rare lymphoma", "Renal failure", "Pulmonary fibrosis"], correctIndex: 1, answer: "Anti-TNF agents like infliximab increase infection risk because TNF-alpha is critical for immune defense, particularly against intracellular organisms. TB reactivation is a specific concern. There is also a rare but real increased risk of lymphoma, particularly hepatosplenic T-cell lymphoma in young males on combination therapy.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q22", type: "question", question: "What is the significance of non-caseating granulomas found on biopsy?", options: ["They are pathognomonic for UC", "They are characteristic of Crohn disease (found in ~30% of biopsies)", "They indicate malignancy", "They are a normal finding"], correctIndex: 1, answer: "Non-caseating granulomas are found in approximately 30% of Crohn disease biopsies and are considered characteristic (though not pathognomonic, as sarcoidosis and other conditions can cause them). They are NOT found in UC, making their presence a helpful differentiating feature.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q23", type: "question", question: "Why is budesonide preferred over prednisone for mild-moderate ileal Crohn flares?", options: ["It is less expensive", "High first-pass hepatic metabolism reduces systemic steroid side effects while maintaining local anti-inflammatory action", "It is more potent than prednisone", "It can be used for maintenance therapy"], correctIndex: 1, answer: "Budesonide is a corticosteroid with high topical anti-inflammatory potency but extensive first-pass hepatic metabolism (90%), resulting in significantly fewer systemic side effects (adrenal suppression, bone loss, hyperglycemia) compared to prednisone. It is effective for ileal and right-sided colonic Crohn disease.", category: "Gastrointestinal", difficulty: 2 },
  { id: "rn-ibd-q24", type: "question", question: "What dietary recommendation should the nurse provide during an IBD flare?", options: ["High-fiber, raw vegetable diet", "Low-residue diet to reduce bowel stimulation, avoiding raw fruits/vegetables, whole grains, and nuts", "Dairy-rich diet for calcium", "No dietary modifications needed"], correctIndex: 1, answer: "During IBD flares, a low-residue diet reduces bowel stimulation and diarrhea. Avoid raw fruits/vegetables, whole grains, nuts, seeds, and high-fiber foods. During remission, a normal balanced diet can be resumed with individual trigger avoidance. Lactose intolerance is common and should be assessed.", category: "Gastrointestinal", difficulty: 1 },
  { id: "rn-ibd-q25", type: "question", question: "What is the Crohn disease recurrence rate after bowel resection?", options: ["<10%", "20-30%", "70% (recurrence, usually at anastomotic site)", "100%"], correctIndex: 2, answer: "Crohn disease recurs in approximately 70% of patients after surgical resection, typically at the surgical anastomosis site. This is why surgery is reserved for complications (strictures, fistulae, perforation) rather than used as primary therapy. Post-surgical prophylaxis with biologics or immunomodulators reduces recurrence.", category: "Gastrointestinal", difficulty: 2 },

  // === CANCER BIOLOGY (25 cards) ===
  { id: "rn-onc-q1", type: "question", question: "Which tumor suppressor gene is mutated in >50% of all human cancers and is called the 'guardian of the genome'?", options: ["BRCA1", "Rb", "p53", "APC"], correctIndex: 2, answer: "p53 is the most commonly mutated gene in cancer. It normally stops the cell cycle at the G1 checkpoint to allow DNA repair or triggers apoptosis if damage is irreparable. When both copies are inactivated, damaged cells bypass the checkpoint and continue dividing with accumulated mutations.", category: "Oncology", difficulty: 1 },
  { id: "rn-onc-q2", type: "question", question: "What is the most important prognostic factor in cancer?", options: ["Tumor grade", "Tumor stage (TNM)", "Patient age", "Tumor marker level"], correctIndex: 1, answer: "TNM staging (Tumor size, Node involvement, Metastasis) is the most important prognostic factor. It describes the anatomic extent of disease and determines treatment approach and survival expectations. Grading reflects aggressiveness of individual cells but staging determines overall outcomes.", category: "Oncology", difficulty: 1 },
  { id: "rn-onc-q3", type: "question", question: "When does the chemotherapy nadir typically occur, and what does it mean?", options: ["Day 1 — first day of treatment", "Days 7-14 — lowest blood cell count and highest infection risk", "Day 21 — end of treatment cycle", "Day 30 — one month after treatment"], correctIndex: 1, answer: "The nadir is the point of lowest blood cell counts, typically occurring 7-14 days after chemotherapy. This is when infection risk is highest due to neutropenia, bleeding risk is highest due to thrombocytopenia, and fatigue is worst due to anemia. Counts typically recover by days 21-28.", category: "Oncology", difficulty: 2, clinicalPearl: "Plan protective measures (neutropenic precautions, bleeding precautions) during the expected nadir period." },
  { id: "rn-onc-q4", type: "question", question: "During doxorubicin administration, the nurse notices swelling at the IV site. The drug is a vesicant. What is the priority action?", options: ["Flush with normal saline to dilute", "Stop the infusion immediately and aspirate residual drug", "Apply a warm compress and continue", "Increase the infusion rate"], correctIndex: 1, answer: "Vesicant extravasation requires IMMEDIATE action: stop the infusion, aspirate residual drug through the catheter, and apply the appropriate antidote (dexrazoxane for anthracyclines). NEVER flush the line — it disperses the vesicant into surrounding tissue, worsening necrosis.", category: "Oncology", difficulty: 3 },
  { id: "rn-onc-q5", type: "question", question: "What is the maximum cumulative dose of doxorubicin and what toxicity does it cause?", options: ["250 mg/m2 — hepatotoxicity", "450-550 mg/m2 — cumulative cardiotoxicity (cardiomyopathy)", "750 mg/m2 — nephrotoxicity", "1000 mg/m2 — neurotoxicity"], correctIndex: 1, answer: "Doxorubicin has a lifetime cumulative dose limit of 450-550 mg/m2 due to dose-dependent irreversible cardiotoxicity (dilated cardiomyopathy). Monitor LVEF with echocardiogram or MUGA scan before and during therapy. Dexrazoxane provides cardioprotection in patients approaching dose limits.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q6", type: "question", question: "Why must hemorrhagic cystitis be prevented with cyclophosphamide therapy?", options: ["It is a minor side effect", "Cyclophosphamide's metabolite acrolein damages the bladder epithelium, causing severe hemorrhagic cystitis", "It causes kidney stones", "It is not a real side effect"], correctIndex: 1, answer: "Cyclophosphamide is metabolized to acrolein, which is directly toxic to the bladder mucosa. Prevention includes aggressive hydration, MESNA (binds acrolein in urine), and frequent voiding. Patients should drink 2-3 L/day of fluids and void every 1-2 hours, including once at night.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q7", type: "question", question: "What side effect should the nurse monitor for when trastuzumab is given with doxorubicin?", options: ["Nephrotoxicity", "Synergistic cardiotoxicity (do NOT give concurrently)", "Hepatotoxicity", "Ototoxicity"], correctIndex: 1, answer: "Trastuzumab and anthracyclines (doxorubicin) have synergistic cardiotoxicity and should NOT be given concurrently. Trastuzumab-related cardiomyopathy is typically reversible, unlike anthracycline cardiotoxicity. Sequential administration is used. Monitor LVEF every 3 months during trastuzumab therapy.", category: "Oncology", difficulty: 3 },
  { id: "rn-onc-q8", type: "question", question: "A patient's ANC is 850/mm3. What neutropenic precautions should be implemented?", options: ["No precautions needed until ANC <200", "Private room, hand hygiene, no fresh flowers/fruits, cooked foods only, limit visitors", "Airborne isolation with N95 mask", "Droplet precautions only"], correctIndex: 1, answer: "ANC <1000 indicates severe neutropenia requiring protective precautions: private room, strict hand hygiene, no fresh flowers/fruits (harbor Aspergillus), cooked foods only, limit visitors, screen visitors for illness. These measures reduce exposure to potential pathogens.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q9", type: "question", question: "What is the WHO pain ladder approach for cancer pain management?", options: ["Start with strong opioids for all cancer pain", "Step 1: non-opioids; Step 2: weak opioids; Step 3: strong opioids (with adjuvants at each step)", "Use only non-pharmacologic interventions", "Avoid all opioids in cancer patients"], correctIndex: 1, answer: "The WHO pain ladder: Step 1 (mild) = non-opioid analgesics (acetaminophen, NSAIDs) +/- adjuvants; Step 2 (moderate) = weak opioids (codeine, tramadol) + non-opioids +/- adjuvants; Step 3 (severe) = strong opioids (morphine, fentanyl) + non-opioids +/- adjuvants. Cancer pain should be treated aggressively.", category: "Oncology", difficulty: 1 },
  { id: "rn-onc-q10", type: "question", question: "What is the 'two-hit hypothesis' in cancer genetics?", options: ["Cancer requires two chemotherapy agents", "Both alleles of a tumor suppressor gene must be inactivated before its protective function is lost", "Two mutations in one oncogene are needed", "Two separate cancers must develop"], correctIndex: 1, answer: "Knudson's two-hit hypothesis states that tumor suppressor genes require inactivation of BOTH copies (alleles) to lose function. In hereditary cancer, one 'hit' is inherited (germline mutation), requiring only one somatic mutation. In sporadic cancer, both hits must occur somatically, explaining later onset.", category: "Oncology", difficulty: 3 },
  { id: "rn-onc-q11", type: "question", question: "What are the seven warning signs of cancer (CAUTION)?", options: ["Seven types of chemotherapy drugs", "C-change in bowel/bladder, A-sore that doesn't heal, U-unusual bleeding, T-thickening/lump, I-indigestion/difficulty swallowing, O-obvious change in mole, N-nagging cough", "Seven stages of cancer", "Seven tumor markers"], correctIndex: 1, answer: "CAUTION: Change in bowel/bladder habits, A sore that does not heal, Unusual bleeding/discharge, Thickening or lump, Indigestion or difficulty swallowing, Obvious change in wart/mole, Nagging cough or hoarseness. These warning signs prompt further evaluation for malignancy.", category: "Oncology", difficulty: 1 },
  { id: "rn-onc-q12", type: "question", question: "What antiemetic protocol is recommended before highly emetogenic chemotherapy?", options: ["Ondansetron alone", "Triple therapy: 5-HT3 antagonist (ondansetron) + corticosteroid (dexamethasone) + NK1 antagonist (aprepitant)", "Prochlorperazine only", "No antiemetics — wait until nausea develops"], correctIndex: 1, answer: "Highly emetogenic chemotherapy (cisplatin, cyclophosphamide) requires triple antiemetic therapy: 5-HT3 receptor antagonist + dexamethasone + NK1 receptor antagonist (aprepitant or fosaprepitant). Administer 30 minutes before chemotherapy. This combination significantly reduces acute and delayed chemotherapy-induced nausea and vomiting.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q13", type: "question", question: "What distinguishes oncogenes from tumor suppressor genes?", options: ["They are the same thing", "Oncogenes promote growth when activated; tumor suppressors inhibit growth and must be inactivated for cancer to develop", "Tumor suppressors promote growth; oncogenes inhibit it", "Neither is involved in cancer"], correctIndex: 1, answer: "Oncogenes are mutated proto-oncogenes that promote uncontrolled cell growth (gain of function). Only ONE copy needs to be activated. Tumor suppressor genes normally act as 'brakes' on cell division; BOTH copies must be inactivated (loss of function) for their protective effect to be lost.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q14", type: "question", question: "What tumor marker is used to monitor colorectal cancer treatment response?", options: ["PSA", "CA-125", "CEA (carcinoembryonic antigen)", "AFP"], correctIndex: 2, answer: "CEA is the primary tumor marker for colorectal cancer monitoring. Rising CEA after treatment suggests recurrence. It is not used for screening (not specific enough) but is valuable for monitoring treatment response and detecting recurrence. PSA = prostate, CA-125 = ovarian, AFP = liver/testicular.", category: "Oncology", difficulty: 1 },
  { id: "rn-onc-q15", type: "question", question: "What safety precautions must the nurse use when handling chemotherapy?", options: ["Standard gloves only", "Closed-system transfer devices, double gloving, gown, eye protection, and ventilated engineering controls", "No special precautions needed", "N95 mask only"], correctIndex: 1, answer: "Chemotherapy is hazardous to healthcare workers. Use closed-system transfer devices (CSTDs), double gloving with chemotherapy-rated gloves, disposable gown, eye protection, and prepare in a ventilated biological safety cabinet. Spills require specialized cleanup kits. Never eat/drink near chemotherapy areas.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q16", type: "question", question: "What is angiogenesis and why is it important in cancer?", options: ["Blood cell formation in bone marrow", "Formation of new blood vessels that tumors need for growth beyond 1-2 mm via VEGF signaling", "Development of new nerve connections", "Bone formation at tumor sites"], correctIndex: 1, answer: "Angiogenesis is the formation of new blood vessels driven by vascular endothelial growth factor (VEGF). Tumors cannot grow beyond 1-2 mm without their own blood supply. Anti-angiogenic agents (bevacizumab) block VEGF, starving the tumor of nutrients and oxygen.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q17", type: "question", question: "A patient on chemotherapy has an ANC of 300/mm3 and develops a temperature of 38.5C. What is the FIRST action?", options: ["Apply cooling blankets", "Give acetaminophen and monitor", "Draw blood cultures and prepare for immediate broad-spectrum antibiotic administration", "Wait for the provider to round"], correctIndex: 2, answer: "Febrile neutropenia (ANC <500 + fever >=38.3C) is a medical emergency. Blood cultures and empiric broad-spectrum antibiotics (cefepime, piperacillin-tazobactam, or meropenem) within 60 minutes are critical. Each hour of delay increases mortality. Do NOT give antipyretics before cultures.", category: "Oncology", difficulty: 3 },
  { id: "rn-onc-q18", type: "question", question: "What paraneoplastic syndrome is associated with small cell lung cancer?", options: ["Hypercalcemia", "SIADH (syndrome of inappropriate ADH secretion)", "Cushing syndrome from ectopic cortisol", "Erythrocytosis"], correctIndex: 1, answer: "Small cell lung cancer commonly causes SIADH through ectopic ADH production, leading to dilutional hyponatremia, water retention, and concentrated urine. Symptoms include confusion, seizures, and edema. Treatment includes fluid restriction and treating the underlying cancer. Squamous cell lung cancer causes hypercalcemia (PTHrP).", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q19", type: "question", question: "What does HER2-positive breast cancer mean for treatment?", options: ["No targeted therapy available", "The tumor overexpresses HER2 receptors and responds to trastuzumab (targeted therapy)", "Surgery is not possible", "Hormone therapy is the only option"], correctIndex: 1, answer: "HER2-positive breast cancer (20-25% of cases) overexpresses the HER2/neu growth factor receptor. Trastuzumab (Herceptin) specifically targets this receptor, significantly improving outcomes. HER2 status is determined by IHC or FISH testing on biopsy tissue. It guides targeted therapy selection.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q20", type: "question", question: "What PPE is needed when caring for a patient within 48 hours of chemotherapy who vomits or has diarrhea?", options: ["No special precautions", "Double gloves, gown, and face shield — body fluids contain cytotoxic drug metabolites for 48 hours", "Standard gloves only", "N95 respirator only"], correctIndex: 1, answer: "For 48 hours after chemotherapy, body fluids (urine, stool, emesis, blood) contain cytotoxic drug metabolites. Handle with double gloves, gown, and face shield. Flush toilet twice after patient uses it. Soiled linens should be handled as hazardous waste. This protects healthcare workers from occupational exposure.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q21", type: "question", question: "What is tumor lysis syndrome and when does it typically occur?", options: ["Tumor growth acceleration during chemotherapy", "Rapid destruction of tumor cells releasing intracellular contents (K+, PO4, uric acid), typically 12-72 hours after treatment initiation", "Tumor metastasis to the liver", "Immune reaction against tumor cells"], correctIndex: 1, answer: "Tumor lysis syndrome occurs when rapid destruction of cancer cells (typically during initial chemotherapy for high-burden hematologic malignancies) releases massive amounts of potassium, phosphorus, and uric acid. This causes hyperkalemia, hyperphosphatemia, hyperuricemia, and secondary hypocalcemia — potentially fatal if not prevented.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q22", type: "question", question: "How do checkpoint inhibitors (pembrolizumab, nivolumab) work?", options: ["They directly kill cancer cells", "They block PD-1/PD-L1 pathways, allowing the patient's own immune system to recognize and attack cancer cells", "They prevent blood vessel formation", "They block hormone receptors"], correctIndex: 1, answer: "Checkpoint inhibitors block immune checkpoint proteins (PD-1 on T cells or PD-L1 on cancer cells) that cancer uses to evade immune detection. By blocking these 'don't attack me' signals, the immune system can recognize and destroy cancer cells. Side effects include immune-related adverse events in any organ.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q23", type: "question", question: "What test should be performed before starting pembrolizumab for cancer?", options: ["Renal function", "PD-L1 expression testing on the tumor", "Blood type and crossmatch", "EEG"], correctIndex: 1, answer: "PD-L1 expression testing determines whether the tumor is likely to respond to checkpoint inhibitor therapy. Higher PD-L1 expression generally predicts better response. However, some cancers respond regardless of PD-L1 status (e.g., MSI-high tumors), so testing is part of a broader biomarker assessment.", category: "Oncology", difficulty: 3 },
  { id: "rn-onc-q24", type: "question", question: "What is the role of BRCA1/2 genetic testing in cancer management?", options: ["It diagnoses cancer", "It identifies hereditary breast/ovarian cancer risk, guiding prevention and targeted therapy decisions", "It monitors treatment response", "It determines tumor grade"], correctIndex: 1, answer: "BRCA1/2 mutations significantly increase lifetime risk of breast cancer (60-80%) and ovarian cancer (20-40%). Testing guides decisions about prophylactic surgery, enhanced screening, and targeted therapy (PARP inhibitors like olaparib work specifically in BRCA-mutated tumors). Genetic counseling is essential.", category: "Oncology", difficulty: 2 },
  { id: "rn-onc-q25", type: "question", question: "What nutritional intervention is important for a patient experiencing chemotherapy-induced mucositis?", options: ["Encourage spicy foods to stimulate appetite", "Soft, bland, cool or room-temperature foods; avoid acidic, spicy, and rough-textured foods", "NPO until mucositis resolves", "Only liquid supplements"], correctIndex: 1, answer: "Chemotherapy-induced mucositis makes eating painful. Provide soft, bland, cool/room-temperature foods. Avoid acidic (citrus), spicy, rough-textured, and very hot/cold foods. Use a soft toothbrush, avoid alcohol-based mouthwash, and rinse with baking soda/saline solution. Monitor for weight loss and dehydration.", category: "Oncology", difficulty: 1 },

  // === ONCOLOGIC EMERGENCIES (25 cards) ===
  { id: "rn-oncem-q1", type: "question", question: "A patient with Burkitt lymphoma starts chemotherapy. What electrolyte pattern indicates tumor lysis syndrome?", options: ["Low K+, low PO4, high Ca2+, low uric acid", "High K+, high PO4, high uric acid, low Ca2+", "Normal electrolytes with elevated WBC", "High Na+, low K+, high Ca2+"], correctIndex: 1, answer: "TLS classic pattern: hyperkalemia (cardiac arrhythmia risk), hyperphosphatemia, hyperuricemia (crystal nephropathy), and secondary hypocalcemia (calcium-phosphate precipitates). Remember: 3 HIGHs (K+, PO4, uric acid) and 1 LOW (Ca2+). Burkitt lymphoma is highest risk due to extremely rapid cell turnover.", category: "Oncology", difficulty: 2, clinicalPearl: "TLS can occur within 12-72 hours of chemotherapy initiation. Prevention with aggressive hydration and allopurinol is critical." },
  { id: "rn-oncem-q2", type: "question", question: "What medication is contraindicated in patients with G6PD deficiency who have tumor lysis syndrome?", options: ["Allopurinol", "Rasburicase", "Calcium gluconate", "Normal saline"], correctIndex: 1, answer: "Rasburicase (recombinant urate oxidase) is contraindicated in G6PD deficiency because it can cause severe hemolytic anemia and methemoglobinemia in these patients. Screen African American, Mediterranean, and Southeast Asian patients for G6PD before administering. Use allopurinol instead.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q3", type: "question", question: "A patient with metastatic prostate cancer reports severe back pain worse at night and new bilateral leg weakness. What emergency is suspected?", options: ["Pathological vertebral fracture", "Spinal cord compression", "Peripheral neuropathy", "Muscle spasm"], correctIndex: 1, answer: "Back pain (worst at night), progressive motor weakness, and bowel/bladder dysfunction in a cancer patient strongly suggest spinal cord compression. This is a neurological emergency — permanent paralysis results if not treated within 24-48 hours. Immediate MRI and high-dose dexamethasone are indicated.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q4", type: "question", question: "What is the initial treatment for spinal cord compression from metastatic cancer?", options: ["Oral ibuprofen", "High-dose dexamethasone (10 mg IV bolus then 4 mg q6h)", "Physical therapy", "Watchful waiting"], correctIndex: 1, answer: "Immediate high-dose dexamethasone reduces peritumoral edema, providing rapid symptom relief and preserving neurological function while definitive treatment (radiation, surgery) is arranged. Time is critical — 'time is function.' Once paraplegia develops, it is usually irreversible.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q5", type: "question", question: "A patient with lung cancer develops facial edema, JVD, and upper extremity swelling. The nurse avoids:", options: ["Elevating the head of bed", "Taking BP or starting IVs in the upper extremities", "Providing supplemental oxygen", "Notifying the provider"], correctIndex: 1, answer: "SVC syndrome impairs venous drainage from the upper body. BP measurement and venipuncture in upper extremities are avoided because impaired venous return causes inaccurate readings and increased extravasation/edema risk. Use lower extremities for IV access and BP monitoring instead.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q6", type: "question", question: "What is the mnemonic for hypercalcemia of malignancy symptoms?", options: ["FAST HUGS", "Stones, Bones, Groans, and Psychiatric Overtones", "SBAR", "ABCDE"], correctIndex: 1, answer: "Hypercalcemia of malignancy presents with: Stones (renal calculi), Bones (bone pain, fractures from osteolysis), Groans (abdominal pain, constipation, nausea), and Psychiatric Overtones (confusion, lethargy, depression, progressing to coma). Occurs in 10-30% of advanced cancers.", category: "Oncology", difficulty: 1 },
  { id: "rn-oncem-q7", type: "question", question: "What is the first-line treatment for hypercalcemia of malignancy?", options: ["IV normal saline hydration at 200-500 mL/hr", "Oral calcium supplements", "Vitamin D", "Thiazide diuretics"], correctIndex: 0, answer: "Aggressive IV NS hydration (200-500 mL/hr) is the first step to promote renal calcium excretion through dilution and diuresis. Follow with IV bisphosphonate (zoledronic acid). Calcitonin provides rapid but short-lived effect as a bridge. Thiazide diuretics are CONTRAINDICATED (they increase calcium reabsorption).", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q8", type: "question", question: "In TLS, what is the cardiac complication of hyperkalemia and what medication stabilizes the myocardium?", options: ["Bradycardia; treat with atropine", "Cardiac arrhythmias (peaked T waves, V-fib); stabilize with calcium gluconate", "Heart failure; treat with digoxin", "Myocardial infarction; treat with aspirin"], correctIndex: 1, answer: "Hyperkalemia causes peaked T waves, widened QRS, and can progress to ventricular fibrillation and cardiac arrest. Calcium gluconate stabilizes cardiac myocyte membranes (does NOT lower K+). Then lower K+ with insulin/dextrose, kayexalate, or dialysis. Continuous cardiac monitoring is essential.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q9", type: "question", question: "What urine output target is maintained during TLS prevention with IV hydration?", options: [">0.5 mL/kg/hr", ">1 mL/kg/hr", ">2 mL/kg/hr", ">5 mL/kg/hr"], correctIndex: 2, answer: "During TLS prevention, maintain UOP >2 mL/kg/hr (or >100 mL/m2/hr in children) with aggressive IV hydration at 3 L/m2/day. This high urine output helps flush uric acid and phosphate crystals from the kidneys, preventing crystal nephropathy and acute kidney injury.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q10", type: "question", question: "What is Pemberton sign in SVC syndrome?", options: ["Facial pallor with arm elevation", "Facial plethora (redness and congestion) when arms are raised above the head", "Neck stiffness", "Arm pain with elevation"], correctIndex: 1, answer: "Pemberton sign is worsening facial plethora, cyanosis, and JVD when the patient raises both arms above the head. This maneuver further compresses the already obstructed SVC, worsening venous congestion in the head and neck. It is a physical exam finding that supports the diagnosis of SVC syndrome.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q11", type: "question", question: "How long does it take zoledronic acid to reach peak effect in hypercalcemia?", options: ["1-2 hours", "4-7 days", "2-3 weeks", "Immediately"], correctIndex: 1, answer: "Zoledronic acid (IV bisphosphonate) has an onset of 2-4 days and peak effect at 4-7 days. Because of this delay, calcitonin (onset 4-6 hours) is used as a bridge for acute symptomatic hypercalcemia. Aggressive hydration begins immediately while waiting for bisphosphonate effect.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q12", type: "question", question: "What cancers most commonly cause spinal cord compression through bone metastasis?", options: ["Brain tumors", "Breast, lung, prostate, and multiple myeloma", "Skin cancers", "Gastrointestinal cancers"], correctIndex: 1, answer: "Breast, lung, and prostate cancers are the most common causes of spinal cord compression because they frequently metastasize to bone. Multiple myeloma and renal cell carcinoma are also common causes. The thoracic spine is the most frequently affected location.", category: "Oncology", difficulty: 1 },
  { id: "rn-oncem-q13", type: "question", question: "What is the role of rasburicase in TLS management?", options: ["It lowers potassium", "It converts uric acid to allantoin (highly soluble and easily excreted), rapidly reducing uric acid levels", "It increases calcium levels", "It prevents hyperphosphatemia"], correctIndex: 1, answer: "Rasburicase (recombinant urate oxidase) rapidly converts existing uric acid to allantoin, which is 5-10x more soluble than uric acid. It works within 4 hours, unlike allopurinol which prevents NEW uric acid formation but does not break down existing uric acid. Blood samples must be kept on ice (rasburicase continues working ex vivo).", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q14", type: "question", question: "A patient with DIC has simultaneous bleeding from IV sites and purple discoloration of fingers. What laboratory findings are expected?", options: ["Normal coagulation studies", "Prolonged PT/PTT, low fibrinogen, elevated D-dimer, thrombocytopenia", "Elevated fibrinogen, normal platelets", "Prolonged PT only"], correctIndex: 1, answer: "DIC shows consumptive coagulopathy: coagulation factors and platelets are consumed in widespread microvascular thrombosis (prolonged PT/PTT, low platelets). Fibrinolysis is activated (elevated D-dimer, low fibrinogen). The paradox is simultaneous bleeding AND clotting. Treatment is addressing the underlying cause.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q15", type: "question", question: "What IV fluid should be administered to patients at risk for TLS and why?", options: ["D5W", "Lactated Ringer's", "Isotonic saline (0.9% NS) — to promote uric acid excretion without adding potassium (LR contains K+)", "Dextran"], correctIndex: 2, answer: "NS is preferred over LR for TLS patients because LR contains potassium (4 mEq/L), which would worsen hyperkalemia. Aggressive NS hydration at 3 L/m2/day promotes renal uric acid and phosphate excretion. Avoid potassium-containing fluids and limit phosphate intake.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q16", type: "question", question: "What type of cancer most commonly causes SVC syndrome?", options: ["Breast cancer", "Lung cancer (especially small cell) and lymphoma", "Colorectal cancer", "Melanoma"], correctIndex: 1, answer: "Lung cancer (particularly small cell lung cancer) and lymphoma are the most common causes of SVC syndrome because they arise in or near the mediastinum. The SVC is a thin-walled, low-pressure vessel easily compressed by adjacent tumors. Central venous catheter-related thrombosis is an increasing non-malignant cause.", category: "Oncology", difficulty: 1 },
  { id: "rn-oncem-q17", type: "question", question: "What nursing assessment should be performed every 2-4 hours for a patient with suspected spinal cord compression?", options: ["Skin assessment", "Detailed neurological exam: motor strength, sensation, reflexes, bladder function", "Lung auscultation", "Cardiac monitoring"], correctIndex: 1, answer: "Serial neurological assessments (motor strength grading, sensory level, deep tendon reflexes, bladder function including post-void residual) should be performed every 2-4 hours and documented meticulously. Deterioration from baseline triggers emergency intervention. Baseline documentation is essential.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q18", type: "question", question: "Which cancer mechanism causes hypercalcemia through PTHrP secretion?", options: ["Small cell lung cancer", "Squamous cell carcinomas (lung, head/neck)", "Lymphoma", "Colorectal cancer"], correctIndex: 1, answer: "Squamous cell carcinomas (lung, head/neck, esophageal) secrete PTHrP (parathyroid hormone-related protein), which mimics PTH action: increasing bone resorption and renal calcium reabsorption. This humoral hypercalcemia of malignancy is the most common mechanism, accounting for 80% of cancer-related hypercalcemia.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q19", type: "question", question: "A patient with TLS has peaked T waves on ECG. After administering calcium gluconate, what is the next intervention?", options: ["Administer more calcium gluconate", "Regular insulin 10 units IV with D50W to shift potassium intracellularly", "Oral potassium supplements", "Discharge the patient"], correctIndex: 1, answer: "After calcium gluconate (stabilizes myocardium but does NOT lower K+), the next step is insulin (10 units regular IV) with D50W (to prevent hypoglycemia). Insulin drives potassium into cells, temporarily lowering serum K+ within 15-30 minutes. Kayexalate and/or dialysis provide definitive potassium removal.", category: "Oncology", difficulty: 3 },
  { id: "rn-oncem-q20", type: "question", question: "What position should the nurse maintain for a patient with SVC syndrome?", options: ["Supine flat", "Trendelenburg", "HOB elevated >45 degrees", "Prone"], correctIndex: 2, answer: "Elevate HOB >45 degrees to promote venous drainage from the head and upper body through collateral pathways. Supine or Trendelenburg positions worsen facial edema, JVD, and dyspnea by impeding venous return. Monitor for signs of airway compromise and cerebral edema.", category: "Oncology", difficulty: 1 },
  { id: "rn-oncem-q21", type: "question", question: "How frequently should electrolytes be monitored during the first 72 hours of TLS risk?", options: ["Once daily", "Every 12 hours", "Every 4-6 hours", "Only if symptoms develop"], correctIndex: 2, answer: "Electrolytes (potassium, phosphorus, calcium, uric acid) and renal function should be monitored every 4-6 hours for the first 72 hours after starting chemotherapy for high-risk TLS patients. Rapid changes can occur, and early detection allows timely intervention before life-threatening complications develop.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q22", type: "question", question: "What cardiac monitoring finding indicates life-threatening hyperkalemia in TLS?", options: ["Sinus tachycardia", "Peaked T waves progressing to widened QRS and sine wave pattern", "Atrial fibrillation", "First-degree AV block"], correctIndex: 1, answer: "Hyperkalemia ECG progression: peaked T waves (mild) → flattened P waves and prolonged PR (moderate) → widened QRS (severe) → sine wave pattern → ventricular fibrillation/asystole (critical). Any ECG changes with hyperkalemia require immediate treatment with calcium gluconate and potassium-lowering measures.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q23", type: "question", question: "What is the difference between allopurinol and rasburicase in TLS?", options: ["They work the same way", "Allopurinol PREVENTS new uric acid formation; rasburicase BREAKS DOWN existing uric acid", "Rasburicase prevents formation; allopurinol breaks down existing acid", "Neither affects uric acid"], correctIndex: 1, answer: "Allopurinol inhibits xanthine oxidase, preventing conversion of hypoxanthine to uric acid (preventive — takes days). Rasburicase enzymatically converts existing uric acid to allantoin (therapeutic — works within hours). Rasburicase is used for treatment of established TLS; allopurinol for prevention.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q24", type: "question", question: "What is the earliest sign of spinal cord compression that the nurse should assess for?", options: ["Paralysis", "Back pain (present in 95% of cases and may precede neurological deficits by weeks)", "Urinary incontinence", "Fecal incontinence"], correctIndex: 1, answer: "Back pain is the earliest and most common symptom (95% of cases), often preceding motor weakness by days to weeks. Pain is typically localized to the spine, worse at night and with Valsalva maneuver, and may have radicular (nerve root) distribution. Any new back pain in a cancer patient should raise suspicion.", category: "Oncology", difficulty: 2 },
  { id: "rn-oncem-q25", type: "question", question: "Calcitonin is used as a bridge therapy in hypercalcemia. What is its limitation?", options: ["It is very toxic", "Tachyphylaxis (diminishing effectiveness) occurs within 48-72 hours", "It takes weeks to work", "It only works for calcium levels >16 mg/dL"], correctIndex: 1, answer: "Calcitonin provides rapid calcium reduction (onset 4-6 hours) but tachyphylaxis develops within 48-72 hours, limiting its effectiveness to a bridge therapy. It works by inhibiting osteoclast-mediated bone resorption and increasing renal calcium excretion. IV bisphosphonates provide sustained long-term effect.", category: "Oncology", difficulty: 3 },

  // === NEUTROPENIC PRECAUTIONS (25 cards) ===
  { id: "rn-neut-q1", type: "question", question: "Calculate the ANC: WBC 2,100, segmented neutrophils 28%, bands 4%.", options: ["ANC = 672", "ANC = 588", "ANC = 840", "ANC = 462"], correctIndex: 0, answer: "ANC = WBC × (% segs + % bands) / 100 = 2,100 × (28 + 4) / 100 = 2,100 × 0.32 = 672. This indicates severe neutropenia (ANC <1000). Implement neutropenic precautions immediately.", category: "Oncology", difficulty: 2, clinicalPearl: "Always calculate ANC when reviewing CBC results in oncology patients — the WBC alone does not reveal neutropenia if the differential is not examined." },
  { id: "rn-neut-q2", type: "question", question: "Why may fever be the ONLY sign of infection in a neutropenic patient?", options: ["Neutropenic patients cannot have other symptoms", "Neutrophils are required to produce classic inflammatory signs (pus, erythema, swelling) — without them, the inflammatory response is absent", "Fever is always present in all infections", "The patient is immunocompromised and symptoms develop later"], correctIndex: 1, answer: "Classic signs of infection (pus, erythema, induration, swelling) require neutrophils to create the inflammatory response. Without adequate neutrophils, these signs are absent. Fever may be the only manifestation of a life-threatening infection, making prompt evaluation and treatment critical.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q3", type: "question", question: "A neutropenic patient develops a temperature of 38.4C. What is the MOST important nursing action?", options: ["Administer acetaminophen and recheck in 30 minutes", "Apply cooling blankets", "Draw blood cultures and notify provider for immediate empiric antibiotics", "Encourage oral fluids and rest"], correctIndex: 2, answer: "Febrile neutropenia is a medical emergency. Priority: draw at least 2 sets of blood cultures (from central line AND peripheral vein if applicable) and notify the provider for STAT empiric broad-spectrum antibiotic orders. Goal: antibiotics within 60 minutes. Do NOT administer antipyretics before cultures.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q4", type: "question", question: "When should filgrastim (G-CSF) be administered in relation to chemotherapy?", options: ["During the chemotherapy infusion", "24-72 hours AFTER chemotherapy completion", "24 hours before chemotherapy", "Only when ANC reaches zero"], correctIndex: 1, answer: "Filgrastim stimulates rapid neutrophil precursor proliferation in bone marrow. Giving it during or immediately with chemotherapy would result in those rapidly dividing precursors being destroyed by the cytotoxic agents. Wait 24-72 hours after the last chemotherapy dose.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q5", type: "question", question: "Why should rectal temperatures, suppositories, and enemas be avoided in neutropenic patients?", options: ["They cause fever", "Rectal mucosal disruption can introduce bacteria directly into the bloodstream", "They are inaccurate", "They cause diarrhea"], correctIndex: 1, answer: "The rectal mucosa is thin and richly vascular. Any disruption (thermometer, suppository, enema) creates a portal of entry for gut bacteria (especially gram-negatives) directly into the bloodstream of a patient who lacks neutrophils to fight infection. Use oral or axillary temperature measurement instead.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q6", type: "question", question: "What is the most common side effect of filgrastim?", options: ["Hepatotoxicity", "Bone pain (from bone marrow expansion)", "Renal failure", "Nausea and vomiting"], correctIndex: 1, answer: "Bone pain is the most common side effect of G-CSF (filgrastim, pegfilgrastim), occurring in 20-30% of patients. It results from rapid expansion of bone marrow as neutrophil production increases. Managed with acetaminophen, NSAIDs, or loratadine (which paradoxically helps bone pain).", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q7", type: "question", question: "What ANC threshold defines severe neutropenia?", options: ["<2000/mm3", "<1500/mm3", "<1000/mm3 (or <500 by some definitions)", "<100/mm3"], correctIndex: 2, answer: "ANC <1000/mm3 defines severe neutropenia with high infection risk. Many institutions use <500/mm3 as the threshold for severe neutropenia and <100/mm3 for profound neutropenia. Below 500, infection risk rises dramatically, and below 100, risk of life-threatening sepsis is very high.", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q8", type: "question", question: "What dietary restrictions apply during neutropenia?", options: ["Low-sodium diet", "No fresh fruits/vegetables, no raw meat, no unpasteurized dairy — all foods must be cooked", "Vegetarian diet only", "No dietary restrictions needed"], correctIndex: 1, answer: "The neutropenic diet eliminates foods that may harbor bacteria or fungi: no raw fruits/vegetables (unless washed and peeled), no raw meat/fish (sushi), no unpasteurized dairy or soft cheeses, no raw eggs. All foods should be well-cooked. This reduces oral intake of potential pathogens.", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q9", type: "question", question: "What is the first-line empiric antibiotic for febrile neutropenia?", options: ["Oral amoxicillin", "IV cefepime (or piperacillin-tazobactam or meropenem)", "Topical mupirocin", "IM gentamicin"], correctIndex: 1, answer: "Empiric monotherapy with an anti-pseudomonal beta-lactam is first-line: cefepime, piperacillin-tazobactam, or meropenem. These provide broad gram-negative coverage including Pseudomonas. Vancomycin is added only for specific indications (suspected catheter infection, skin/soft tissue infection, hemodynamic instability, or MRSA risk).", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q10", type: "question", question: "When should antifungal therapy be added in febrile neutropenia?", options: ["Immediately with first-line antibiotics", "If fever persists >4-7 days despite appropriate antibacterial therapy", "Only if blood cultures are positive for fungi", "Antifungals are never needed"], correctIndex: 1, answer: "Empiric antifungal therapy is added when fever persists after 4-7 days of appropriate antibacterial therapy. Prolonged neutropenia with persistent fever suggests invasive fungal infection (Aspergillus, Candida). Voriconazole is first-line for suspected aspergillosis; echinocandins (micafungin) for candidiasis.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q11", type: "question", question: "What is the single most important infection prevention measure in neutropenic patients?", options: ["Prophylactic antibiotics", "Strict hand hygiene", "HEPA filtration", "Protective gowning"], correctIndex: 1, answer: "Hand hygiene is the single most important measure for preventing infection in neutropenic patients. All healthcare workers, visitors, and the patient themselves must perform thorough hand hygiene before patient contact. It is more effective than any other single intervention.", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q12", type: "question", question: "Why should fresh flowers and plants be removed from a neutropenic patient's room?", options: ["They cause allergies", "They harbor Aspergillus and other fungal organisms in soil and water", "They interfere with oxygen delivery", "They have no therapeutic benefit"], correctIndex: 1, answer: "Fresh flowers and plants harbor Aspergillus mold spores (in soil, standing water, and on plant surfaces) and other environmental fungi. Neutropenic patients are highly susceptible to invasive aspergillosis, which carries high mortality. Remove all plants and ensure no standing water in the room.", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q13", type: "question", question: "What is the difference between filgrastim and pegfilgrastim?", options: ["They are entirely different drugs", "Pegfilgrastim is a long-acting form (PEGylated) requiring only one injection per chemotherapy cycle vs daily filgrastim", "Filgrastim is long-acting", "Pegfilgrastim is given daily"], correctIndex: 1, answer: "Pegfilgrastim has a polyethylene glycol (PEG) molecule attached to filgrastim, extending its half-life and allowing a single subcutaneous injection per chemotherapy cycle (vs daily injections for filgrastim). Both stimulate neutrophil production but pegfilgrastim is more convenient.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q14", type: "question", question: "A patient with ANC of 200 has RLQ abdominal pain, fever, and bloody diarrhea. What complication should the nurse suspect?", options: ["Appendicitis", "Typhlitis (neutropenic enterocolitis)", "Diverticulitis", "Ulcerative colitis flare"], correctIndex: 1, answer: "Typhlitis (neutropenic enterocolitis) is inflammation of the cecum and ascending colon in severely neutropenic patients. RLQ pain (cecum location), fever, and bloody diarrhea are the classic triad. CT shows cecal wall thickening. Management includes bowel rest, IV antibiotics, and surgery if perforation occurs.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q15", type: "question", question: "When can antibiotics be discontinued in febrile neutropenia?", options: ["After 24 hours of no fever", "When blood cultures are negative at 48 hours", "When ANC recovers to >500/mm3 AND the patient has been afebrile for 48 hours", "After completing a fixed 14-day course"], correctIndex: 2, answer: "Continue empiric antibiotics until ANC >500/mm3 and afebrile for at least 48 hours. Premature discontinuation risks breakthrough infection during ongoing neutropenia. Some protocols allow earlier discontinuation in low-risk patients with negative cultures and rapid clinical improvement.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q16", type: "question", question: "What percentage of febrile neutropenia risk triggers primary G-CSF prophylaxis?", options: [">5%", ">10%", ">20%", ">50%"], correctIndex: 2, answer: "NCCN/ASCO guidelines recommend primary G-CSF prophylaxis when the chemotherapy regimen has >20% risk of causing febrile neutropenia. For regimens with 10-20% risk, individual patient risk factors (age >65, comorbidities, prior febrile neutropenia) determine whether prophylaxis is added.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q17", type: "question", question: "What temperature monitoring schedule should the nurse implement for a neutropenic patient?", options: ["Once daily", "Every 8 hours", "Every 4 hours, and instruct the patient to report any fever immediately", "Only when the patient feels warm"], correctIndex: 2, answer: "Monitor temperature every 4 hours in neutropenic patients. Instruct the patient to report any sensation of fever, chills, or feeling unwell immediately — even between scheduled checks. Do NOT use antipyretics prophylactically as they mask fever, the potentially sole indicator of infection.", category: "Oncology", difficulty: 1 },
  { id: "rn-neut-q18", type: "question", question: "Why should pegfilgrastim NOT be used in acute myeloid leukemia (AML)?", options: ["It is ineffective in AML", "It can stimulate blast (leukemia) cell proliferation", "It causes severe bone pain in AML", "It is too expensive"], correctIndex: 1, answer: "G-CSF can stimulate proliferation of myeloid blast cells in AML, potentially worsening the leukemia. In AML, G-CSF use is carefully timed and limited to post-chemotherapy recovery when blasts are cleared. It should never be given when circulating blasts are present.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q19", type: "question", question: "What type of blood cultures should be drawn in febrile neutropenia?", options: ["One aerobic culture only", "At least 2 sets (aerobic and anaerobic) from different sites; draw from central line AND peripheral vein", "Fungal cultures only", "No cultures needed if antibiotics are started"], correctIndex: 1, answer: "Draw at least 2 sets of blood cultures (each set = 1 aerobic + 1 anaerobic bottle) from different sites. If the patient has a central line, draw one set from the line and one from a peripheral vein. This helps identify catheter-related bloodstream infections (differential time to positivity).", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q20", type: "question", question: "A patient with an ANC of 400 has a chest X-ray showing no infiltrates despite cough and fever. Why might the CXR appear normal?", options: ["The patient doesn't have pneumonia", "Without adequate neutrophils, the lung cannot mount an inflammatory infiltrate — CXR may be falsely negative", "The X-ray machine is malfunctioning", "Fever causes CXR artifacts"], correctIndex: 1, answer: "Neutrophils are required to produce the inflammatory infiltrate visible on CXR. In profound neutropenia, pulmonary infection may be present without visible infiltrate on CXR. CT may show subtle findings missed on CXR. Clinical suspicion should guide treatment regardless of imaging.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q21", type: "question", question: "What is the MASCC score used for?", options: ["Staging cancer", "Risk stratifying febrile neutropenia into low-risk and high-risk for selecting outpatient vs inpatient management", "Calculating chemotherapy doses", "Predicting cancer survival"], correctIndex: 1, answer: "The MASCC (Multinational Association for Supportive Care in Cancer) score risk-stratifies febrile neutropenia. Score >=21 = low risk (may be eligible for outpatient management with oral antibiotics). Score <21 = high risk (requires inpatient IV antibiotic therapy). Factors include disease burden, symptoms, vitals, and comorbidities.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q22", type: "question", question: "What oral assessment is critical in neutropenic patients and why?", options: ["Dental examination", "Oral mucosa assessment — mucositis provides entry for bacteria into the bloodstream", "Throat culture", "Fluoride application"], correctIndex: 1, answer: "Chemotherapy-induced oral mucositis (mucosal breakdown) is common and creates a direct portal of entry for oral bacteria into the bloodstream. Assess oral mucosa every shift for erythema, ulceration, pain, and white patches (candidiasis). Maintain gentle oral hygiene with soft toothbrush and salt-water rinses.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q23", type: "question", question: "When should vancomycin be added to empiric febrile neutropenia therapy?", options: ["Always — it should be part of initial therapy", "Only for specific indications: suspected catheter infection, skin/soft tissue infection, hemodynamic instability, or MRSA risk", "Never — it is contraindicated", "Only after 7 days of fever"], correctIndex: 1, answer: "Vancomycin is NOT part of routine empiric therapy. Add it for specific indications: suspected central line infection, skin/soft tissue infection, hypotension/shock, known MRSA colonization, or blood cultures growing gram-positive cocci pending identification. Inappropriate vancomycin use promotes VRE.", category: "Oncology", difficulty: 2 },
  { id: "rn-neut-q24", type: "question", question: "What screening tests should be ordered when prolonged neutropenia raises concern for invasive fungal infection?", options: ["Only blood cultures", "Galactomannan and beta-D-glucan serum assays", "Urinalysis only", "Stool culture"], correctIndex: 1, answer: "Serum galactomannan (specific for Aspergillus) and beta-D-glucan (broad fungal marker) are non-invasive biomarkers for invasive fungal infection. They help guide early antifungal therapy in patients with prolonged neutropenia (>7 days) and persistent fever. CT chest may show halo sign or air crescent sign in pulmonary aspergillosis.", category: "Oncology", difficulty: 3 },
  { id: "rn-neut-q25", type: "question", question: "What is the 60-minute rule in febrile neutropenia?", options: ["The patient must be evaluated within 60 minutes of arrival", "Empiric broad-spectrum antibiotics must be administered within 60 minutes of fever recognition — delays increase mortality", "Blood cultures must return within 60 minutes", "The fever must resolve within 60 minutes"], correctIndex: 1, answer: "The 60-minute rule states that empiric broad-spectrum antibiotics must be administered within 60 minutes of recognizing febrile neutropenia. Every hour of delay in antibiotic administration increases mortality. This is why rapid recognition, blood culture collection, and antibiotic initiation are critical.", category: "Oncology", difficulty: 1 },

  // === PEDIATRIC RESPIRATORY DISTRESS (25 cards) ===
  { id: "rn-pedresp-q1", type: "question", question: "A 2-year-old presents with a barky cough, inspiratory stridor, and hoarseness that developed gradually. What is the most likely diagnosis?", options: ["Epiglottitis", "Croup (laryngotracheobronchitis)", "Bronchiolitis", "Asthma"], correctIndex: 1, answer: "Barky (seal-like) cough, inspiratory stridor, and hoarseness with gradual onset in a toddler are classic for croup. Croup is caused primarily by parainfluenza virus, affecting the subglottic area. It peaks in fall/winter and is most common in children 6 months to 3 years.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q2", type: "question", question: "A child with suspected epiglottitis is drooling, sitting in tripod position, and has a high fever. What should the nurse NEVER do?", options: ["Call the provider", "Keep emergency airway equipment at bedside", "Examine the throat with a tongue depressor", "Allow the parent to hold the child"], correctIndex: 2, answer: "NEVER examine the throat of a child with suspected epiglottitis. A tongue depressor or laryngoscopy can trigger laryngospasm and complete airway obstruction. Keep the child calm, allow position of comfort (tripod), and have emergency intubation equipment and tracheostomy tray at bedside.", category: "Pediatrics", difficulty: 2, clinicalPearl: "The 4 D's of epiglottitis: Dysphagia, Drooling, Distress, Dysphonia (muffled voice). NO spontaneous cough (unlike croup)." },
  { id: "rn-pedresp-q3", type: "question", question: "Why does 1 mm of airway edema have a much greater impact on a child than an adult?", options: ["Children breathe faster", "Poiseuille's law: airway resistance is inversely proportional to the 4th power of the radius — 1 mm edema reduces a 4 mm pediatric airway by 75%", "Children have weaker respiratory muscles", "Adults don't get airway edema"], correctIndex: 1, answer: "Per Poiseuille's law, resistance ∝ 1/r⁴. In a 4 mm pediatric airway, 1 mm of edema reduces the radius to 2 mm, reducing cross-sectional area by 75%. In an 8 mm adult airway, the same 1 mm reduces it to 6 mm (only 19% reduction). This is why children deteriorate rapidly with airway swelling.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedresp-q4", type: "question", question: "What X-ray finding is associated with croup?", options: ["Thumbprint sign", "Steeple sign (subglottic narrowing on AP neck X-ray)", "Ground-glass opacity", "Air bronchograms"], correctIndex: 1, answer: "The steeple sign on AP neck X-ray shows subglottic narrowing resembling a church steeple. It represents mucosal edema narrowing the normally shouldered subglottic space. The thumbprint sign is seen in epiglottitis (swollen epiglottis on lateral neck X-ray).", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q5", type: "question", question: "What is the standard corticosteroid dose for croup?", options: ["Methylprednisolone 1 mg/kg IV daily for 5 days", "Dexamethasone 0.6 mg/kg PO/IM single dose (max 10 mg)", "Prednisone 2 mg/kg PO daily for 10 days", "Budesonide 0.5 mg nebulized BID for 3 days"], correctIndex: 1, answer: "Single-dose dexamethasone 0.6 mg/kg (PO or IM, max 10 mg) is the standard treatment for croup. Onset is 6 hours with duration of 24-36 hours. A single dose is effective even for mild croup and reduces the need for return visits. It works by reducing subglottic mucosal edema.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q6", type: "question", question: "After nebulized racemic epinephrine for croup, how long must the child be observed?", options: ["30 minutes", "1 hour", "2-4 hours for possible rebound worsening", "No observation needed"], correctIndex: 2, answer: "Children must be observed for 2-4 hours after racemic epinephrine for rebound stridor. The vasoconstrictive effect wears off in 2-4 hours, and symptoms may return or worsen. Rebound edema can occur as the medication's mucosal vasoconstriction resolves. The child should not be discharged during this window.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q7", type: "question", question: "What is the most common cause of bronchiolitis in infants?", options: ["Parainfluenza virus", "Influenza", "Respiratory syncytial virus (RSV)", "Adenovirus"], correctIndex: 2, answer: "RSV is the most common cause of bronchiolitis, accounting for 50-80% of cases. It predominantly affects infants <1 year, peaking at 2-6 months. RSV causes bronchiolar edema, mucus plugging, and air trapping. Peak season is November through March.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q8", type: "question", question: "Are bronchodilators (albuterol) recommended for RSV bronchiolitis by AAP guidelines?", options: ["Yes — albuterol is first-line", "No — AAP guidelines do not recommend routine bronchodilator use in bronchiolitis", "Only for children >2 years", "Only in combination with steroids"], correctIndex: 1, answer: "AAP guidelines specifically recommend AGAINST routine use of bronchodilators in bronchiolitis. Multiple studies show no benefit, and they may cause adverse effects (tachycardia, tremor) in infants. Supportive care (nasal suctioning, oxygen, hydration) is the mainstay. A trial dose may be considered for severe cases with reassessment.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q9", type: "question", question: "What distinguishes epiglottitis from croup in terms of onset?", options: ["Both have gradual onset", "Epiglottitis has ABRUPT onset with rapid deterioration; croup has GRADUAL onset over 1-2 days", "Croup has abrupt onset; epiglottitis is gradual", "Neither has a predictable onset pattern"], correctIndex: 1, answer: "Epiglottitis develops abruptly — a previously well child becomes acutely ill with high fever (>39C), severe sore throat, drooling, and respiratory distress over hours. Croup develops gradually over 1-2 days with worsening barky cough, stridor, and hoarseness, preceded by URI symptoms.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q10", type: "question", question: "What isolation precaution is required for an infant with RSV bronchiolitis?", options: ["Airborne precautions", "Droplet precautions", "Contact precautions (gown and gloves)", "No isolation needed"], correctIndex: 2, answer: "RSV is transmitted primarily through contact with infected secretions (hand contamination, fomites). Contact precautions (gown and gloves) are required. RSV survives on hard surfaces for hours. Strict hand hygiene is critical. Cohorting RSV-positive patients and using dedicated equipment prevents nosocomial spread.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q11", type: "question", question: "What medication provides RSV prophylaxis for high-risk infants?", options: ["RSV vaccine", "Palivizumab (Synagis) — monthly IM injection during RSV season", "Ribavirin prophylaxis", "Amantadine"], correctIndex: 1, answer: "Palivizumab is a monoclonal antibody that binds RSV F-protein, preventing viral entry. Given monthly IM during RSV season (November-March) to eligible high-risk infants (premature <29 weeks, CHD, chronic lung disease). It is PROPHYLAXIS only — does not treat active RSV infection.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q12", type: "question", question: "What is the priority nursing intervention for a 4-month-old with RSV, SpO2 of 88%, and nasal flaring?", options: ["Administer albuterol nebulizer", "Apply supplemental oxygen to maintain SpO2 >90%", "Administer IV corticosteroids", "Perform deep suctioning"], correctIndex: 1, answer: "Supplemental oxygen to maintain SpO2 >90% is the priority. Gentle nasal suctioning helps clear secretions that obstruct the nasal airway (infants are obligate nose breathers). Albuterol and corticosteroids are NOT recommended by AAP for routine bronchiolitis management.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q13", type: "question", question: "What sign indicates impending respiratory failure in a child with any respiratory condition?", options: ["Mild tachypnea", "Increased work of breathing with good air movement", "Decreasing respiratory effort (exhaustion), altered consciousness, and bradycardia", "Nasal flaring alone"], correctIndex: 2, answer: "Decreasing respiratory effort in a child who was previously working hard to breathe is ominous — it indicates exhaustion and impending respiratory failure. Combined with altered LOC and bradycardia (late decompensation), this requires immediate intervention (bag-valve-mask ventilation, intubation).", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q14", type: "question", question: "What feeding modification is important for an infant with bronchiolitis?", options: ["Large-volume feeds every 6 hours", "Small, frequent feeds with nasal suctioning before feeding", "NPO for the entire illness", "Add cereal to formula to thicken feeds"], correctIndex: 1, answer: "Infants with bronchiolitis have increased work of breathing that makes feeding difficult. Suction the nose before feeds (infants are obligate nose breathers). Provide small, frequent feeds to reduce aspiration risk and energy expenditure. IV fluids or NG feeding may be needed if the infant cannot feed safely.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q15", type: "question", question: "Why is the tripod position significant in a child with epiglottitis?", options: ["It is a comfortable sleeping position", "The child instinctively positions to maximize airway opening — DO NOT force the child to lie down", "It indicates abdominal pain", "It is a sign of cardiac disease"], correctIndex: 1, answer: "The tripod position (sitting upright, leaning forward with arms braced, chin thrust forward, mouth open) is the child's instinctive posture to maximize airway opening by lifting the swollen epiglottis off the glottis. Forcing the child to lie down can cause the swollen epiglottis to completely obstruct the airway.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q16", type: "question", question: "What breath sounds are typical of bronchiolitis?", options: ["Stridor", "Wheezing and fine crackles (rales)", "Rhonchi only", "Absent breath sounds"], correctIndex: 1, answer: "Bronchiolitis produces expiratory wheezing (from bronchiolar narrowing) and fine crackles/rales (from fluid in small airways). This differentiates it from croup (inspiratory stridor from upper airway narrowing). Tachypnea and subcostal/intercostal retractions are also present.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q17", type: "question", question: "At what SpO2 level should supplemental oxygen be initiated in bronchiolitis?", options: ["<98%", "<95%", "<92%", "<85%"], correctIndex: 2, answer: "AAP guidelines recommend initiating supplemental oxygen when SpO2 falls below 90% (some institutions use 92% as the threshold). Continuous pulse oximetry is indicated for hospitalized infants. The goal is to maintain SpO2 >90%. Avoid unnecessary oxygen supplementation that may prolong hospitalization.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q18", type: "question", question: "What complication can occur in premature infants with RSV bronchiolitis that may not occur in older children?", options: ["Pneumothorax", "Apnea (cessation of breathing)", "Cardiac tamponade", "Meningitis"], correctIndex: 1, answer: "Premature infants (<35 weeks) with RSV are at risk for apnea (cessation of breathing >=20 seconds or any pause associated with cyanosis/bradycardia). The immature respiratory center is particularly susceptible. These infants require continuous cardiorespiratory monitoring and may need respiratory support.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedresp-q19", type: "question", question: "What caused the dramatic decrease in H. influenzae type b epiglottitis?", options: ["Improved sanitation", "Hib vaccine introduction", "Natural viral mutation", "Antibiotic overuse"], correctIndex: 1, answer: "The introduction of the Hib vaccine dramatically reduced epiglottitis caused by H. influenzae type b. Before vaccination, Hib was the primary cause of epiglottitis in children. Now, other organisms (S. aureus, Streptococcus species, non-typeable H. influenzae) cause most cases in vaccinated populations.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q20", type: "question", question: "What is the role of hypertonic saline (3%) nebulization in bronchiolitis?", options: ["It treats the viral infection", "It may improve mucociliary clearance by drawing water into the airways and reducing mucus viscosity", "It is the primary bronchodilator for RSV", "It prevents secondary bacterial infection"], correctIndex: 1, answer: "Hypertonic saline (3%) nebulization draws water into the airway lumen, rehydrating airway surface liquid and improving mucociliary clearance. Evidence supports its use in hospitalized infants with bronchiolitis to reduce length of stay. It is not routinely recommended in the emergency department setting.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q21", type: "question", question: "A child with croup has stridor at rest. What severity level does this indicate?", options: ["Mild croup", "Moderate-severe croup requiring racemic epinephrine", "Normal for croup", "It indicates the child is improving"], correctIndex: 1, answer: "Stridor at rest indicates moderate-severe croup requiring nebulized racemic epinephrine and dexamethasone. Mild croup has stridor only with agitation or crying. Severe croup has stridor at rest with significant retractions, decreased air entry, and altered consciousness.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q22", type: "question", question: "What is the best way to keep a child with croup calm to prevent worsening of symptoms?", options: ["Restrain the child for procedures", "Allow the child to sit in the parent's lap in an upright position", "Separate the child from parents for assessment", "Place the child supine with restraints"], correctIndex: 1, answer: "Agitation and crying worsen airway obstruction in croup by increasing turbulent airflow through the narrowed subglottic space. Allow the child to remain in the parent's lap in an upright position. Minimize invasive procedures. Blow-by oxygen is preferred over face masks to reduce distress.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q23", type: "question", question: "What assessment finding differentiates stridor from wheezing?", options: ["Stridor occurs during expiration; wheezing during inspiration", "Stridor is an inspiratory upper airway sound (croup, epiglottitis); wheezing is an expiratory lower airway sound (bronchiolitis, asthma)", "They are the same sound", "Stridor is louder"], correctIndex: 1, answer: "Stridor is a high-pitched sound heard primarily during INSPIRATION, caused by turbulent airflow through a narrowed upper airway (larynx, trachea). Wheezing is heard primarily during EXPIRATION, caused by narrowed lower airways (bronchioles). This differentiation helps localize the pathology.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedresp-q24", type: "question", question: "What antibiotics are used to treat epiglottitis?", options: ["Amoxicillin oral", "IV ceftriaxone or ampicillin-sulbactam (after airway is secured)", "Azithromycin oral", "No antibiotics needed — it is viral"], correctIndex: 1, answer: "Epiglottitis is bacterial (unlike croup which is viral). IV antibiotics (ceftriaxone or ampicillin-sulbactam) provide coverage for the common causative organisms (H. influenzae, S. pneumoniae, S. aureus, Group A Strep). Antibiotics are started AFTER the airway is secured — airway management is always the first priority.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedresp-q25", type: "question", question: "What should the nurse assess to differentiate respiratory distress from respiratory failure in a child?", options: ["Temperature", "The child's activity level only", "Work of breathing combined with effectiveness of gas exchange (mental status, heart rate, SpO2, skin color)", "Blood pressure alone"], correctIndex: 2, answer: "Respiratory distress = increased work of breathing with maintained gas exchange (tachypnea, retractions, nasal flaring but normal SpO2 and mental status). Respiratory failure = inadequate gas exchange despite increased effort (altered mental status, bradycardia, cyanosis, decreasing SpO2, exhaustion). Failure requires immediate intervention.", category: "Pediatrics", difficulty: 2 },

  // === PEDIATRIC FLUIDS (25 cards) ===
  { id: "rn-pedfl-q1", type: "question", question: "Using the 4-2-1 rule, calculate the hourly maintenance fluid rate for a 22 kg child.", options: ["55 mL/hr", "62 mL/hr", "70 mL/hr", "48 mL/hr"], correctIndex: 1, answer: "4-2-1 rule: 4 mL/kg/hr for first 10 kg = 40 + 2 mL/kg/hr for next 10 kg = 20 + 1 mL/kg/hr for remaining 2 kg = 2. Total = 40 + 20 + 2 = 62 mL/hr.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q2", type: "question", question: "A 10 kg infant has lost 8% of body weight from dehydration. How many mL of fluid deficit does this represent?", options: ["400 mL", "600 mL", "800 mL", "1000 mL"], correctIndex: 2, answer: "Fluid deficit = % dehydration × weight (kg) × 10. So: 8% × 10 kg × 10 = 800 mL deficit. This moderate dehydration (6-9%) requires IV rehydration if oral is not tolerated. Replace over 24 hours for isotonic dehydration.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q3", type: "question", question: "What is the most accurate method to assess hydration status in a child?", options: ["Blood pressure", "Accurate body weight compared to a recent known weight", "Skin turgor alone", "Urine color"], correctIndex: 1, answer: "Accurate body weight is the most reliable measure of fluid status in children. 1 kg of weight loss = 1 L of fluid loss. Compare current weight to the most recent known weight. Weigh at the same time, on the same scale, with the same amount of clothing each time.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q4", type: "question", question: "An infant's anterior fontanel is sunken. What does this indicate?", options: ["Normal finding", "Dehydration", "Increased intracranial pressure", "Overhydration"], correctIndex: 1, answer: "A sunken anterior fontanel indicates dehydration in infants. The normal fontanel is flat and soft. A bulging fontanel indicates increased ICP or fluid overload. The anterior fontanel normally closes by 12-18 months. Fontanel assessment is a unique pediatric advantage for assessing fluid status.", category: "Pediatrics", difficulty: 1, clinicalPearl: "Sunken fontanel + absent tears + decreased skin turgor = moderate dehydration (6-9% in infants)." },
  { id: "rn-pedfl-q5", type: "question", question: "Why should IV potassium NEVER be added to fluids until the child has urinated?", options: ["It causes nausea", "Kidneys are the primary excretory route — without urine output, potassium cannot be eliminated, causing fatal hyperkalemia", "It crystallizes in the tubing", "It is not necessary for children"], correctIndex: 1, answer: "Potassium is primarily excreted by the kidneys. If the child has not urinated (potential renal impairment or severe prerenal azotemia from dehydration), adding IV potassium can cause fatal hyperkalemia. Always confirm urine output before adding KCl to maintenance fluids.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q6", type: "question", question: "What is the standard IV bolus for pediatric dehydration?", options: ["10 mL/kg NS over 1 hour", "20 mL/kg NS or LR over 20-30 minutes", "50 mL/kg NS over 10 minutes", "5 mL/kg D5W over 4 hours"], correctIndex: 1, answer: "Standard pediatric fluid bolus: 20 mL/kg of isotonic crystalloid (NS or LR) over 20-30 minutes. May repeat up to 3 times (60 mL/kg total) based on clinical response. Reassess after each bolus: HR, capillary refill, urine output, mental status. This differs from adult protocols.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q7", type: "question", question: "Why must hypertonic dehydration (Na >150 mEq/L) be corrected SLOWLY?", options: ["Rapid correction causes cardiac arrest", "Rapid correction causes cerebral edema — brain cells have accumulated idiogenic osmoles that draw water in when sodium is lowered quickly", "Slow correction is not necessary", "Rapid correction causes renal failure"], correctIndex: 1, answer: "In hypertonic dehydration, brain cells generate idiogenic osmoles to maintain volume. Rapid lowering of serum sodium causes water to rush into brain cells (osmotic gradient), causing cerebral edema, seizures, and potentially death. Correct no faster than 0.5 mEq/L/hr or 10-12 mEq/L/24 hours.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedfl-q8", type: "question", question: "What is the most common cause of dehydration in children?", options: ["Diabetes mellitus", "Renal disease", "Gastroenteritis (vomiting and diarrhea)", "Burns"], correctIndex: 2, answer: "Acute gastroenteritis with vomiting and diarrhea is by far the most common cause of dehydration in children worldwide. Viral gastroenteritis (rotavirus, norovirus) accounts for the majority of cases. Young children are particularly vulnerable due to higher fluid turnover relative to body weight.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q9", type: "question", question: "What is the minimum number of wet diapers per day that indicates adequate hydration in an infant?", options: ["2-3", "4-5", "6-8", "10-12"], correctIndex: 2, answer: "A well-hydrated infant should produce 6-8 wet diapers per day (approximately 1 mL/kg/hr of urine output). Fewer than 6 wet diapers in 24 hours suggests dehydration. Weigh diapers for accurate measurement (1 gram = 1 mL). Oliguria in an infant is <1 mL/kg/hr.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q10", type: "question", question: "Why are sports drinks (Gatorade) and fruit juices NOT recommended for pediatric oral rehydration?", options: ["They are too expensive", "Their high sugar content and osmolality worsen diarrhea through osmotic water draw into the intestine", "They taste bad to children", "They contain too much protein"], correctIndex: 1, answer: "Sports drinks and fruit juices have high sugar content and osmolality that draws water into the intestinal lumen by osmosis, worsening diarrhea. Commercial ORS (Pedialyte) has an optimal sodium-glucose ratio that maximizes intestinal water absorption via the SGLT1 sodium-glucose cotransporter.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q11", type: "question", question: "Using Holliday-Segar, calculate the daily maintenance fluid for a 28 kg child.", options: ["1560 mL/day", "1660 mL/day", "1760 mL/day", "1860 mL/day"], correctIndex: 1, answer: "Holliday-Segar: 100 mL/kg for first 10 kg = 1000 + 50 mL/kg for next 10 kg = 500 + 20 mL/kg for remaining 8 kg = 160. Total = 1000 + 500 + 160 = 1660 mL/day.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q12", type: "question", question: "Why must all pediatric IV fluids be administered via infusion pump?", options: ["Hospital policy only", "Gravity or free-flow infusion can cause rapid, fatal fluid overload in small children due to their smaller blood volume", "Infusion pumps are more accurate", "To reduce nursing workload"], correctIndex: 1, answer: "Pediatric patients have smaller circulating blood volumes, making them extremely vulnerable to fluid overload. Even small errors in fluid delivery can cause pulmonary edema, heart failure, or hyponatremia. Infusion pumps ensure precise delivery of prescribed volumes and prevent free-flow accidents.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q13", type: "question", question: "What clinical sign helps distinguish moderate from severe dehydration in an infant?", options: ["Slightly dry lips vs very dry lips", "Decreased tears vs absent tears with altered mental status", "Mild thirst vs moderate thirst", "Normal HR vs slightly elevated HR"], correctIndex: 1, answer: "Moderate dehydration: decreased tears, sunken eyes, decreased skin turgor, tachycardia, dry mucous membranes. Severe dehydration: ABSENT tears, markedly sunken eyes, tenting skin, tachycardia with weak/thready pulse, altered mental status (lethargy), hypotension, and very decreased/absent urine output.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q14", type: "question", question: "How should oral rehydration solution (ORS) be administered to a vomiting child?", options: ["Large volumes rapidly via cup", "Small frequent amounts: 5-10 mL every 5-10 minutes using syringe, spoon, or medicine cup", "Via NG tube only", "Wait until vomiting stops completely before giving any fluids"], correctIndex: 1, answer: "Give ORS in small, frequent volumes (5-10 mL every 5-10 minutes) using a syringe, spoon, or medicine cup. Small volumes are less likely to trigger vomiting than large boluses. Most children can be rehydrated orally even with mild-moderate vomiting using this technique.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q15", type: "question", question: "What is the maximum potassium concentration allowed in a peripheral IV for pediatric patients?", options: ["10 mEq/L", "20 mEq/L", "40 mEq/L", "60 mEq/L"], correctIndex: 2, answer: "Maximum peripheral IV potassium concentration is typically 40 mEq/L. Higher concentrations (>40 mEq/L) require central venous access due to risk of phlebitis and tissue damage. Maximum infusion rate is 0.5 mEq/kg/hr. Always use an infusion pump for potassium administration.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedfl-q16", type: "question", question: "A child with DKA is brought to the ED severely dehydrated. Why should fluid resuscitation be more conservative than typical dehydration?", options: ["DKA children are not dehydrated", "Aggressive fluid resuscitation in pediatric DKA increases risk of cerebral edema — the leading cause of DKA death in children", "IV fluids are contraindicated in DKA", "Only insulin is needed"], correctIndex: 1, answer: "Cerebral edema is the leading cause of DKA-related death in children. Overly aggressive fluid resuscitation (especially with hypotonic fluids) can worsen cerebral edema through osmotic shifts. Use 10-20 mL/kg NS bolus initially, then 1.5× maintenance over 24-48 hours. Avoid rapid correction of sodium.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedfl-q17", type: "question", question: "What capillary refill time indicates poor perfusion in a child?", options: ["<2 seconds", ">2 seconds (normal <2 seconds)", "<4 seconds", ">5 seconds only"], correctIndex: 1, answer: "Normal capillary refill is <2 seconds. A capillary refill time >2 seconds indicates poor peripheral perfusion from dehydration, shock, or hypothermia. Assess on a fingertip or sternum (not on cool extremities as ambient temperature affects results). It is an important quick bedside assessment.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q18", type: "question", question: "What electrolyte abnormality is characteristic of pyloric stenosis?", options: ["Hyperkalemia and metabolic acidosis", "Hypochloremic, hypokalemic metabolic alkalosis", "Hypernatremia", "Hypercalcemia"], correctIndex: 1, answer: "Pyloric stenosis causes projectile, non-bilious vomiting of gastric contents, leading to loss of HCl (hydrogen and chloride). The resulting hypochloremic metabolic alkalosis is accompanied by hypokalemia (kidneys excrete K+ to retain H+). This classic electrolyte pattern is a USMLE/NCLEX favorite.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedfl-q19", type: "question", question: "How does fever increase fluid requirements in children?", options: ["It doesn't affect fluid needs", "Each degree Celsius above 37C increases insensible losses by approximately 12%", "Fever decreases fluid requirements", "Only if fever exceeds 40C"], correctIndex: 1, answer: "Fever increases metabolic rate and insensible fluid losses (through increased respiration and sweating). For each degree Celsius above 37C, insensible losses increase by approximately 12%. Maintenance fluid calculations should be adjusted upward for febrile children.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q20", type: "question", question: "What is the significance of an overhydrated infant with a bulging fontanel?", options: ["Normal variant", "Indicates fluid overload or increased intracranial pressure — requires immediate evaluation", "Sign of hunger", "Indicates dehydration"], correctIndex: 1, answer: "A bulging (tense, full) fontanel can indicate fluid overload (iatrogenic from excessive IV fluids) or increased intracranial pressure (meningitis, hydrocephalus). In the context of IV fluid administration, it is a critical sign of overhydration requiring immediate rate reduction and medical evaluation.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q21", type: "question", question: "What percentage of body weight is water in a newborn?", options: ["40-50%", "55-60%", "75-80%", "90-95%"], correctIndex: 2, answer: "Newborns have 75-80% total body water (TBW) compared to 60% in adults. This higher proportion, combined with a greater body surface area-to-weight ratio, higher metabolic rate, and immature renal concentrating ability, makes infants more susceptible to dehydration and fluid imbalances.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q22", type: "question", question: "How much ORS should be given after each diarrheal stool for home management?", options: ["5 mL/kg", "10 mL/kg after each loose stool", "50 mL regardless of child's weight", "No additional fluids between meals"], correctIndex: 1, answer: "For home management of mild dehydration, give 10 mL/kg of ORS after each loose stool to replace ongoing losses. This is in addition to maintenance fluid needs. Continue age-appropriate diet (including breastfeeding). Return to medical care if symptoms worsen or the child cannot keep fluids down.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q23", type: "question", question: "What is the most common type of dehydration in children?", options: ["Hypertonic dehydration", "Hypotonic dehydration", "Isotonic dehydration (80% of cases)", "Metabolic dehydration"], correctIndex: 2, answer: "Isotonic dehydration (proportional loss of water and sodium, serum Na 130-150 mEq/L) accounts for approximately 80% of pediatric dehydration cases. It is the most straightforward to manage because there is no osmotic gradient driving fluid shifts between compartments.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedfl-q24", type: "question", question: "A child weighing 18 kg needs maintenance fluids using Holliday-Segar. What is the daily volume?", options: ["1200 mL/day", "1400 mL/day", "1500 mL/day", "1600 mL/day"], correctIndex: 1, answer: "Holliday-Segar: first 10 kg × 100 = 1000 mL + next 8 kg × 50 = 400 mL = 1400 mL/day. Hourly rate: 40 + 16 = 56 mL/hr using the 4-2-1 rule.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedfl-q25", type: "question", question: "What maintenance fluid composition is typically used after initial resuscitation boluses in pediatric patients?", options: ["D5W only", "Normal saline 0.9% with 5% dextrose", "D5 0.45% NS (half-normal saline with 5% dextrose) ± KCl after urination", "Lactated Ringer's with albumin"], correctIndex: 2, answer: "After isotonic boluses for resuscitation, maintenance fluid is typically D5 0.45% NS (or D5 0.9% NS for younger infants). Add KCl (20-40 mEq/L) ONLY after urine output is confirmed. The dextrose prevents hypoglycemia, and the saline provides sodium for maintenance needs.", category: "Pediatrics", difficulty: 2 },

  // === LOW CARDIAC OUTPUT PEDS (25 cards) ===
  { id: "rn-lco-q1", type: "question", question: "When does low cardiac output syndrome (LCOS) typically reach its nadir after pediatric cardiac surgery?", options: ["Immediately after surgery", "6-18 hours postoperatively (nadir 8-12 hours)", "48-72 hours postoperatively", "5-7 days postoperatively"], correctIndex: 1, answer: "LCOS typically develops 6-18 hours after cardiac surgery, with the nadir (lowest cardiac output) at 8-12 hours. This timing correlates with myocardial stunning from cardiopulmonary bypass, inflammatory cytokine peak, and reperfusion injury. The nursing team must be vigilant during this window.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q2", type: "question", question: "Why is hypotension a LATE sign in pediatric patients?", options: ["Children have higher baseline blood pressures", "Children compensate with tachycardia and peripheral vasoconstriction, maintaining BP until 25-30% of blood volume is lost", "BP monitoring is inaccurate in children", "Children rarely develop hypotension"], correctIndex: 1, answer: "Pediatric patients have powerful compensatory mechanisms that maintain blood pressure: tachycardia (increasing CO = HR × SV) and peripheral vasoconstriction (maintaining SVR). These compensate until 25-30% of circulating volume is lost. Hypotension in a child is a PRE-ARREST sign indicating cardiovascular decompensation.", category: "Pediatrics", difficulty: 2, clinicalPearl: "In pediatrics: tachycardia + poor perfusion + normal BP = compensated shock. Adding hypotension = decompensated shock = pre-arrest." },
  { id: "rn-lco-q3", type: "question", question: "What is the earliest and most sensitive lab indicator of inadequate tissue perfusion in LCOS?", options: ["Elevated BUN", "Rising serum lactate", "Low hemoglobin", "Elevated AST"], correctIndex: 1, answer: "Serum lactate is the earliest and most sensitive marker of tissue hypoperfusion. It rises when cells switch to anaerobic metabolism due to inadequate oxygen delivery. Trend lactate every 2-4 hours — a rising level indicates worsening CO even before vital signs deteriorate. Normal <2 mmol/L; >4 is critical.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q4", type: "question", question: "What is the first-line inotrope for pediatric LCOS?", options: ["Dopamine", "Epinephrine", "Milrinone (phosphodiesterase-3 inhibitor)", "Dobutamine"], correctIndex: 2, answer: "Milrinone is first-line for LCOS because it provides positive inotropy AND reduces afterload (vasodilation) without increasing myocardial oxygen demand. This combination is particularly beneficial for the stunned, stiff post-bypass myocardium. It also improves diastolic relaxation (lusitropy).", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q5", type: "question", question: "A post-cardiac surgery infant has chest tube output of 4 mL/kg/hr for 3 consecutive hours. What should the nurse do?", options: ["Continue monitoring", "Notify the surgeon — this exceeds the threshold for possible surgical re-exploration (>3 mL/kg/hr for 3 hours)", "Increase IV fluids", "Clamp the chest tube"], correctIndex: 1, answer: "Chest tube output >3 mL/kg/hr for 3 consecutive hours suggests surgical bleeding requiring evaluation for re-exploration. Monitor output hourly, recording volume and character (bloody vs serosanguineous). Never clamp a chest tube without a specific order — clamping can cause cardiac tamponade.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q6", type: "question", question: "Chest tube drainage suddenly stops in a post-cardiac surgery child who develops tachycardia and hypotension. What is the concern?", options: ["Resolved bleeding", "Cardiac tamponade — clot may be occluding the tube while blood accumulates in the pericardium", "Pleural effusion", "Normal postoperative finding"], correctIndex: 1, answer: "Sudden cessation of drainage with hemodynamic deterioration strongly suggests cardiac tamponade. A blood clot likely occluded the chest tube while blood continued accumulating in the pericardium, compressing the heart and impairing diastolic filling. This is a surgical emergency requiring bedside or OR decompression.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q7", type: "question", question: "Why do infants depend more on heart rate than stroke volume to increase cardiac output?", options: ["Infants have mature myocardium", "The neonatal myocardium has fewer contractile elements and relatively non-compliant ventricles, limiting stroke volume augmentation", "Infants have larger hearts", "Heart rate is easier to monitor"], correctIndex: 1, answer: "The immature neonatal/infant myocardium has fewer and disorganized sarcomeres, more non-contractile elements, and relatively non-compliant ventricles that operate near the top of the Frank-Starling curve. This limits the ability to increase stroke volume. Therefore, CO = HR × SV relies primarily on heart rate adjustments.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q8", type: "question", question: "What core-to-peripheral temperature gap indicates poor perfusion in a post-cardiac surgery child?", options: [">0.5C", ">1C", ">2C gap between core (rectal/esophageal) and peripheral (toe) temperature", ">5C"], correctIndex: 2, answer: "A core-peripheral temperature gap >2C indicates peripheral vasoconstriction from inadequate cardiac output. The body redirects blood flow from the periphery (cool extremities) to vital organs. Monitor core temperature (esophageal/rectal) and peripheral temperature (toe) simultaneously to detect this gradient.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q9", type: "question", question: "What urine output indicates inadequate renal perfusion in an infant?", options: ["<3 mL/kg/hr", "<2 mL/kg/hr", "<1 mL/kg/hr", "<0.1 mL/kg/hr"], correctIndex: 2, answer: "UOP <1 mL/kg/hr in infants and <0.5 mL/kg/hr in older children indicates inadequate renal perfusion. Monitor hourly with a Foley catheter for accurate measurement. Report declining UOP trends promptly — the kidneys are highly sensitive to reduced cardiac output.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-lco-q10", type: "question", question: "What is the most common post-cardiac surgery arrhythmia in children?", options: ["Atrial fibrillation", "Ventricular tachycardia", "Junctional ectopic tachycardia (JET)", "Sinus bradycardia"], correctIndex: 2, answer: "JET is the most common post-cardiac surgery arrhythmia in children, particularly after VSD or TOF repair. It causes loss of AV synchrony (atrial kick), reducing cardiac output by 15-25%. Treatment includes active cooling to 35C (slows the ectopic focus) and amiodarone. Avoid digoxin.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q11", type: "question", question: "What mixed venous oxygen saturation (SvO2) indicates inadequate oxygen delivery?", options: ["<80%", "<70%", "<60%", "<50%"], correctIndex: 2, answer: "SvO2 <60% indicates that tissues are extracting more oxygen than normal because delivery is inadequate (low cardiac output). Normal SvO2 is 65-75%. It is a global indicator of the balance between oxygen supply and demand. Trends are more important than single values.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q12", type: "question", question: "What monitoring technology provides continuous assessment of cerebral and renal oxygenation in post-cardiac surgery children?", options: ["Pulse oximetry", "Arterial blood gas", "Near-infrared spectroscopy (NIRS)", "Capnography"], correctIndex: 2, answer: "NIRS uses near-infrared light to continuously monitor regional tissue oxygen saturation in the brain (cerebral NIRS) and kidneys (renal NIRS). It detects tissue hypoxia before vital signs change, providing early warning of low cardiac output. Declining trends trigger intervention before organ damage occurs.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q13", type: "question", question: "What is ECMO and when is it used in pediatric LCOS?", options: ["A type of ventilator", "Extracorporeal membrane oxygenation — rescue therapy for LCOS that does not respond to maximal medical therapy", "An antibiotic", "A type of chest drain"], correctIndex: 1, answer: "ECMO provides temporary cardiopulmonary support by circulating blood through an external oxygenator, allowing the heart and lungs to rest and recover. In LCOS, it is used as rescue therapy when the patient fails to respond to maximal inotropic support, volume optimization, and rate management.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q14", type: "question", question: "Why is normothermia (36.5-37C) important in post-cardiac surgery children?", options: ["It prevents infection", "Hypothermia increases SVR and myocardial oxygen demand, worsening LCOS", "It is a standard hospital policy", "Temperature doesn't affect cardiac output"], correctIndex: 1, answer: "Hypothermia causes peripheral vasoconstriction (increasing SVR/afterload), increasing myocardial oxygen demand at a time when the stunned myocardium cannot compensate. Active warming with warming blankets and warm IV fluids is essential. Target core temperature 36.5-37.0C.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q15", type: "question", question: "At what dose range does epinephrine transition from primarily beta to primarily alpha effects?", options: ["0.001-0.005 mcg/kg/min", "0.01-0.05 mcg/kg/min (beta) vs >0.1 mcg/kg/min (alpha)", "1-5 mcg/kg/min", "10-50 mcg/kg/min"], correctIndex: 1, answer: "Epinephrine at low doses (0.01-0.05 mcg/kg/min) primarily stimulates beta receptors (increased HR, contractility). Above 0.1 mcg/kg/min, alpha effects predominate (vasoconstriction). In LCOS, escalating epinephrine doses indicate worsening cardiac function. Monitor for tachyarrhythmias and tissue lactate at high doses.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q16", type: "question", question: "What nursing intervention helps minimize oxygen demand in a post-cardiac surgery child?", options: ["Encourage ambulation", "Cluster nursing care, provide adequate sedation and pain management, minimize unnecessary stimulation", "Frequent vital sign checks every 15 minutes", "Bright lighting for assessment"], correctIndex: 1, answer: "Minimizing metabolic demand reduces myocardial work. Cluster care (group assessments and interventions together), provide adequate analgesia and sedation, reduce environmental stimulation (dim lights, minimize noise), and maintain normothermia. Each stress response increases catecholamines, HR, and myocardial oxygen consumption.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q17", type: "question", question: "What sign of cardiac tamponade is classically described as Beck's triad?", options: ["Fever, tachycardia, hypotension", "Hypotension, JVD/elevated CVP, muffled heart sounds", "Bradycardia, hypertension, irregular respirations", "Chest pain, dyspnea, diaphoresis"], correctIndex: 1, answer: "Beck's triad of cardiac tamponade: hypotension (decreased CO from impaired filling), JVD/elevated CVP (impaired venous return to compressed heart), and muffled/distant heart sounds (pericardial fluid dampening sounds). In post-surgical patients, sudden decrease in chest tube output with these signs is highly concerning.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q18", type: "question", question: "What type of IV access is required for inotrope administration in children?", options: ["Any peripheral IV", "Central venous access via infusion pump with weight-based dosing calculations verified by a second nurse", "Oral medication route", "IM injection"], correctIndex: 1, answer: "Inotropes should be administered via central venous access (internal jugular, subclavian, or femoral central line) using a dedicated lumen and infusion pump. Peripheral administration of vasopressors risks tissue necrosis from extravasation. All weight-based calculations must be verified independently.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q19", type: "question", question: "If dopamine extravasates from a peripheral IV, what is the antidote?", options: ["Warm compresses", "Phentolamine (alpha-adrenergic blocker) infiltrated locally", "Nitroglycerin paste", "Ice application"], correctIndex: 1, answer: "Phentolamine (5-10 mg diluted in 10 mL NS) is infiltrated directly into the affected tissue to counteract the alpha-adrenergic vasoconstriction caused by extravasated dopamine or other vasopressors. It must be given within 12 hours of extravasation to prevent tissue necrosis.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-lco-q20", type: "question", question: "Why is milrinone preferred over dobutamine for pediatric LCOS?", options: ["It is cheaper", "Milrinone reduces afterload (vasodilation) in addition to improving contractility, which is beneficial for the stiff, post-bypass myocardium", "Dobutamine is not available for children", "They are equally effective"], correctIndex: 1, answer: "Milrinone is an inodilator — it increases contractility AND reduces afterload (SVR) through PDE-3 inhibition. This dual action is ideal for the post-bypass myocardium, which is stunned and non-compliant. Reducing afterload decreases the workload on the weakened heart while improving forward flow.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q21", type: "question", question: "What assessment finding best indicates improving cardiac output in a post-surgical infant?", options: ["Decreasing heart rate, warming extremities, increasing urine output, and falling lactate", "Increasing blood pressure only", "Decreased respiratory rate", "Normal temperature"], correctIndex: 0, answer: "Improvement in LCOS is indicated by: decreasing HR (less compensation needed), warming extremities (improved peripheral perfusion), increasing UOP (improved renal perfusion), falling lactate (improved tissue oxygenation), and narrowing core-peripheral temperature gap. These are more reliable indicators than BP alone.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q22", type: "question", question: "What complex cardiac surgeries carry the highest risk for LCOS?", options: ["Simple ASD repair", "Norwood procedure, arterial switch operation, Fontan completion", "PDA ligation", "Pacemaker insertion"], correctIndex: 1, answer: "Complex surgeries with prolonged bypass times carry the highest LCOS risk: Norwood procedure (for HLHS — most complex neonatal cardiac surgery), arterial switch (for TGA), and Fontan completion (for single ventricle). These involve significant myocardial manipulation and long bypass/cross-clamp times.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q23", type: "question", question: "How often should serum lactate be trended during the LCOS risk window?", options: ["Once daily", "Every 2-4 hours", "Every 12 hours", "Only if the patient appears unwell"], correctIndex: 1, answer: "Trend lactate every 2-4 hours during the 6-18 hour LCOS risk window. A rising trend is more concerning than a single elevated value. Clearing lactate (returning to normal) indicates adequate resuscitation. Persistently elevated or rising lactate despite maximal therapy may indicate need for mechanical support (ECMO).", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q24", type: "question", question: "What is the significance of metabolic acidosis (base deficit) on ABG in a child with suspected LCOS?", options: ["It indicates respiratory disease", "It reflects anaerobic metabolism from inadequate tissue oxygen delivery", "It is a normal postoperative finding", "It indicates metabolic alkalosis"], correctIndex: 1, answer: "Metabolic acidosis with base deficit on ABG indicates that tissues are not receiving adequate oxygen, forcing anaerobic metabolism and lactic acid production. A worsening base deficit correlates with worsening tissue hypoperfusion and is an important marker of LCOS severity.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-lco-q25", type: "question", question: "What emergency equipment should be at the bedside of every post-cardiac surgery pediatric patient?", options: ["Wheelchair", "Defibrillator, pacing equipment, intubation supplies, emergency medications, and ECMO team contact information", "Oxygen tank only", "Suction device only"], correctIndex: 1, answer: "Post-cardiac surgery patients require immediate access to: defibrillator (for arrhythmias), temporary pacing equipment (epicardial wires placed intraoperatively), intubation supplies, emergency medications (epinephrine, atropine, calcium), and ECMO team contact for rapid deployment if needed.", category: "Pediatrics", difficulty: 1 },

  // === PEDIATRIC SEIZURES (25 cards) ===
  { id: "rn-pedsz-q1", type: "question", question: "What defines a simple febrile seizure?", options: ["Focal onset, >15 minutes, recurrent", "Generalized tonic-clonic, <15 minutes, single episode per illness, no focal features", "Any seizure with fever", "Seizure in a child >6 years"], correctIndex: 1, answer: "Simple febrile seizures are: generalized (not focal), <15 minutes duration, single episode per febrile illness, no focal features, and occur in children 6 months to 5 years. They have an excellent prognosis with NO increased risk of epilepsy. Complex febrile seizures are >15 min, focal, or recurrent.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q2", type: "question", question: "A child has been seizing continuously for 7 minutes with no IV access. What medication is given?", options: ["IV lorazepam", "IM midazolam 0.2 mg/kg", "Oral phenobarbital", "IV fosphenytoin"], correctIndex: 1, answer: "When IV access is unavailable, IM midazolam 0.2 mg/kg (max 10 mg) is first-line for status epilepticus. The RAMPART trial showed IM midazolam was as effective as IV lorazepam. Intranasal midazolam (0.2 mg/kg) or rectal diazepam are alternatives.", category: "Pediatrics", difficulty: 2, clinicalPearl: "The RAMPART trial is landmark evidence supporting IM midazolam as equivalent to IV lorazepam for pre-hospital seizure management." },
  { id: "rn-pedsz-q3", type: "question", question: "What should the nurse check FIRST in any seizing child?", options: ["Blood pressure", "Fingerstick glucose — hypoglycemia is the most treatable cause", "Serum sodium", "Head CT"], correctIndex: 1, answer: "Fingerstick glucose is the FIRST bedside test in any seizing child. Hypoglycemia is the most common rapidly reversible cause of seizures and can be corrected immediately with IV dextrose (D10W 2-5 mL/kg for neonates, D25W 2 mL/kg for infants/children). Prolonged hypoglycemia causes brain damage.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q4", type: "question", question: "What is the definition of status epilepticus?", options: ["Any seizure lasting >30 seconds", "Continuous seizure activity lasting >5 minutes or 2+ seizures without return to baseline consciousness", "A seizure that requires medication", "More than 3 seizures in 24 hours"], correctIndex: 1, answer: "Status epilepticus is defined as continuous seizure activity lasting >5 minutes (updated from the historical 30-minute definition) OR two or more seizures without return to baseline consciousness between them. It is a neurological emergency requiring immediate benzodiazepine therapy.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q5", type: "question", question: "What is the 5-20-40 rule for status epilepticus management?", options: ["Timing for vital signs", "5 min: benzodiazepine; 20 min: second-line AED; 40 min: third-line/anesthetic agents", "Dosing schedule for phenobarbital", "ICU transfer criteria"], correctIndex: 1, answer: "The 5-20-40 timed approach: At 5 minutes — give benzodiazepine (lorazepam or midazolam). At 20 minutes if still seizing — give second-line AED (fosphenytoin or levetiracetam). At 40 minutes if still seizing — give third-line agent (phenobarbital or continuous infusion anesthetic) with intubation.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q6", type: "question", question: "What should the nurse NEVER put in the mouth of a seizing patient?", options: ["A tongue depressor to prevent tongue swallowing", "Nothing should be placed in the mouth — the myth of swallowing the tongue is false and bite blocks cause injury", "A padded tongue blade", "An oral airway during active seizure"], correctIndex: 1, answer: "NEVER insert anything into the mouth during a seizure. The tongue cannot be swallowed. Bite blocks and tongue depressors cause dental fractures, oral lacerations, and aspiration of broken fragments. Position the patient on their side (recovery position) to maintain airway and prevent aspiration.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q7", type: "question", question: "After administering lorazepam for status epilepticus, what must the nurse monitor most closely?", options: ["Heart rhythm", "Respiratory rate and depth — benzodiazepines cause respiratory depression", "Skin color changes", "Blood glucose"], correctIndex: 1, answer: "Benzodiazepines cause respiratory depression, which is the most dangerous side effect. Have bag-valve-mask, suction, and supplemental oxygen at bedside. Monitor respiratory rate, depth, SpO2, and level of consciousness. Be prepared for possible apnea requiring assisted ventilation.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q8", type: "question", question: "Do simple febrile seizures increase the risk of epilepsy?", options: ["Yes — all febrile seizures lead to epilepsy", "No — simple febrile seizures do NOT increase the risk of epilepsy", "Only if they occur more than once", "Only in children under 1 year"], correctIndex: 1, answer: "Simple febrile seizures do NOT increase the risk of epilepsy and do NOT cause brain damage. The risk of developing epilepsy is the same as the general population (~1%). Complex febrile seizures carry a slightly increased risk (2-4%). Parental reassurance is a critical nursing intervention.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q9", type: "question", question: "What is Todd paralysis?", options: ["A type of seizure", "Transient focal weakness following a seizure that may mimic stroke — it resolves spontaneously", "Permanent paralysis from seizures", "A medication side effect"], correctIndex: 1, answer: "Todd paralysis is transient focal neurological deficit (typically hemiparesis) occurring after a seizure, lasting minutes to hours (rarely up to 36 hours). It results from temporary neuronal exhaustion in the seizure focus. It is important to differentiate from stroke, though both require urgent evaluation.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q10", type: "question", question: "What is the most common cause of neonatal seizures?", options: ["Febrile seizure", "Hypoxic-ischemic encephalopathy (HIE)", "Epilepsy", "Metabolic alkalosis"], correctIndex: 1, answer: "Hypoxic-ischemic encephalopathy (perinatal asphyxia) is the most common cause of neonatal seizures. Neonatal seizures are ALWAYS pathological (never benign febrile seizures) and require thorough investigation for HIE, intracranial hemorrhage, infection (meningitis), metabolic disturbances, or congenital anomalies.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q11", type: "question", question: "What seizure presentation is unique to neonates that differs from older children?", options: ["Grand mal seizures", "Subtle seizures: eye deviation, lip smacking, bicycling movements, apnea", "Absence seizures", "Complex partial seizures"], correctIndex: 1, answer: "Neonatal seizures are often subtle rather than the classic tonic-clonic activity seen in older children. Look for eye deviation/nystagmus, lip smacking, tongue thrusting, bicycling or swimming movements of extremities, and apneic episodes. These are easily missed without careful observation.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q12", type: "question", question: "What is Diastat and when is it used?", options: ["An oral anticonvulsant for daily use", "Rectal diazepam — prescribed for home/school rescue use in children with epilepsy and history of prolonged seizures", "An IV antibiotic", "A nasal decongestant"], correctIndex: 1, answer: "Diastat (rectal diazepam gel) is a rescue medication prescribed for home or school use in children with known epilepsy who have a history of prolonged or cluster seizures. Caregivers are trained to administer it rectally if a seizure lasts >5 minutes. Call 911 if seizure continues after administration.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q13", type: "question", question: "What documented information about a seizure is most important for the medical team?", options: ["The child's recent meals", "Time of onset, duration, type of movements, body parts involved, eye position, incontinence, and postictal state", "Room temperature", "Visitors present"], correctIndex: 1, answer: "Detailed seizure documentation includes: exact time of onset, duration, type of movements (tonic, clonic, or both), body parts involved (generalized vs focal), direction of eye deviation, presence of aura, incontinence, level of consciousness, and postictal state description. This guides EEG interpretation and diagnosis.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q14", type: "question", question: "What is the dose of IV lorazepam for status epilepticus?", options: ["0.01 mg/kg", "0.1 mg/kg (max 4 mg/dose)", "1 mg/kg", "10 mg flat dose"], correctIndex: 1, answer: "IV lorazepam 0.1 mg/kg (max 4 mg/dose) is the first-line IV benzodiazepine for status epilepticus. Onset is 2-3 minutes when given IV. May repeat once in 5-10 minutes if seizure continues. Duration of action is 12-24 hours. Monitor for respiratory depression.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q15", type: "question", question: "Can antipyretics (acetaminophen/ibuprofen) prevent febrile seizures?", options: ["Yes — always give prophylactic antipyretics during febrile illness", "No — antipyretics reduce fever for comfort but do NOT prevent febrile seizures", "Only ibuprofen prevents seizures", "Only if given every 2 hours"], correctIndex: 1, answer: "Antipyretics do NOT prevent febrile seizures because the seizure is triggered by the RATE of temperature rise, not the absolute temperature. By the time fever is detected, the rapid rise has already occurred. Antipyretics are given for comfort but should not be used prophylactically to prevent seizures.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q16", type: "question", question: "What side effect of levetiracetam (Keppra) is particularly notable in children?", options: ["Hepatotoxicity", "Behavioral changes and irritability ('Keppra rage')", "Hair loss", "Weight gain"], correctIndex: 1, answer: "'Keppra rage' — behavioral changes including irritability, aggression, mood swings, and emotional lability — is a well-known side effect in children taking levetiracetam. It occurs in approximately 10-20% of patients. Despite this, levetiracetam remains widely used because it has fewer drug interactions and no need for level monitoring.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q17", type: "question", question: "When is lumbar puncture indicated for a febrile seizure?", options: ["Always for any febrile seizure", "For infants <6 months, immunocompromised children, or when meningitis is clinically suspected", "Never", "Only for complex febrile seizures"], correctIndex: 1, answer: "LP is indicated for febrile seizures in infants <6-12 months (who may not show meningeal signs), immunocompromised children, those who are not up to date on Hib/pneumococcal vaccines, or when there is clinical suspicion of meningitis. It is contraindicated if there are signs of increased ICP.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedsz-q18", type: "question", question: "What teaching is most important for parents of a child who had a simple febrile seizure?", options: ["Start daily anticonvulsant medication", "Seizure first aid, when to call 911, and reassurance that simple febrile seizures do not cause brain damage or epilepsy", "Avoid all vaccines", "Keep the child home permanently"], correctIndex: 1, answer: "Key parental education: most febrile seizures are benign, do not cause brain damage, and do not lead to epilepsy. Teach seizure first aid (side position, time it, don't put anything in mouth). Call 911 if seizure lasts >5 minutes, breathing difficulty, or first seizure. Manage fever for comfort.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q19", type: "question", question: "What second-line anticonvulsant is increasingly used in pediatric status epilepticus?", options: ["Carbamazepine", "Phenytoin", "Levetiracetam (40-60 mg/kg IV) — fewer drug interactions and no cardiac monitoring needed", "Gabapentin"], correctIndex: 2, answer: "Levetiracetam is increasingly used as a second-line agent for pediatric status epilepticus (40-60 mg/kg IV). Advantages include fewer drug interactions than phenytoin, no need for cardiac monitoring during loading, broader spectrum of efficacy, and no hepatic metabolism concerns.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q20", type: "question", question: "What age range is most susceptible to febrile seizures?", options: ["Birth to 3 months", "6 months to 5 years", "6 to 12 years", "13 to 18 years"], correctIndex: 1, answer: "Febrile seizures occur in children aged 6 months to 5 years, with peak incidence at 12-18 months. After age 5, the brain's thermoregulatory mechanisms mature and the seizure threshold increases. Febrile seizures affect 2-5% of children in this age group.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q21", type: "question", question: "During a seizure, what is the correct nursing position for the patient?", options: ["Supine with head tilted back", "Side-lying (recovery position) to maintain airway and prevent aspiration", "Prone", "Upright in a chair"], correctIndex: 1, answer: "Position the patient on their side (recovery position) to allow secretions to drain from the mouth, maintaining the airway and preventing aspiration. Remove hazardous objects from the area. Do not restrain the patient. Pad side rails if in bed. Loosen tight clothing around the neck.", category: "Pediatrics", difficulty: 1 },
  { id: "rn-pedsz-q22", type: "question", question: "What IV dextrose concentration is used for neonatal hypoglycemic seizures?", options: ["D50W (50% dextrose)", "D25W (25% dextrose)", "D10W (10% dextrose) at 2-5 mL/kg", "Regular IV saline"], correctIndex: 2, answer: "D10W at 2-5 mL/kg IV is used for neonatal hypoglycemia. D50W and D25W are TOO concentrated for neonates and can cause rebound hypoglycemia, hyperglycemia with osmotic shifts, and intraventricular hemorrhage. Infants receive D25W at 2 mL/kg. Adolescents may receive D50W.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedsz-q23", type: "question", question: "Why are febrile seizures triggered by the RATE of temperature rise rather than the absolute temperature?", options: ["The thermometer is inaccurate", "Immature thermoregulatory mechanisms in children cause rapid changes in neuronal excitability during rapid temperature elevation", "Seizures only occur at specific temperatures", "This theory has been disproven"], correctIndex: 1, answer: "The immature developing brain is particularly sensitive to rapid changes in core body temperature. The speed of temperature rise causes increased neuronal excitability more than the peak temperature itself. This explains why seizures often occur at the onset of illness before parents even realize the child has a fever.", category: "Pediatrics", difficulty: 2 },
  { id: "rn-pedsz-q24", type: "question", question: "What is refractory status epilepticus and how is it managed?", options: ["Any seizure >2 minutes", "Status epilepticus that does not respond to first- and second-line agents — requires ICU, continuous EEG, and anesthetic infusions", "A seizure that resolves spontaneously", "Absence seizures"], correctIndex: 1, answer: "Refractory status epilepticus fails to respond to benzodiazepines and second-line agents. It requires ICU admission, continuous EEG monitoring, and anesthetic infusions (midazolam, propofol, or pentobarbital continuous drip) with mechanical ventilation. Pharmacoresistance develops as GABA receptors are internalized during prolonged seizures.", category: "Pediatrics", difficulty: 3 },
  { id: "rn-pedsz-q25", type: "question", question: "What determines whether a child with epilepsy needs daily maintenance anticonvulsant therapy?", options: ["A single unprovoked seizure always requires medication", "Two or more unprovoked seizures (epilepsy diagnosis), or a single seizure with high recurrence risk", "Only status epilepticus requires medication", "All febrile seizures require daily medication"], correctIndex: 1, answer: "Epilepsy is defined as 2+ unprovoked seizures (or 1 seizure with high recurrence risk based on EEG/MRI findings). Simple febrile seizures do NOT require maintenance anticonvulsants. Treatment decisions consider seizure type, frequency, age, and impact on quality of life.", category: "Pediatrics", difficulty: 2 },

  // === WOUND HEALING (25 cards) ===
  { id: "rn-wh-q1", type: "question", question: "Which cell type is the MOST important coordinator of wound healing?", options: ["Neutrophils", "Platelets", "Macrophages", "Fibroblasts"], correctIndex: 2, answer: "Macrophages are the most critical cells in wound healing. They arrive on day 2-3, phagocytize debris, secrete growth factors (PDGF, TGF-beta, VEGF) that recruit fibroblasts and stimulate angiogenesis, and orchestrate the transition from inflammation to proliferation. Without macrophages, wounds cannot heal.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q2", type: "question", question: "A surgical wound separates on day 5 and loops of bowel are visible. What is the FIRST nursing action?", options: ["Push the bowel back into the abdomen", "Cover with sterile saline-moistened towels, position supine with knees flexed, call surgeon STAT", "Apply an abdominal binder", "Irrigate with antiseptic"], correctIndex: 1, answer: "Evisceration is a surgical emergency. Cover exposed organs with sterile saline-moistened (not dry) towels to prevent drying and contamination. Position supine with knees flexed to reduce abdominal tension. NEVER attempt to reinsert organs. Notify surgeon immediately for emergent OR return.", category: "Integumentary", difficulty: 3, clinicalPearl: "Keep the towels continuously moist with sterile saline. Evisceration most commonly occurs on postoperative days 5-8 during the early proliferative phase when wound strength is minimal." },
  { id: "rn-wh-q3", type: "question", question: "What vitamin is essential for collagen synthesis and cross-linking?", options: ["Vitamin A", "Vitamin B12", "Vitamin C (ascorbic acid)", "Vitamin D"], correctIndex: 2, answer: "Vitamin C is an essential cofactor for prolyl and lysyl hydroxylase enzymes needed for collagen cross-linking and stability. Deficiency (scurvy) causes impaired wound healing, easy bruising, gum bleeding, and connective tissue weakness. Supplement 250-500 mg BID during active wound healing.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q4", type: "question", question: "What does the 'red-yellow-black' wound color assessment guide?", options: ["Infection classification", "Red = protect (granulation), Yellow = cleanse/debride (slough), Black = debride (eschar/necrotic tissue)", "Dressing selection chart", "Pain scale"], correctIndex: 1, answer: "The red-yellow-black system guides wound management: RED = healthy granulation tissue, protect with moist dressings; YELLOW = slough (devitalized tissue), requires cleansing and gentle debridement; BLACK = eschar (necrotic tissue), requires debridement before healing can occur.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q5", type: "question", question: "What maximum tensile strength does a fully healed wound achieve compared to original tissue?", options: ["40%", "60%", "80% of original strength (never 100%)", "100%"], correctIndex: 2, answer: "Fully mature scar tissue achieves only approximately 80% of the original tissue's tensile strength, even after the remodeling phase (which can last up to 2 years). The wound will never return to pre-injury strength. This is why healed wounds are at risk for re-injury under stress.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q6", type: "question", question: "What solution and pressure should be used for wound irrigation?", options: ["Hydrogen peroxide at high pressure", "Normal saline at 4-15 psi (using a 30-60 mL syringe with 18-gauge angiocath)", "Povidone-iodine (Betadine) full strength", "Alcohol irrigation"], correctIndex: 1, answer: "Normal saline irrigation at 4-15 psi provides adequate pressure to remove debris and bacteria without damaging healthy tissue. A 30-60 mL syringe with an 18-gauge angiocath generates this pressure. Avoid cytotoxic agents (hydrogen peroxide, full-strength Betadine) on healing tissue — they damage fibroblasts.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q7", type: "question", question: "Why do wounds heal faster in a moist environment?", options: ["Moisture prevents infection", "Moist environments promote epithelial cell migration, angiogenesis, and autolytic debridement — healing is 50% faster", "Moisture reduces pain only", "Moist environments have no benefit"], correctIndex: 1, answer: "Moist wound healing promotes: epithelial cell migration across the wound bed, angiogenesis, autolytic debridement (body's own enzymes break down necrotic tissue), and reduces scar formation. Research shows wounds heal 50% faster in optimally moist environments compared to dry environments.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q8", type: "question", question: "How does smoking impair wound healing?", options: ["It doesn't affect wound healing", "Nicotine causes vasoconstriction reducing tissue oxygenation; carbon monoxide binds hemoglobin reducing oxygen-carrying capacity", "It causes excess collagen formation", "It only affects lung function"], correctIndex: 1, answer: "Smoking impairs wound healing through multiple mechanisms: nicotine causes peripheral vasoconstriction (reducing tissue oxygen and nutrient delivery), carbon monoxide binds hemoglobin (reducing oxygen-carrying capacity by 15%), and cigarette toxins impair immune function and collagen synthesis.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q9", type: "question", question: "What protein intake is recommended for wound healing?", options: ["0.8 g/kg/day (standard)", "1.25-1.5 g/kg/day", "3 g/kg/day", "Protein restriction"], correctIndex: 1, answer: "Wound healing requires increased protein (1.25-1.5 g/kg/day) because protein is essential for collagen synthesis, immune function, and cell proliferation. Serum albumin <3.5 g/dL and prealbumin <15 mg/dL indicate nutritional deficiency that impairs healing. Collaborate with dietitian for optimization.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q10", type: "question", question: "How can vitamin A counteract the negative effects of corticosteroids on wound healing?", options: ["It cannot", "Vitamin A (10,000 IU/day) partially restores inflammatory and immune responses suppressed by steroids", "It increases steroid absorption", "It reduces steroid side effects on bone"], correctIndex: 1, answer: "Corticosteroids impair wound healing by suppressing inflammation and immune function. Vitamin A (10,000 IU/day) can partially reverse these effects by restoring macrophage function, collagen synthesis, and epithelialization. This is clinically important for patients on chronic steroids who develop wounds.", category: "Integumentary", difficulty: 3 },
  { id: "rn-wh-q11", type: "question", question: "What are the four phases of wound healing in order?", options: ["Proliferation, inflammation, hemostasis, remodeling", "Hemostasis, inflammation, proliferation, remodeling (maturation)", "Inflammation, hemostasis, remodeling, proliferation", "Remodeling, proliferation, inflammation, hemostasis"], correctIndex: 1, answer: "The four overlapping phases: 1) Hemostasis (immediate — clot formation), 2) Inflammation (days 1-6 — neutrophils then macrophages), 3) Proliferation (days 4-21 — fibroblasts, collagen, granulation, epithelialization), 4) Remodeling/Maturation (day 21 to 2 years — type III to type I collagen replacement).", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q12", type: "question", question: "What type of wound dressing is most appropriate for a dry wound bed?", options: ["Alginate dressing (absorbs moisture)", "Hydrogel (donates moisture to the wound)", "Gauze packing without moistening", "No dressing needed"], correctIndex: 1, answer: "Hydrogel dressings donate moisture to dry wound beds, creating the optimal moist environment for healing. Alginates and foam dressings are for heavily exudating wounds (they absorb excess moisture). The goal is to match the dressing to the wound's moisture needs — neither too wet nor too dry.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q13", type: "question", question: "What is the difference between primary, secondary, and tertiary intention wound healing?", options: ["They all mean the same thing", "Primary = surgical closure (edges approximated); Secondary = open wound healing by granulation; Tertiary = delayed closure after initial open management", "Primary = open wound; secondary = sutured; tertiary = infected", "These terms are not used in nursing"], correctIndex: 1, answer: "Primary intention: wound edges are directly approximated (sutures, staples, adhesive) — fastest healing, minimal scarring. Secondary intention: wound is left open to heal by granulation, contraction, and epithelialization — larger scar. Tertiary (delayed primary): wound initially left open (e.g., contaminated wound), then closed after infection is controlled.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q14", type: "question", question: "What technique should be used to obtain a wound culture that accurately reflects tissue bacteria?", options: ["Swab the wound surface", "Clean the wound first, then culture from the wound BASE (not the surface) for accurate results", "Culture the drainage on the dressing", "No preparation needed"], correctIndex: 1, answer: "Surface swabs pick up colonizing organisms, not the true infecting pathogens. Cleanse the wound first to remove surface contaminants, then obtain the specimen from the wound base or freshly debrided tissue. Quantitative tissue biopsy (>100,000 CFU/g) is the gold standard for wound infection diagnosis.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q15", type: "question", question: "What are the signs of wound infection that extend beyond normal inflammatory response?", options: ["Mild redness at wound edges only", "Erythema extending >2 cm beyond wound margins, increased warmth, purulent drainage, foul odor, increasing pain, and systemic signs (fever, elevated WBC)", "Any exudate is infection", "Pain alone indicates infection"], correctIndex: 1, answer: "Wound infection signs include: erythema spreading >2 cm beyond wound edges (cellulitis), increasing warmth, purulent (yellow/green) drainage, foul odor, escalating pain, induration, and systemic signs (fever, tachycardia, leukocytosis). Normal inflammation is localized and proportional; infection is spreading and worsening.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q16", type: "question", question: "What analgesic timing is recommended before wound dressing changes?", options: ["During the procedure", "30 minutes before the dressing change", "After the dressing change", "No analgesic is needed"], correctIndex: 1, answer: "Administer analgesics 30 minutes before dressing changes to allow peak drug effect during the procedure. Wound care can be extremely painful, especially for chronic wounds. Use both systemic analgesics and topical agents (lidocaine gel). Assess pain before, during, and after the procedure.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q17", type: "question", question: "What does negative pressure wound therapy (wound VAC) do?", options: ["Sterilizes the wound", "Applies controlled negative pressure to promote granulation tissue formation, remove excess exudate, and reduce edema", "Adds moisture to the wound", "Closes the wound surgically"], correctIndex: 1, answer: "NPWT applies controlled negative pressure (typically -125 mmHg) through a sealed dressing. This promotes granulation tissue formation, removes excess wound fluid, reduces bacterial colonization, reduces edema, and increases local blood flow. Used for complex wounds, grafts, and open abdomens.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q18", type: "question", question: "What mineral is essential for cell division and immune function in wound healing?", options: ["Iron", "Zinc", "Magnesium", "Copper"], correctIndex: 1, answer: "Zinc is essential for cell division (mitosis), protein synthesis, and immune function — all critical for wound healing. Supplement with zinc sulfate 220 mg daily (50 mg elemental zinc) for 2-3 weeks during active wound healing. Prolonged use (>3 months) can cause copper deficiency.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q19", type: "question", question: "Why does diabetes mellitus impair wound healing?", options: ["Diabetes doesn't affect wounds", "Hyperglycemia impairs neutrophil function, microangiopathy reduces tissue perfusion, and peripheral neuropathy prevents protective sensation", "Insulin causes wound breakdown", "Only type 1 diabetes affects healing"], correctIndex: 1, answer: "Diabetes impairs healing through multiple mechanisms: hyperglycemia directly impairs neutrophil chemotaxis and phagocytosis (increasing infection risk), microangiopathy reduces tissue oxygen and nutrient delivery, and peripheral neuropathy prevents detection of injury or pressure. Target glucose <180 mg/dL for optimal healing.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q20", type: "question", question: "What HbA1c target optimizes wound healing in diabetic patients?", options: ["<10%", "<9%", "<7%", "Any level is acceptable"], correctIndex: 2, answer: "HbA1c <7% indicates good glycemic control over the past 2-3 months and is the target for optimal wound healing. Poor glycemic control (HbA1c >8%) significantly impairs all phases of wound healing and increases infection risk. Blood glucose should be maintained <180 mg/dL during active wound treatment.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q21", type: "question", question: "What is the MEASURE framework for wound assessment?", options: ["A wound sizing calculator", "M=Measure, E=Exudate, A=Appearance, S=Suffering(pain), U=Undermining, R=Re-evaluate, E=Edge condition", "A medication protocol", "A nutrition assessment tool"], correctIndex: 1, answer: "MEASURE provides systematic wound assessment: Measure (length × width × depth), Exudate (type, amount, color, odor), Appearance (wound bed description), Suffering (pain assessment), Undermining/tunneling (document by clock position), Re-evaluate (reassess at intervals), Edge condition (rolled, macerated, attached).", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q22", type: "question", question: "When using collagenase (Santyl) for enzymatic debridement, what products should NOT be applied simultaneously?", options: ["Normal saline", "Moisture barriers", "Silver-containing products or acidic solutions — they inactivate the enzyme", "Gauze dressings"], correctIndex: 2, answer: "Collagenase (Santyl) is inactivated by silver-containing products, iodine, acidic solutions, and heavy metal ions. Do not use these simultaneously. Apply Santyl directly to necrotic tissue, cross-hatch hard eschar for better penetration, and cover with an appropriate moisture-retentive secondary dressing.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q23", type: "question", question: "What is wound undermining?", options: ["A wound that extends beneath intact skin at the wound margins, creating a pocket", "Wound infection", "Wound closure technique", "Normal healing process"], correctIndex: 0, answer: "Undermining is tissue destruction extending beneath intact skin around the wound edges, creating a pocket or shelf. It is measured by inserting a cotton-tipped applicator under the wound edge and documenting by clock position and depth. It indicates progressive tissue destruction and may require packing or surgical intervention.", category: "Integumentary", difficulty: 2 },
  { id: "rn-wh-q24", type: "question", question: "What serum albumin level indicates malnutrition that impairs wound healing?", options: ["<5.0 g/dL", "<4.0 g/dL", "<3.5 g/dL", "<2.0 g/dL"], correctIndex: 2, answer: "Serum albumin <3.5 g/dL indicates malnutrition affecting wound healing. However, albumin has a 20-day half-life and reflects chronic nutritional status. Prealbumin (half-life 2-3 days, normal 15-35 mg/dL) is more sensitive to acute nutritional changes and is preferred for monitoring short-term nutrition status.", category: "Integumentary", difficulty: 1 },
  { id: "rn-wh-q25", type: "question", question: "In which phase of wound healing does granulation tissue form?", options: ["Hemostasis phase", "Inflammatory phase", "Proliferative phase (days 4-21)", "Remodeling phase"], correctIndex: 2, answer: "Granulation tissue (red, beefy, highly vascular tissue) forms during the proliferative phase (days 4-21). Fibroblasts synthesize collagen, new blood vessels form (angiogenesis), and epithelial cells migrate across the wound surface. Granulation tissue indicates healthy healing progress.", category: "Integumentary", difficulty: 1 },

  // === PRESSURE INJURIES (25 cards) ===
  { id: "rn-pi-q1", type: "question", question: "A nurse presses on a reddened area over the sacrum and the area does NOT blanch. What stage is this?", options: ["Normal skin finding", "Stage 1 pressure injury", "Stage 2 pressure injury", "Deep tissue pressure injury"], correctIndex: 1, answer: "Stage 1 pressure injury: non-blanchable erythema of intact skin. When pressed, the redness does NOT turn white (blanch), indicating capillary damage and early tissue ischemia. The skin remains intact with no open wound. It may feel warm, firm, or boggy compared to surrounding tissue.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q2", type: "question", question: "A wound shows exposed tendon at its base with surrounding necrotic tissue. What stage is this?", options: ["Stage 2", "Stage 3", "Stage 4 (exposed bone, tendon, or muscle)", "Unstageable"], correctIndex: 2, answer: "Stage 4: full-thickness tissue loss with exposed bone, tendon, or muscle. The presence of visible tendon confirms Stage 4. Stage 3 has visible subcutaneous fat but bone/tendon/muscle are NOT exposed. Stage 4 injuries carry risk of osteomyelitis.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q3", type: "question", question: "How often should immobile patients be repositioned to prevent pressure injuries?", options: ["Every 4 hours", "Every 6 hours", "Every 2 hours", "Once per shift"], correctIndex: 2, answer: "Reposition immobile patients at least every 2 hours in bed and every 1 hour in a wheelchair. Use the 30-degree lateral position rather than 90-degree side-lying to avoid trochanteric pressure. Post the turning schedule at bedside and document each repositioning.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q4", type: "question", question: "What are the two most common sites for pressure injuries?", options: ["Shoulders and knees", "Sacrum (#1) and heels (#2)", "Elbows and ankles", "Ears and occiput"], correctIndex: 1, answer: "The sacrum is the #1 most common site for pressure injuries (especially in supine patients), and heels are #2. Always elevate heels off the bed surface by placing pillows under the calves — do NOT place pillows directly under the heels as this creates a pressure point.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q5", type: "question", question: "A Braden Scale score of 10 indicates what level of risk?", options: ["No risk", "Mild risk", "Moderate risk", "High risk (score 10-12)"], correctIndex: 3, answer: "Braden Scale scoring: <=9 = very high risk, 10-12 = high risk, 13-14 = moderate risk, 15-18 = mild risk, >18 = no significant risk. A score of 10 requires aggressive prevention: specialty support surface, repositioning every 1-2 hours, nutritional optimization, heel elevation, and meticulous skin care.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q6", type: "question", question: "Why should pressure injuries NEVER be reverse staged during healing?", options: ["It causes confusion", "A healing Stage 4 does not become Stage 3 — lost tissue (muscle, bone exposure) is replaced with granulation tissue, not original tissue layers", "Reverse staging is standard practice", "It is acceptable in some facilities"], correctIndex: 1, answer: "Pressure injuries heal by filling with granulation tissue, not by regenerating the lost anatomic layers. A healing Stage 4 is documented as 'Stage 4, healing' or 'Stage 4, improving' — never downstaged to Stage 3. The original staging reflects the deepest tissue involvement, which never changes.", category: "Integumentary", difficulty: 2, clinicalPearl: "Once staged, always that stage. Document healing progress by describing wound bed, decreasing size, and granulation percentage." },
  { id: "rn-pi-q7", type: "question", question: "What are the six domains of the Braden Scale?", options: ["Pain, mobility, nutrition, medication, age, weight", "Sensory perception, moisture, activity, mobility, nutrition, and friction/shear", "Temperature, heart rate, blood pressure, respiratory rate, SpO2, pain", "None of the above"], correctIndex: 1, answer: "Braden Scale six domains: 1) Sensory Perception (1-4), 2) Moisture (1-4), 3) Activity (1-4), 4) Mobility (1-4), 5) Nutrition (1-4), 6) Friction/Shear (1-3). Total possible score: 6-23. Lower scores = higher risk. Each domain is scored independently based on specific criteria.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q8", type: "question", question: "What position angle is preferred for lateral repositioning and why?", options: ["90-degree side-lying", "30-degree lateral tilt — avoids direct pressure on the trochanter", "45-degree angle", "Flat supine"], correctIndex: 1, answer: "The 30-degree lateral position is preferred because it distributes weight across the buttock and thigh, avoiding direct pressure on the greater trochanter (a common pressure injury site). 90-degree side-lying places the full body weight directly on the trochanter, increasing pressure injury risk.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q9", type: "question", question: "A wound bed is covered entirely with black eschar. How should it be staged?", options: ["Stage 2", "Stage 3", "Stage 4", "Unstageable — wound base is obscured; cannot determine depth until debridement"], correctIndex: 3, answer: "Unstageable: when slough (yellow) or eschar (black/brown) obscures the wound base, the true depth and tissue involvement cannot be determined. It must be debrided to reveal the wound bed before accurate staging can occur. A stable, dry eschar on heels may be left intact (biological cover).", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q10", type: "question", question: "What is a deep tissue pressure injury (DTPI)?", options: ["Stage 1 pressure injury", "Localized area of persistent non-blanchable deep red, maroon, or purple discoloration — damage to underlying soft tissue from pressure/shear", "Any bruise", "Skin tear"], correctIndex: 1, answer: "DTPI presents as a localized area of persistent deep red, maroon, or purple discoloration of intact or non-intact skin. It represents damage to underlying soft tissue from pressure and/or shear. DTI may evolve rapidly to reveal full-thickness tissue destruction or may resolve without tissue loss.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q11", type: "question", question: "Why is incontinence-associated dermatitis (IAD) NOT classified as a pressure injury?", options: ["They are the same thing", "IAD is moisture damage (chemical irritation from urine/stool) — not pressure damage; however, IAD increases pressure injury risk in the affected area", "IAD only occurs on the face", "IAD is more severe than pressure injuries"], correctIndex: 1, answer: "IAD is caused by chemical irritation from prolonged contact with urine and/or stool, not by pressure. It presents as diffuse erythema, maceration, and skin breakdown in perineal/buttock areas. While IAD is NOT a pressure injury, the compromised skin barrier significantly increases the risk of developing pressure injuries.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q12", type: "question", question: "What is the fastest-growing category of pressure injuries?", options: ["Sacral pressure injuries", "Heel pressure injuries", "Medical device-related pressure injuries (MDRPI)", "Trochanteric pressure injuries"], correctIndex: 2, answer: "Medical device-related pressure injuries (MDRPI) are the fastest-growing category. Oxygen masks, nasal cannula, cervical collars, splints, endotracheal tubes, pulse oximeters, and any device that contacts skin can cause pressure injury. Inspect under all devices every shift and reposition devices regularly.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q13", type: "question", question: "What HOB elevation increases sacral shear forces?", options: ["<15 degrees", ">30 degrees elevation increases shear at the sacrum", "Any HOB elevation", "HOB elevation has no effect on shear"], correctIndex: 1, answer: "HOB elevation >30 degrees increases shear forces on the sacrum because the body tends to slide downward. The skin remains fixed while underlying tissues slide, damaging blood vessels. Maintain the lowest HOB elevation consistent with medical needs (aspiration prevention requires >=30 degrees).", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q14", type: "question", question: "How should patients be repositioned to minimize friction and shear?", options: ["Pull the patient across the sheets", "Use lift sheets, draw sheets, and transfer devices — NEVER drag the patient", "Push the patient into position", "Friction is not a concern during repositioning"], correctIndex: 1, answer: "Always use lift sheets, transfer boards, or mechanical lifting devices to reposition patients. Dragging creates friction (damaging the epidermis) and shear (parallel forces that damage blood vessels in deeper tissue layers). Proper technique protects both the patient's skin and the nurse's back.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q15", type: "question", question: "A Stage 2 pressure injury has slough in the wound bed. Is this correctly staged?", options: ["Yes — Stage 2 can have slough", "No — Stage 2 NEVER has slough; if slough is present, the wound is at least Stage 3 or unstageable", "Slough indicates Stage 1", "Slough is normal in all stages"], correctIndex: 1, answer: "Stage 2 pressure injuries present as partial-thickness skin loss with a red-pink wound bed or intact/ruptured serum-filled blister. By definition, Stage 2 NEVER contains slough or eschar. If slough or eschar is present, the wound is at least Stage 3 or unstageable.", category: "Integumentary", difficulty: 3 },
  { id: "rn-pi-q16", type: "question", question: "What is the external pressure threshold that causes tissue ischemia?", options: [">10 mmHg", ">20 mmHg", ">32 mmHg (capillary closing pressure)", ">50 mmHg"], correctIndex: 2, answer: "Normal capillary closing pressure is approximately 32 mmHg. External pressure exceeding this threshold occludes blood flow, causing tissue ischemia, hypoxia, metabolic waste accumulation, and eventual cell death. This is why pressure redistribution (not just 'pressure relief') is the cornerstone of prevention.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q17", type: "question", question: "What type of support surface is appropriate for a patient with a Stage 3 or 4 pressure injury?", options: ["Standard hospital mattress", "Foam overlay", "Low-air-loss or air-fluidized bed", "Egg crate mattress"], correctIndex: 2, answer: "Stage 3-4 pressure injuries require advanced support surfaces: low-air-loss beds (continuous air flow reducing moisture and pressure) or air-fluidized beds (patient floats on silicone beads with warm air flow, providing maximum pressure redistribution). Standard mattresses and foam overlays are insufficient for advanced wounds.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q18", type: "question", question: "How should heel pressure be managed in immobile patients?", options: ["Place a pillow directly under the heels", "Elevate heels completely off the bed by placing pillows under the calves", "Apply heel-shaped cushions", "No intervention needed for heels"], correctIndex: 1, answer: "Elevate heels off the bed surface by placing pillows under the calves (not under the heels — that creates a pressure point). Heel suspension devices/boots are also effective. The heels should 'float' with no contact on any surface. Heels are vulnerable because they have little subcutaneous tissue protection.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q19", type: "question", question: "What nutritional protein target helps prevent and heal pressure injuries?", options: ["0.5 g/kg/day", "0.8 g/kg/day (standard)", "1.25-1.5 g/kg/day", "3 g/kg/day"], correctIndex: 2, answer: "Protein intake of 1.25-1.5 g/kg/day is recommended for pressure injury prevention and healing. Protein provides amino acids essential for collagen synthesis, immune function, and cell proliferation. Supplement with vitamin C (250 mg BID) and zinc (220 mg daily) for optimal wound healing support.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q20", type: "question", question: "When should Braden Scale assessment be performed?", options: ["Only on admission", "On admission, every shift in acute care, with change in condition, and at regular intervals per policy", "Once weekly", "Only when a wound is identified"], correctIndex: 1, answer: "Perform Braden Scale assessment on admission to establish baseline risk, every shift in acute care settings, whenever the patient's condition changes (e.g., new immobility, incontinence, nutritional change), and at regular intervals per institutional policy. Documentation should include the total score and individual domain scores.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q21", type: "question", question: "A stable, dry, intact eschar on a heel — should it be debrided?", options: ["Yes — all eschar must be debrided", "No — stable, dry, intact eschar on heels serves as a natural biological cover and should NOT be debrided", "Only if the patient requests it", "Debride only if soft"], correctIndex: 1, answer: "Stable, dry, intact eschar on heels should NOT be debrided — it serves as the body's natural biological dressing protecting the underlying tissue. However, if the eschar becomes soft, boggy, fluctuant, draining, or if signs of infection develop, it must be debrided to assess the wound bed.", category: "Integumentary", difficulty: 3 },
  { id: "rn-pi-q22", type: "question", question: "What is the role of barrier cream in pressure injury prevention?", options: ["It treats pressure injuries", "It protects perineal and skin fold areas from moisture damage (incontinence-associated dermatitis), reducing the risk of subsequent pressure injury", "It replaces repositioning", "It is decorative"], correctIndex: 1, answer: "Barrier creams (dimethicone-based) protect the skin from chemical irritation caused by urine and stool. They create a waterproof barrier that prevents moisture-associated skin breakdown (IAD). While they don't prevent pressure injuries directly, they maintain skin integrity which reduces pressure injury risk.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q23", type: "question", question: "What is the most significant modifiable risk factor for pressure injury development?", options: ["Age", "Nutritional status", "Immobility (inability to reposition independently)", "Race"], correctIndex: 2, answer: "Immobility is the single most significant risk factor for pressure injuries. Without the ability to shift weight and reposition, sustained pressure exceeds capillary closing pressure, causing tissue ischemia. Repositioning interventions (every 2 hours) are the most important preventive measure.", category: "Integumentary", difficulty: 1 },
  { id: "rn-pi-q24", type: "question", question: "A dark-skinned patient may not show erythema. What alternative assessment should the nurse use?", options: ["Skip skin assessment", "Palpate for warmth, firmness, bogginess, and compare to surrounding tissue; look for color changes (purplish hue) and use adequate lighting", "Only assess light-skinned areas", "Rely solely on patient complaints"], correctIndex: 1, answer: "In darker skin tones, erythema may not be visually apparent. Use palpation: the area may feel warmer, firmer, or boggier than surrounding tissue. Look for color changes (purplish or darker hue), edema, and induration. Use adequate lighting. Compare symmetrical body areas. Listen to patient reports of pain or tenderness.", category: "Integumentary", difficulty: 2 },
  { id: "rn-pi-q25", type: "question", question: "What complication may develop in Stage 4 pressure injuries involving bone?", options: ["Skin cancer", "Osteomyelitis (bone infection)", "Osteoporosis", "Arthritis"], correctIndex: 1, answer: "Osteomyelitis is a serious complication of Stage 4 pressure injuries where exposed bone becomes infected. Suspect osteomyelitis if the wound fails to heal despite appropriate treatment, bone is visible and probing reaches bone, or inflammatory markers remain elevated. Diagnosis requires bone biopsy or MRI.", category: "Integumentary", difficulty: 2 },

  // === SKIN CANCER (25 cards) ===
  { id: "rn-sc-q1", type: "question", question: "What does ABCDE stand for in melanoma assessment?", options: ["Area, Border, Color, Depth, Evolution", "Asymmetry, Border irregularity, Color variation, Diameter >6mm, Evolving", "Assessment, Biopsy, Classification, Diagnosis, Education", "Age, Background, Cancer type, Depth, Evaluation"], correctIndex: 1, answer: "ABCDE melanoma criteria: A = Asymmetry (one half unlike the other), B = Border irregularity (scalloped, notched, blurred), C = Color variation (multiple colors: brown, black, red, white, blue), D = Diameter >6 mm (pencil eraser size), E = Evolving (changing in size, shape, color, or symptoms).", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q2", type: "question", question: "Which skin cancer type is most common overall but almost never metastasizes?", options: ["Melanoma", "Squamous cell carcinoma", "Basal cell carcinoma (most common, <0.1% metastasis rate)", "Merkel cell carcinoma"], correctIndex: 2, answer: "Basal cell carcinoma is the most common cancer overall, arising from basal cells in the stratum basale. It is locally destructive but almost never metastasizes (<0.1%). It typically presents as a pearly, flesh-colored papule with telangiectasia and rolled borders on sun-exposed areas.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q3", type: "question", question: "What is the single most important prognostic factor for melanoma?", options: ["Patient age", "Tumor location", "Breslow depth (thickness of tumor invasion in millimeters)", "Number of moles"], correctIndex: 2, answer: "Breslow depth measures the vertical thickness of the melanoma from the granular layer to the deepest point of invasion. It is the single most important prognostic factor: <1 mm = >95% 5-year survival; 1-2 mm = 80-90%; 2-4 mm = 60-75%; >4 mm = <50%. It also determines surgical excision margins.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q4", type: "question", question: "What is the 'ugly duckling' sign in skin cancer screening?", options: ["A mole that is itchy", "A lesion that looks distinctly different from all other moles on the patient's body — warrants evaluation regardless of ABCDE criteria", "A mole on the foot", "A birthmark"], correctIndex: 1, answer: "The 'ugly duckling' sign refers to a mole that looks notably different from all other moles on the patient's body. While most of a person's moles tend to look similar to each other, an 'outlier' lesion may be melanoma even if it doesn't meet all ABCDE criteria. It should be evaluated by dermatology.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q5", type: "question", question: "Organ transplant recipients have how many times increased risk of squamous cell carcinoma?", options: ["5x", "25x", "65x", "100x"], correctIndex: 2, answer: "Organ transplant recipients have approximately 65x increased risk of SCC due to chronic immunosuppression. They require dermatologic screening every 6-12 months. SCC in immunosuppressed patients is also more aggressive with higher metastatic potential than in the general population.", category: "Integumentary", difficulty: 3 },
  { id: "rn-sc-q6", type: "question", question: "What type of biopsy is preferred for a suspected melanoma?", options: ["Shave biopsy", "Punch biopsy", "Excisional biopsy with narrow margins (captures full depth for Breslow measurement)", "Fine needle aspiration"], correctIndex: 2, answer: "Excisional biopsy is preferred for suspected melanoma because it removes the entire lesion, allowing complete histologic evaluation including accurate Breslow depth measurement. Shave biopsy may not capture the full depth, potentially underestimating thickness and leading to inadequate treatment planning.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q7", type: "question", question: "What does a pearly papule with telangiectasia on the nose most likely represent?", options: ["Melanoma", "Basal cell carcinoma", "Squamous cell carcinoma", "Actinic keratosis"], correctIndex: 1, answer: "A pearly, flesh-colored or pink papule with visible telangiectasia (dilated blood vessels) and rolled borders on a sun-exposed area (face, nose, ears) is the classic presentation of basal cell carcinoma. It may develop central ulceration ('rodent ulcer'). BCC grows slowly and is locally destructive.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q8", type: "question", question: "What are actinic keratoses and why are they clinically significant?", options: ["Benign moles", "Pre-cancerous lesions that can progress to squamous cell carcinoma", "Melanoma precursors", "Cosmetic concerns only"], correctIndex: 1, answer: "Actinic keratoses are pre-cancerous lesions caused by cumulative UV exposure. They present as rough, scaly, sandpaper-like patches on sun-damaged skin. An estimated 5-10% progress to SCC if left untreated. Treatment options include cryotherapy (liquid nitrogen), topical 5-FU, imiquimod, or photodynamic therapy.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q9", type: "question", question: "What melanoma type is most common in dark-skinned individuals?", options: ["Superficial spreading melanoma", "Nodular melanoma", "Acral lentiginous melanoma (palms, soles, nail beds)", "Lentigo maligna melanoma"], correctIndex: 2, answer: "Acral lentiginous melanoma occurs on the palms, soles, and under fingernails/toenails. It is the most common melanoma type in dark-skinned individuals (African American, Asian, Hispanic). Bob Marley died from an acral lentiginous melanoma under his toenail. It is often diagnosed late due to its hidden location.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q10", type: "question", question: "What SPF and spectrum of sunscreen is recommended for skin cancer prevention?", options: ["SPF 10, UVB only", "SPF 30+ broad-spectrum (UVA and UVB), reapplied every 2 hours and after swimming/sweating", "SPF 50+ once daily", "Any SPF, no reapplication needed"], correctIndex: 1, answer: "SPF 30+ broad-spectrum sunscreen (protecting against both UVA and UVB) is recommended. Apply generously 15-30 minutes before sun exposure. Reapply every 2 hours and after swimming or sweating. No sunscreen provides 100% protection — combine with protective clothing, hats, and shade.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q11", type: "question", question: "What immune-related adverse events should the nurse monitor in a patient receiving pembrolizumab for melanoma?", options: ["No monitoring needed", "Rash, diarrhea/colitis, hepatitis, pneumonitis, endocrinopathy (thyroid dysfunction), nephritis — can affect ANY organ", "Only skin reactions", "Only GI side effects"], correctIndex: 1, answer: "Checkpoint inhibitors can cause immune-related adverse events (irAEs) in virtually any organ system. Monitor for: dermatitis, colitis (diarrhea), hepatitis (elevated LFTs), pneumonitis (cough, dyspnea), endocrinopathy (thyroid dysfunction most common — check TSH regularly), nephritis, and myocarditis.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q12", type: "question", question: "What surgical margin is recommended for melanoma with Breslow depth of 1.5 mm?", options: ["5 mm margins", "1-2 cm margins", "3 cm margins", "No margins needed"], correctIndex: 1, answer: "Melanoma excision margins are based on Breslow depth: in situ = 5 mm, <1 mm = 1 cm, 1-2 mm = 1-2 cm, >2 mm = 2 cm. A 1.5 mm melanoma requires 1-2 cm margins. Wider margins reduce local recurrence risk. Sentinel lymph node biopsy is also indicated for depth >0.8 mm.", category: "Integumentary", difficulty: 3 },
  { id: "rn-sc-q13", type: "question", question: "What does Mohs micrographic surgery involve and when is it used?", options: ["Standard surgical excision", "Layer-by-layer removal with immediate microscopic examination of margins — used for cosmetically sensitive areas and high-risk BCC/SCC", "Laser ablation", "Cryotherapy"], correctIndex: 1, answer: "Mohs surgery removes skin cancer in thin layers, with each layer immediately examined microscopically for residual cancer cells. This process continues until all margins are clear, minimizing tissue removal while ensuring complete excision. It achieves the highest cure rates (99% for BCC) and is preferred for facial lesions.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q14", type: "question", question: "Tanning beds increase melanoma risk by what percentage when first used before age 35?", options: ["10%", "25%", "50%", "75%"], correctIndex: 3, answer: "Using tanning beds before age 35 increases melanoma risk by 75%. There is NO safe tan from UV radiation — both UVA (tanning beds primarily) and UVB cause DNA damage in melanocytes. The WHO classifies tanning beds as Group 1 carcinogens (same category as tobacco and asbestos).", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q15", type: "question", question: "What is the expected skin reaction when using topical 5-fluorouracil (5-FU) for actinic keratoses?", options: ["No visible reaction", "Severe inflammatory reaction with redness, crusting, and erosion — this is the EXPECTED therapeutic response", "Immediate improvement", "Blue discoloration"], correctIndex: 1, answer: "Topical 5-FU causes significant inflammatory reaction at treatment sites: erythema, crusting, erosion, and discomfort over 4-6 weeks. This is the EXPECTED and desired therapeutic response — the drug selectively destroys pre-cancerous cells. Educate patients to continue through the inflammatory phase and not discontinue prematurely.", category: "Integumentary", difficulty: 2, clinicalPearl: "Patients often want to stop 5-FU when the skin reaction looks 'terrible' — counsel them that this means the medication is working." },
  { id: "rn-sc-q16", type: "question", question: "What percentage of skin cancers are melanoma, and what percentage of skin cancer deaths does melanoma cause?", options: ["50% of cancers, 50% of deaths", "4% of skin cancers but 75% of skin cancer deaths", "20% of cancers, 20% of deaths", "1% of cancers, 10% of deaths"], correctIndex: 1, answer: "Melanoma accounts for only 4% of skin cancer diagnoses but causes 75% of skin cancer deaths due to its aggressive metastatic potential. This underscores the importance of early detection through ABCDE screening — melanomas diagnosed and treated while thin (Breslow <1 mm) have >95% cure rates.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q17", type: "question", question: "A patient with melanoma has a positive BRAF mutation. What targeted therapy is indicated?", options: ["Trastuzumab", "BRAF/MEK inhibitors (vemurafenib + cobimetinib or dabrafenib + trametinib)", "Imatinib", "Tamoxifen"], correctIndex: 1, answer: "BRAF V600 mutations are found in approximately 40-60% of melanomas. Targeted therapy with BRAF inhibitors (vemurafenib, dabrafenib) combined with MEK inhibitors (cobimetinib, trametinib) significantly improves progression-free survival. Combination therapy reduces resistance development compared to BRAF inhibitor monotherapy.", category: "Integumentary", difficulty: 3 },
  { id: "rn-sc-q18", type: "question", question: "What is sentinel lymph node biopsy in melanoma, and when is it indicated?", options: ["Removal of all lymph nodes", "Biopsy of the first lymph node(s) draining the tumor site to assess for metastasis — indicated for Breslow depth >0.8 mm", "Blood test for lymph node involvement", "Imaging study"], correctIndex: 1, answer: "Sentinel lymph node biopsy identifies and examines the first node(s) in the lymphatic drainage pathway from the melanoma. A radioactive tracer and/or blue dye injected near the tumor guides identification. Positive sentinel nodes indicate regional metastasis, guiding further treatment (completion lymph node dissection or adjuvant therapy).", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q19", type: "question", question: "What characteristic distinguishes SCC from BCC appearance?", options: ["Both look identical", "SCC: scaly, erythematous plaque with crusted surface; BCC: pearly papule with telangiectasia and rolled borders", "BCC is red and crusty; SCC is pearly", "Only biopsy can differentiate them"], correctIndex: 1, answer: "SCC presents as a scaly, erythematous (red) plaque or nodule with a rough, crusted surface, sometimes developing a cutaneous horn. BCC presents as a pearly, flesh-colored or pink papule with visible telangiectasia (surface blood vessels) and rolled borders, often with central ulceration. Both occur on sun-exposed areas.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q20", type: "question", question: "What follow-up schedule is recommended after melanoma treatment?", options: ["Annual checkup only", "Skin exams every 3-6 months for first 2 years, then annually", "No follow-up needed", "Every 5 years"], correctIndex: 1, answer: "After melanoma diagnosis and treatment, skin exams every 3-6 months for the first 2 years (when recurrence risk is highest), then every 6-12 months for years 3-5, then annually for life. Patients should also perform monthly self-skin examinations. Recurrence can occur years after initial treatment.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q21", type: "question", question: "What risk factor is most significant for developing melanoma?", options: ["Dark skin", "History of blistering sunburns before age 18 and intermittent intense UV exposure", "Chronic low-level sun exposure", "Age over 70"], correctIndex: 1, answer: "Intermittent intense UV exposure with blistering sunburns (especially before age 18) is the strongest environmental risk factor for melanoma. This differs from BCC/SCC where cumulative chronic exposure is more important. Family history (10% of melanomas) and multiple/atypical nevi are also significant risk factors.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q22", type: "question", question: "What patient education is essential after a skin biopsy for suspected skin cancer?", options: ["No special care needed", "Keep the site clean and dry, watch for signs of infection (redness, swelling, drainage, fever), and importance of follow-up for results", "Apply antibiotic ointment continuously", "Expose the wound to sunlight for healing"], correctIndex: 1, answer: "Post-biopsy education: keep the site clean and dry, apply prescribed antibiotic ointment and bandage as directed, avoid submerging in water for 24-48 hours, watch for infection signs, take analgesics as needed, and — most importantly — keep the follow-up appointment to receive biopsy results and discuss treatment plan.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q23", type: "question", question: "What is imiquimod (Aldara) used for in skin cancer?", options: ["Stage 4 melanoma treatment", "Topical treatment for superficial BCC and actinic keratoses — stimulates local immune response", "Systemic chemotherapy", "Wound healing"], correctIndex: 1, answer: "Imiquimod is a topical immune response modifier that activates toll-like receptor 7, inducing local interferon-alpha and other cytokines that promote immune-mediated tumor destruction. Used for superficial BCC and actinic keratoses. Expect local inflammation (the intended therapeutic effect). Not for deep or nodular tumors.", category: "Integumentary", difficulty: 2 },
  { id: "rn-sc-q24", type: "question", question: "What self-examination technique should the nurse teach patients for skin cancer detection?", options: ["Check only visible moles once a year", "Monthly full-body self-exam including scalp, between toes, nail beds, and soles using mirrors for hard-to-see areas", "Examine arms and legs only", "Self-examination is not recommended"], correctIndex: 1, answer: "Teach monthly full-body self-skin examination: use a well-lit room, full-length mirror, and hand mirror. Examine systematically: face, scalp (use a blow dryer to part hair), ears, neck, torso, arms, hands (including between fingers), legs, feet (including soles and between toes), nail beds, and genital area.", category: "Integumentary", difficulty: 1 },
  { id: "rn-sc-q25", type: "question", question: "How does SCC differ from BCC in terms of metastatic potential?", options: ["Both have the same metastatic risk", "SCC can metastasize (3-5% risk, higher in immunosuppressed); BCC almost never metastasizes (<0.1%)", "BCC has higher metastatic risk", "Neither can metastasize"], correctIndex: 1, answer: "SCC has a 3-5% metastatic potential in immunocompetent patients, rising to 10-20% in immunosuppressed individuals. It can spread via lymphatics and blood. BCC almost never metastasizes (<0.1%) but is locally destructive, potentially invading cartilage and bone if neglected. This difference affects treatment aggressiveness.", category: "Integumentary", difficulty: 2 }
];
